/// Input for `index_folder`.
#[derive(Deserialize, Serialize, JsonSchema)]
pub struct IndexFolderInput {
    /// Absolute or relative path to the directory to index.
    pub path: String,
    /// Optional key used to replay an identical `index_folder` request safely.
    #[serde(default)]
    pub idempotency_key: Option<String>,
    /// Feature 012 (Phase 2): when true, OPEN this folder ADDITIVELY in the
    /// current session's working set instead of retargeting. The session keeps
    /// its existing active project AND gains this one, enabling cross-project
    /// reads (`project`/`projects` on `search_symbols`/`search_text`/
    /// `find_references`). Default/omitted = the existing retarget behavior
    /// (FR-006, byte-identical). Multi-project requires the daemon; on stdio/embed
    /// (no daemon) an `add:true` call honestly refuses (Principle VII).
    #[serde(default, deserialize_with = "lenient_bool")]
    pub add: Option<bool>,
}

/// Input for `checkpoint_now`.
#[derive(Default, Deserialize, Serialize, JsonSchema)]
pub struct CheckpointNowInput {
    /// When true, deserialize the snapshot after writing and fail the command if it cannot be read back.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub verify_after_write: Option<bool>,
    /// When true, additionally export the Best-tier team artifact
    /// (`.symforge/index.bin.zst` + `artifact.json`, plus a `.gitattributes`
    /// `*.zst merge=ours` hint) alongside the plain snapshot. See
    /// contracts/team-artifact.md § Tiers.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub export_artifact: Option<bool>,
}

/// Input for `health`.
///
/// SF-STRESS-010: the parse/span quarantine registry was hard-capped at 10
/// entries with no retrieval surface, so the full list of partial/failed files
/// was unreachable without thousands of per-file calls. These optional paging
/// parameters page the ranked registry; entries are ranked real-source-first so
/// genuine repo-owned losses surface before vendored/fixture noise. Omitting
/// both preserves the historical default (offset 0, limit 10).
#[derive(Default, Deserialize, Serialize, JsonSchema)]
pub struct HealthInput {
    /// Maximum quarantine registry entries to render (default 10, capped at
    /// 1000). Raise to retrieve more of the full partial/failed file list.
    #[serde(default, deserialize_with = "lenient_u32")]
    pub quarantine_limit: Option<u32>,
    /// Offset into the ranked quarantine registry for paging (default 0).
    #[serde(default, deserialize_with = "lenient_u32")]
    pub quarantine_offset: Option<u32>,
}

impl HealthInput {
    fn quarantine_limit(&self) -> Option<usize> {
        self.quarantine_limit.map(|n| n as usize)
    }

    fn quarantine_offset(&self) -> Option<usize> {
        self.quarantine_offset.map(|n| n as usize)
    }
}

/// Input for `what_changed`.
#[derive(Deserialize, Serialize, JsonSchema)]
pub struct WhatChangedInput {
    /// Optional Unix timestamp (seconds since epoch). Files newer than this are returned.
    #[serde(default, deserialize_with = "lenient_i64")]
    pub since: Option<i64>,
    /// Optional git ref to diff against, for example `HEAD~5` or `branch:main`.
    pub git_ref: Option<String>,
    /// When true, report uncommitted git changes. Defaults to true when no other mode is specified and a repo root exists.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub uncommitted: Option<bool>,
    /// Optional relative path prefix scope, for example `src/` or `src/protocol`.
    pub path_prefix: Option<String>,
    /// Optional canonical language name such as `Rust`, `TypeScript`, `C#`, or `C++`.
    pub language: Option<String>,
    /// When true, exclude non-source files (docs, configs, images, lock files).
    /// Only files with a recognized programming language extension are included.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub code_only: Option<bool>,
    /// When true, also include a symbol-level diff alongside the file list.
    /// Only applies in git_ref and uncommitted modes (not timestamp mode).
    /// In git_ref mode, diffs the given ref against HEAD.
    /// In uncommitted mode, diffs HEAD against the working tree.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub include_symbol_diff: Option<bool>,
    /// When true, return an approximate token cost estimate instead of actual content.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub estimate: Option<bool>,
    /// Optional maximum token budget for the response.
    #[serde(default, deserialize_with = "lenient_u64")]
    pub max_tokens: Option<u64>,
}

/// Blast-radius granularity for `detect_impact`
/// (contracts/detect-impact.md, frozen 2026-06-30).
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Deserialize, Serialize, JsonSchema)]
#[serde(rename_all = "lowercase")]
pub enum ImpactScope {
    Files,
    #[default]
    Symbols,
}

/// `depth` defaults to 2 via this function — **not** `u8::default()` (0),
/// since depth 0 yields an empty blast radius (a silent no-op impact query).
/// contracts/detect-impact.md § Input.
fn default_impact_depth() -> u8 {
    2
}

fn default_include_untracked() -> bool {
    true
}

/// Maximum depth accepted before `detect_impact` clamps + warns
/// (contracts/detect-impact.md § Risk tiers / error catalog: "depth capped").
const DETECT_IMPACT_MAX_DEPTH: u8 = 5;

/// ponytail: fixed safety cap on EACH list (`changed_files`, `changed_symbols`,
/// `blast_radius`) returned per call — the bound that stops the 54 MB / 291K-symbol
/// dump seen on a large repo. The frozen contract's `pagination` envelope has no
/// `offset`/`limit` input field to page past it — add one if a real need for
/// deeper paging shows up. `risk_summary` is always counted over the full set.
const DETECT_IMPACT_MAX_RETURNED: usize = 200;

/// Input for `detect_impact` (contracts/detect-impact.md, frozen 2026-06-30).
#[derive(Deserialize, Serialize, JsonSchema)]
pub struct DetectImpactInput {
    /// Base branch/ref to diff against HEAD when `since` is not set. Defaults
    /// to `main` when neither `base_branch` nor `since` is set
    /// (contracts/detect-impact.md § Input); on a repo whose default branch is
    /// not `main`, pass this (or `since`) explicitly — an absent `main` surfaces
    /// an "Invalid git ref" error. Uncommitted working-tree changes are always
    /// merged in per `include_untracked`.
    pub base_branch: Option<String>,
    /// Git ref to diff against HEAD; overrides `base_branch` when set. Pass
    /// the literal value `WORKTREE` to diff tracked working-tree changes
    /// (staged + unstaged) against HEAD instead of another ref.
    pub since: Option<String>,
    /// Blast-radius hop depth (default 2). Values above 5 are clamped to 5
    /// with a warning footer.
    #[serde(default = "default_impact_depth")]
    pub depth: u8,
    /// Blast-radius granularity: `files` or `symbols` (default `symbols`).
    #[serde(default)]
    pub scope: ImpactScope,
    /// Merge uncommitted (staged + unstaged + untracked) changes into the
    /// changed-file set (default true).
    #[serde(
        default = "default_include_untracked",
        deserialize_with = "lenient_bool_required"
    )]
    pub include_untracked: bool,
}

