#[derive(Debug, serde::Deserialize, schemars::JsonSchema)]
pub struct SmartQueryInput {
    /// Natural language question about the codebase. Examples:
    /// "who calls optimize_deterministic", "where is LiveIndex defined",
    /// "how does the parser work", "what changed", "find file tools.rs"
    pub query: String,
    /// Optional maximum token budget for the response.
    #[serde(default, deserialize_with = "lenient_u64")]
    pub max_tokens: Option<u64>,
}

#[derive(Debug, serde::Deserialize, serde::Serialize, schemars::JsonSchema)]
pub struct EditPlanInput {
    /// The symbol name or file path you want to edit.
    pub target: String,
}

#[derive(Debug, serde::Deserialize, serde::Serialize, schemars::JsonSchema)]
pub struct InvestigationInput {
    /// Optional focus area to filter suggestions.
    pub focus: Option<String>,
}

/// Input for `diff_symbols`.
#[derive(Deserialize, Serialize, JsonSchema)]
pub struct DiffSymbolsInput {
    /// Base git ref to compare from (default: "main").
    pub base: Option<String>,
    /// Target git ref to compare to (default: "HEAD").
    pub target: Option<String>,
    /// Optional path filter — only show diffs for files matching this prefix.
    pub path_prefix: Option<String>,
    /// Optional canonical language name such as `Rust`, `TypeScript`, `C#`, or `C++`.
    pub language: Option<String>,
    /// When true, exclude non-source files (docs, configs, images, lock files).
    /// Only files with a recognized programming language extension are included.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub code_only: Option<bool>,
    /// When true, show only per-file summary counts (+N added, -N removed, ~N modified)
    /// without listing individual symbols. Like `git diff --stat` vs `git diff`.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub compact: Option<bool>,
    /// When true, emit only the aggregate summary line (total added/removed/modified
    /// counts) without any per-file detail. Useful for quick change-scope assessment.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub summary_only: Option<bool>,
    /// When true, return an approximate token cost estimate instead of actual content.
    #[serde(default, deserialize_with = "lenient_bool")]
    pub estimate: Option<bool>,
    /// Optional maximum token budget for the response.
    #[serde(default, deserialize_with = "lenient_u64")]
    pub max_tokens: Option<u64>,
}

enum WhatChangedMode {
    Timestamp(i64),
    GitRef(String),
    Uncommitted,
}

#[derive(Default)]
struct ExploreMatchScore {
    raw_count: usize,
    matched_terms: HashSet<String>,
}

#[derive(Default)]
struct ExploreFileSignal {
    raw_score: u64,
    matched_terms: HashSet<String>,
}

struct DerivedExploreCluster {
    seed_terms: Vec<String>,
    promoted_symbols: Vec<String>,
    seed_files: Vec<String>,
}

fn determine_what_changed_mode(
    input: &WhatChangedInput,
    has_repo_root: bool,
) -> Result<WhatChangedMode, String> {
    if let Some(git_ref) = input
        .git_ref
        .as_deref()
        .map(str::trim)
        .filter(|git_ref| !git_ref.is_empty())
    {
        return if has_repo_root {
            Ok(WhatChangedMode::GitRef(
                git_ref
                    .strip_prefix("branch:")
                    .unwrap_or(git_ref)
                    .to_string(),
            ))
        } else {
            Err("Git change detection unavailable; pass `since` for timestamp mode.".to_string())
        };
    }

    if input.uncommitted.unwrap_or(false) || (input.since.is_none() && has_repo_root) {
        return if has_repo_root {
            Ok(WhatChangedMode::Uncommitted)
        } else {
            Err("Git change detection unavailable; pass `since` for timestamp mode.".to_string())
        };
    }

    if let Some(since) = input.since {
        Ok(WhatChangedMode::Timestamp(since))
    } else {
        Err(
            "what_changed requires either `since`, `git_ref`, or an available repo root."
                .to_string(),
        )
    }
}

fn filter_paths_by_prefix_and_language(
    paths: Vec<String>,
    path_prefix: Option<&str>,
    language: Option<&str>,
    code_only: bool,
) -> Result<Vec<String>, String> {
    let lang_filter = parse_language_filter(language)?;
    let prefix = path_prefix
        .map(str::trim)
        .filter(|p| !p.is_empty())
        .map(|p| {
            p.replace('\\', "/")
                .trim_start_matches("./")
                .trim_start_matches('/')
                .trim_end_matches('/')
                .to_string()
        });

    Ok(paths
        .into_iter()
        .filter(|path| {
            if let Some(ref pfx) = prefix
                && !path.starts_with(pfx.as_str())
            {
                return false;
            }
            if let Some(ref lang) = lang_filter {
                let ext = path.rsplit('.').next().unwrap_or("");
                if crate::domain::index::LanguageId::from_extension(ext).as_ref() != Some(lang) {
                    return false;
                }
            }
            if code_only && lang_filter.is_none() {
                let ext = path.rsplit('.').next().unwrap_or("");
                match crate::domain::index::LanguageId::from_extension(ext) {
                    None => return false,
                    Some(lang) => {
                        if crate::parsing::config_extractors::is_config_language(&lang) {
                            return false;
                        }
                    }
                }
            }
            true
        })
        .collect())
}

fn normalize_exact_path(input: &str) -> String {
    let normalized = input
        .trim()
        .replace('\\', "/")
        .trim_start_matches("./")
        .trim_start_matches('/')
        .trim_end_matches('/')
        .to_string();

    if normalized.is_empty() {
        input.trim().to_string()
    } else {
        normalized
    }
}

/// Find up to 5 similar file paths for "file not found" suggestions.
/// Extracts the basename from the failed path and searches the index.
fn suggest_similar_files(index: &crate::live_index::LiveIndex, path: &str) -> Vec<String> {
    let basename = std::path::Path::new(path)
        .file_name()
        .and_then(|f| f.to_str())
        .unwrap_or(path);
    // Try basename match first
    let mut suggestions: Vec<String> = index
        .find_files_by_basename(basename)
        .into_iter()
        .take(5)
        .map(|s| s.to_string())
        .collect();
    // If no basename match, try the stem (without extension)
    if suggestions.is_empty() {
        let stem = std::path::Path::new(path)
            .file_stem()
            .and_then(|f| f.to_str())
            .unwrap_or(basename);
        if stem.len() >= 3 {
            let stem_lower = stem.to_ascii_lowercase();
            suggestions = index
                .all_files()
                .map(|(p, _)| p.as_str())
                .filter(|p| {
                    let file_stem = std::path::Path::new(p)
                        .file_stem()
                        .and_then(|s| s.to_str())
                        .unwrap_or("");
                    file_stem.to_ascii_lowercase().contains(&stem_lower)
                })
                .take(5)
                .map(|s| s.to_string())
                .collect();
        }
    }
    suggestions
}

fn enrich_with_callers(
    index: &crate::live_index::LiveIndex,
    result: &mut search::TextSearchResult,
    file_limit: usize,
) {
    use std::collections::HashSet;

    for file_matches in result.files.iter_mut().take(file_limit) {
        // Collect unique enclosing symbol names from this file's matches
        let mut symbol_names: HashSet<String> = HashSet::new();
        for m in &file_matches.matches {
            if let Some(ref enc) = m.enclosing_symbol {
                symbol_names.insert(enc.name.clone());
            }
        }

        if symbol_names.is_empty() {
            continue;
        }

        let mut callers: Vec<search::CallerEntry> = Vec::new();
        let mut seen: HashSet<(String, String)> = HashSet::new(); // (file, symbol) dedup

        for sym_name in &symbol_names {
            let refs = index.find_references_for_name(sym_name, None, false);
            for (ref_file, ref_record) in refs {
                // Get enclosing symbol of the reference
                let enclosing_name = ref_record
                    .enclosing_symbol_index
                    .and_then(|idx| {
                        index
                            .get_file(ref_file)
                            .and_then(|f| f.symbols.get(idx as usize))
                            .map(|s| s.name.clone())
                    })
                    .unwrap_or_else(|| "(top-level)".to_string());

                // Skip self-references only when the caller IS one of the matched
                // symbols (same-file callers from different symbols are useful context)
                if ref_file == file_matches.path && symbol_names.contains(&enclosing_name) {
                    continue;
                }

                let key = (ref_file.to_string(), enclosing_name.clone());
                if seen.insert(key) {
                    callers.push(search::CallerEntry {
                        file: ref_file.to_string(),
                        symbol: enclosing_name,
                        line: ref_record.line_range.0 + 1, // 0-based to 1-based
                    });
                }
            }
        }

        // Cap at 10 callers to avoid noise
        callers.truncate(10);

        // Always set callers when follow_refs was requested — distinguishes
        // "not requested" (None) from "ran but found nothing" (Some([]))
        file_matches.callers = Some(callers);
    }
}

fn freshen_exact_path_for_targeted_retrieval(
    server: &SymForgeServer,
    path_scope: &search::PathScope,
) -> bool {
    let search::PathScope::Exact(relative_path) = path_scope else {
        return false;
    };
    let expected_gen = server.index.current_project_generation();
    let Some(repo_root) = server.capture_repo_root() else {
        return false;
    };
    let Ok(abs_path) = safe_repo_path_for_freshen(&repo_root, relative_path) else {
        return false;
    };
    match watcher::freshen_file_if_stale(relative_path, &abs_path, &server.index, expected_gen) {
        watcher::FreshenResult::Fresh => false,
        watcher::FreshenResult::StaleReindexed => true,
        watcher::FreshenResult::StaleRemoved => true,
        watcher::FreshenResult::GenerationMismatch => false,
    }
}

pub(super) fn safe_repo_path_for_freshen(
    repo_root: &std::path::Path,
    relative_path: &str,
) -> Result<PathBuf, String> {
    let relative = std::path::Path::new(relative_path);
    if relative.is_absolute()
        || relative
            .components()
            .any(|component| matches!(component, std::path::Component::ParentDir))
    {
        return Err(format!("path '{relative_path}' is outside the repository"));
    }

    match edit::safe_repo_path(repo_root, relative_path) {
        Ok(path) => Ok(path),
        Err(_) => {
            let canon_root = repo_root
                .canonicalize()
                .map_err(|e| format!("cannot resolve repo root: {e}"))?;
            Ok(canon_root.join(relative))
        }
    }
}

fn search_scope_summary(
    path_scope: &search::PathScope,
    language_filter: Option<&LanguageId>,
    noise_policy: &search::NoisePolicy,
    include_personal_tooling: bool,
    glob: Option<&str>,
    exclude_glob: Option<&str>,
    ranked: bool,
) -> String {
    let mut parts = Vec::new();
    match path_scope {
        search::PathScope::Any => parts.push("repo-wide".to_string()),
        search::PathScope::Exact(path) => parts.push(format!("path `{path}`")),
        search::PathScope::Prefix(prefix) => parts.push(format!("path prefix `{prefix}`")),
    }
    if let Some(language) = language_filter {
        parts.push(format!("language `{language}`"));
    }
    // SF-STRESS-011 honesty fix: these are HEURISTIC path-based filters, not a
    // guaranteed outcome. Detection keys on path segments (vendor/, deps/,
    // dist/, test_data/, ...) and basename patterns, so a vendored/generated
    // file with an unconventional path can still appear in results. The header
    // says "filter active (heuristic)" rather than asserting the file class was
    // actually removed, which the previous "vendor filtered" wording overstated.
    parts.push(if noise_policy.include_tests {
        "tests included".to_string()
    } else {
        "tests filter active (heuristic)".to_string()
    });
    parts.push(if noise_policy.include_generated {
        "generated included".to_string()
    } else {
        "generated filter active (heuristic)".to_string()
    });
    parts.push(if noise_policy.include_vendor {
        "vendor included".to_string()
    } else {
        "vendor filter active (heuristic)".to_string()
    });
    parts.push(if include_personal_tooling {
        "personal tooling included".to_string()
    } else {
        "personal tooling filtered".to_string()
    });
    if let Some(glob) = glob {
        parts.push(format!("glob `{glob}`"));
    }
    if let Some(exclude_glob) = exclude_glob {
        parts.push(format!("exclude `{exclude_glob}`"));
    }
    if ranked {
        parts.push("ranked ordering enabled".to_string());
    }
    parts.join("; ")
}

fn search_parse_state_for_paths<'a, I>(index: &LiveIndex, paths: I) -> &'static str
where
    I: IntoIterator<Item = &'a str>,
{
    if paths
        .into_iter()
        .filter_map(|path| index.get_file(path))
        .any(|file| file.parse_diagnostic.is_some())
    {
        "partial"
    } else {
        "parsed"
    }
}

fn parse_state_for_file(file: &IndexedFile) -> &'static str {
    match &file.parse_status {
        crate::live_index::store::ParseStatus::Parsed => "parsed",
        crate::live_index::store::ParseStatus::PartialParse { .. } => {
            // SF-003: a partial parse caused only by the tree-sitter-typescript
            // 0.23.2 import-type-array grammar limitation is valid TypeScript;
            // report it as parsed rather than partial.
            if crate::parsing::is_expected_typescript_import_type_array_limitation(
                &file.language,
                &file.content,
                crate::domain::LanguageId::is_tsx_path(&file.relative_path),
            ) {
                "parsed"
            } else {
                "partial"
            }
        }
        crate::live_index::store::ParseStatus::Failed { .. } => "degraded",
    }
}

fn context_source_authority_label(refreshed: bool) -> &'static str {
    if refreshed {
        "disk-refreshed"
    } else {
        "current index"
    }
}

fn context_bundle_completeness_label(
    view: &crate::live_index::ContextBundleFoundView,
    rendered: &str,
) -> String {
    let section_overflow =
        view.callers.overflow_count + view.callees.overflow_count + view.type_usages.overflow_count;
    let mut parts = Vec::new();
    if rendered.contains("Truncated at ~") {
        parts.push("budget-limited".to_string());
    }
    if section_overflow > 0 {
        parts.push(format!(
            "section-capped ({} additional reference entries not shown)",
            section_overflow
        ));
    }
    if parts.is_empty() {
        "full".to_string()
    } else {
        parts.join("; ")
    }
}

fn search_completeness_label(overflow_count: usize, suppressed_by_noise: usize) -> String {
    // Honesty (trust): the index is built by a discovery walk with the `ignore`
    // crate default `.hidden(true)`, so hidden / dotdir paths (`.github/`,
    // `.gitlab-ci.yml`, …) are NOT indexed and never appear in results. A bare
    // "full" claim would mislead an agent into trusting the file count as
    // exhaustive (the dogfood report: `search_text` silently omitted
    // `.github/workflows/release-please.yml` that ripgrep found). Qualify the
    // claim so the agent knows to use a raw grep for hidden paths.
    let mut parts = vec![if overflow_count > 0 {
        format!("truncated by result cap ({overflow_count} more omitted)")
    } else {
        "full for indexed scope (hidden/dotdir paths not indexed — grep those)".to_string()
    }];
    if suppressed_by_noise > 0 {
        if suppressed_by_noise > search::SUPPRESSED_TEXT_MATCH_DISPLAY_CAP {
            parts.push(format!(
                "{}+ noise-filtered match(es) suppressed",
                search::SUPPRESSED_TEXT_MATCH_DISPLAY_CAP
            ));
        } else {
            parts.push(format!(
                "{suppressed_by_noise} noise-filtered match(es) suppressed"
            ));
        }
    }
    parts.join("; ")
}

fn search_text_match_type_label(
    structural: bool,
    is_regex: bool,
    terms: Option<&[String]>,
    auto_detected_regex: bool,
    auto_corrected_regex: bool,
    ranked: bool,
) -> String {
    if structural {
        "structural (ast-grep)".to_string()
    } else if auto_corrected_regex {
        "heuristic (auto-corrected regex)".to_string()
    } else if is_regex && auto_detected_regex {
        "heuristic (auto-detected regex)".to_string()
    } else if is_regex {
        "heuristic (regex)".to_string()
    } else if ranked {
        match terms {
            Some(terms) if !terms.is_empty() => "heuristic (ranked OR-literal terms)".to_string(),
            _ => "heuristic (ranked literal)".to_string(),
        }
    } else if matches!(terms, Some(terms) if !terms.is_empty()) {
        "constrained (OR-literal terms)".to_string()
    } else {
        "constrained (literal)".to_string()
    }
}

fn search_symbols_match_type_label(
    result: &search::SymbolSearchResult,
    is_browse: bool,
) -> &'static str {
    if is_browse {
        "constrained (scoped browse)"
    } else {
        match result.hits.first().map(|hit| hit.tier) {
            Some(search::SymbolMatchTier::Exact) => "exact",
            Some(search::SymbolMatchTier::Prefix) => "constrained (prefix tier)",
            Some(search::SymbolMatchTier::Substring) => "heuristic (substring tier)",
            None => "constrained",
        }
    }
}

fn search_files_match_type_label(view: &SearchFilesView) -> &'static str {
    match view {
        SearchFilesView::Found { hits, .. } => match hits.first().map(|hit| hit.tier) {
            Some(SearchFilesTier::CoChange) => "heuristic (git-temporal coupling)",
            Some(SearchFilesTier::StrongPath) | Some(SearchFilesTier::Basename) => {
                "constrained (tiered path relevance)"
            }
            Some(SearchFilesTier::LoosePath) => "heuristic (loose path relevance)",
            Some(SearchFilesTier::MetadataOnly) => "heuristic (Tier-2 metadata-only path)",
            None => "constrained",
        },
        _ => "constrained",
    }
}

const MAX_CO_CHANGE_PARTNERS_PER_ANCHOR: u32 = 20;

struct SearchFilesCoChangeResolution {
    neighbors: Option<SearchFilesCouplingNeighbors>,
    evidence: CapabilityEvidence,
}

fn cochange_ranking_evidence(
    status: CapabilityStatus,
    freshness: CapabilityFreshness,
    cost: CapabilityCost,
    detail: impl Into<String>,
) -> CapabilityEvidence {
    CapabilityEvidence::new(CapabilityName::CoChangeRanking, status)
        .with_freshness(freshness)
        .with_cost(cost)
        .with_safety(CapabilitySafety::ReadOnly)
        .with_detail(detail)
}

/// Build the precise `FallbackUsed` co-change detail for the case where the
/// coupling store loaded usable partner rows for the anchor, yet no returned
/// candidate landed in the co-change tier. The four distinguishable reasons:
///
/// 1. chore-anchor excluded (`is_chore_anchor_path` fires before the gate),
/// 2. anchor reached only prefix-tier path confidence (below the basename
///    floor), with a `query="<basename>"` hint to clear it,
/// 3. neighbors exist but none of them appear among the returned candidates
///    (the genuine path-mismatch case),
/// 4. neighbors appear among candidates but were filtered out by a later gate.
///
/// The anchor-confidence reason (1 and 2) is computed once at anchor level via
/// [`classify_anchor_cochange_rejection`], not per candidate.
fn cochange_fallback_detail(
    query: &str,
    anchor_path: &str,
    neighbors: &SearchFilesCouplingNeighbors,
    candidate_paths: &[&str],
) -> String {
    let partner_count = neighbors.len();
    let anchor_score = crate::live_index::query::anchor_path_match_score(query, anchor_path);
    match crate::live_index::rank_signals::classify_anchor_cochange_rejection(
        anchor_path,
        anchor_score,
    ) {
        Some(crate::live_index::rank_signals::AnchorCoChangeRejection::ChoreAnchor) => {
            format!(
                "anchor_path={anchor_path} loaded {partner_count} usable coupling partner(s), but it is a chore anchor (lockfile/changelog/workflow) excluded from co-change promotion; path ranking returned"
            )
        }
        Some(crate::live_index::rank_signals::AnchorCoChangeRejection::BelowConfidenceFloor) => {
            let anchor_basename = std::path::Path::new(anchor_path)
                .file_name()
                .and_then(|name| name.to_str())
                .unwrap_or(anchor_path);
            format!(
                "anchor_path={anchor_path} loaded {partner_count} usable coupling partner(s), but the query reached only prefix-tier path confidence for the anchor (below the basename-tier floor); pass query=\"{anchor_basename}\" to clear it; path ranking returned"
            )
        }
        None => {
            let any_partner_in_candidates = candidate_paths
                .iter()
                .any(|path| neighbors.contains_key(*path));
            if any_partner_in_candidates {
                format!(
                    "anchor_path={anchor_path} loaded {partner_count} usable coupling partner(s) present among returned candidates, but a later rank gate filtered them; path ranking returned"
                )
            } else {
                format!(
                    "anchor_path={anchor_path} loaded {partner_count} usable coupling partner(s), but none appear among the returned candidates; path ranking returned"
                )
            }
        }
    }
}

fn cochange_lazy_prepare_evidence(
    root: &Path,
    reason: &str,
    fallback_detail: &str,
) -> CapabilityEvidence {
    match crate::live_index::coupling::start_lazy_prepare(root) {
        Ok(crate::live_index::coupling::LazyPrepareOutcome::Started) => cochange_ranking_evidence(
            CapabilityStatus::Preparing,
            CapabilityFreshness::Unknown,
            CapabilityCost::Bounded,
            format!("{reason}; bounded background preparation started; {fallback_detail}"),
        ),
        Ok(crate::live_index::coupling::LazyPrepareOutcome::AlreadyRunning) => {
            cochange_ranking_evidence(
                CapabilityStatus::Preparing,
                CapabilityFreshness::Unknown,
                CapabilityCost::Bounded,
                format!(
                    "{reason}; bounded background preparation already in progress; {fallback_detail}"
                ),
            )
        }
        Err(error) => cochange_ranking_evidence(
            CapabilityStatus::Unavailable,
            CapabilityFreshness::Unknown,
            CapabilityCost::Bounded,
            format!("{reason}; unable to start bounded preparation: {error}; {fallback_detail}"),
        ),
    }
}

fn cochange_stale_prepare_evidence(root: &Path) -> CapabilityEvidence {
    match crate::live_index::coupling::start_lazy_prepare(root) {
        Ok(crate::live_index::coupling::LazyPrepareOutcome::Started) => cochange_ranking_evidence(
            CapabilityStatus::Stale,
            CapabilityFreshness::Stale,
            CapabilityCost::Bounded,
            "coupling store is stale for the current HEAD; bounded background refresh started; path ranking returned",
        ),
        Ok(crate::live_index::coupling::LazyPrepareOutcome::AlreadyRunning) => {
            cochange_ranking_evidence(
                CapabilityStatus::Stale,
                CapabilityFreshness::Stale,
                CapabilityCost::Bounded,
                "coupling store is stale for the current HEAD; bounded background refresh already in progress; path ranking returned",
            )
        }
        Err(error) => cochange_ranking_evidence(
            CapabilityStatus::Unavailable,
            CapabilityFreshness::Stale,
            CapabilityCost::Bounded,
            format!(
                "coupling store is stale for the current HEAD; unable to start bounded refresh: {error}; path ranking returned"
            ),
        ),
    }
}

fn search_files_coupling_neighbors(
    index: &LiveIndex,
    repo_root: Option<&Path>,
    anchor_path: &str,
) -> SearchFilesCoChangeResolution {
    let anchor_path = normalize_exact_path(anchor_path);
    if !index.files.contains_key(&anchor_path) {
        return SearchFilesCoChangeResolution {
            neighbors: None,
            evidence: cochange_ranking_evidence(
                CapabilityStatus::FallbackUsed,
                CapabilityFreshness::Unknown,
                CapabilityCost::Free,
                format!("anchor_path={anchor_path} is not indexed; path ranking returned"),
            ),
        };
    }

    match crate::live_index::coupling::coupling_prepare_policy_from_env() {
        CouplingPreparePolicy::Disabled => {
            return SearchFilesCoChangeResolution {
                neighbors: None,
                evidence: cochange_ranking_evidence(
                    CapabilityStatus::DisabledByPolicy,
                    CapabilityFreshness::Unknown,
                    CapabilityCost::Free,
                    "operator policy disabled co-change preparation and ranking; path ranking returned",
                ),
            };
        }
        CouplingPreparePolicy::LazyOnRequest | CouplingPreparePolicy::WarmOnStart => {}
    }

    let store = if let Some(store) = index.coupling_store() {
        Some(store.clone())
    } else if let Some(root) = repo_root {
        match crate::live_index::coupling::open_existing_coupling_store(root) {
            Ok(Some(store)) => Some((*store).clone()),
            Ok(None) => {
                return SearchFilesCoChangeResolution {
                    neighbors: None,
                    evidence: cochange_lazy_prepare_evidence(
                        root,
                        "no coupling store exists for this workspace",
                        "path ranking returned",
                    ),
                };
            }
            Err(error) => {
                return SearchFilesCoChangeResolution {
                    neighbors: None,
                    evidence: cochange_ranking_evidence(
                        CapabilityStatus::Unavailable,
                        CapabilityFreshness::Unknown,
                        CapabilityCost::Low,
                        format!("unable to open coupling store: {error}; path ranking returned"),
                    ),
                };
            }
        }
    } else {
        return SearchFilesCoChangeResolution {
            neighbors: None,
            evidence: cochange_ranking_evidence(
                CapabilityStatus::Unavailable,
                CapabilityFreshness::Unknown,
                CapabilityCost::Free,
                "no repository root is bound; path ranking returned",
            ),
        };
    };
    let Some(store) = store else {
        return SearchFilesCoChangeResolution {
            neighbors: None,
            evidence: cochange_ranking_evidence(
                CapabilityStatus::Unavailable,
                CapabilityFreshness::Unknown,
                CapabilityCost::Free,
                "no coupling store is available; path ranking returned",
            ),
        };
    };

    if let Some(root) = repo_root {
        match store.cold_built_at() {
            Ok(Some(_)) => {}
            Ok(None) => {
                return SearchFilesCoChangeResolution {
                    neighbors: None,
                    evidence: cochange_lazy_prepare_evidence(
                        root,
                        "coupling store exists but has not completed a cold build",
                        "path ranking returned",
                    ),
                };
            }
            Err(error) => {
                return SearchFilesCoChangeResolution {
                    neighbors: None,
                    evidence: cochange_ranking_evidence(
                        CapabilityStatus::Unavailable,
                        CapabilityFreshness::Unknown,
                        CapabilityCost::Low,
                        format!(
                            "unable to inspect coupling store build state: {error}; path ranking returned"
                        ),
                    ),
                };
            }
        }

        let stored_head = match store.last_head() {
            Ok(head) => head,
            Err(error) => {
                return SearchFilesCoChangeResolution {
                    neighbors: None,
                    evidence: cochange_ranking_evidence(
                        CapabilityStatus::Unavailable,
                        CapabilityFreshness::Unknown,
                        CapabilityCost::Low,
                        format!(
                            "unable to inspect coupling store HEAD state: {error}; path ranking returned"
                        ),
                    ),
                };
            }
        };
        let current_head = crate::git::head_sha(root).ok();
        if stored_head != current_head {
            return SearchFilesCoChangeResolution {
                neighbors: None,
                evidence: cochange_stale_prepare_evidence(root),
            };
        }
    }

    let rows = store
        .query_with_floor(
            &crate::live_index::coupling::AnchorKey::file(&anchor_path),
            MAX_CO_CHANGE_PARTNERS_PER_ANCHOR,
            crate::live_index::rank_signals::FILE_LEVEL_CO_CHANGE_FLOOR,
        )
        .map_err(|error| error.to_string());
    let rows = match rows {
        Ok(rows) => rows,
        Err(error) => {
            return SearchFilesCoChangeResolution {
                neighbors: None,
                evidence: cochange_ranking_evidence(
                    CapabilityStatus::Unavailable,
                    CapabilityFreshness::Unknown,
                    CapabilityCost::Low,
                    format!("unable to query coupling store: {error}; path ranking returned"),
                ),
            };
        }
    };
    let mut neighbors = HashMap::new();
    for row in rows {
        let Some(partner_path) = row.partner.as_str().strip_prefix("file:") else {
            continue;
        };
        let weighted_score = row.weighted_score as f32;
        if !weighted_score.is_finite() || weighted_score <= 0.0 {
            continue;
        }
        neighbors.insert(
            partner_path.to_string(),
            SearchFilesCouplingEvidence {
                shared_commits: row.shared_commits,
                weighted_score,
            },
        );
    }
    if neighbors.is_empty() {
        SearchFilesCoChangeResolution {
            neighbors: None,
            evidence: cochange_ranking_evidence(
                CapabilityStatus::FallbackUsed,
                CapabilityFreshness::Empty,
                CapabilityCost::Low,
                format!(
                    "ready coupling store has no usable partner rows for anchor_path={anchor_path}; path ranking returned"
                ),
            ),
        }
    } else {
        SearchFilesCoChangeResolution {
            neighbors: Some(neighbors),
            evidence: cochange_ranking_evidence(
                CapabilityStatus::Ready,
                CapabilityFreshness::Current,
                CapabilityCost::Low,
                format!(
                    "ready coupling store loaded usable partner rows for anchor_path={anchor_path}"
                ),
            ),
        }
    }
}

fn frecency_ranking_evidence(
    status: CapabilityStatus,
    detail: impl Into<String>,
) -> CapabilityEvidence {
    CapabilityEvidence::new(CapabilityName::FrecencyRanking, status)
        .with_freshness(CapabilityFreshness::Current)
        .with_safety(CapabilitySafety::ReadOnly)
        .with_detail(detail)
}

const RANKING_DIAGNOSTICS_ENV: &str = "SYMFORGE_DEBUG_RANKING";

fn ranking_diagnostics_policy_from_env() -> RankingDiagnosticsPolicy {
    match std::env::var(RANKING_DIAGNOSTICS_ENV) {
        Ok(value) => match value.trim().to_ascii_lowercase().as_str() {
            "" => RankingDiagnosticsPolicy::CallTimeExplain,
            "1" | "true" | "on" | "yes" | "default-on" => RankingDiagnosticsPolicy::DefaultOn,
            "0" | "false" | "no" | "off" | "disabled" | "disable" => {
                RankingDiagnosticsPolicy::Disabled
            }
            _ => RankingDiagnosticsPolicy::Disabled,
        },
        Err(std::env::VarError::NotPresent) => RankingDiagnosticsPolicy::CallTimeExplain,
        Err(std::env::VarError::NotUnicode(_)) => RankingDiagnosticsPolicy::Disabled,
    }
}

struct SearchFilesRankingDiagnosticsDecision {
    explain: bool,
    evidence: Option<CapabilityEvidence>,
}

fn ranking_diagnostics_evidence(
    status: CapabilityStatus,
    detail: impl Into<String>,
) -> CapabilityEvidence {
    CapabilityEvidence::new(CapabilityName::RankingDiagnostics, status)
        .with_freshness(CapabilityFreshness::Current)
        .with_safety(CapabilitySafety::ReadOnly)
        .with_detail(detail)
}

fn search_files_debug_ranking_requested(
    input: &SearchFilesInput,
) -> SearchFilesRankingDiagnosticsDecision {
    match ranking_diagnostics_policy_from_env() {
        RankingDiagnosticsPolicy::CallTimeExplain => SearchFilesRankingDiagnosticsDecision {
            explain: input.debug_ranking.unwrap_or(false),
            evidence: None,
        },
        RankingDiagnosticsPolicy::DefaultOn => SearchFilesRankingDiagnosticsDecision {
            explain: true,
            evidence: None,
        },
        RankingDiagnosticsPolicy::Disabled if input.debug_ranking.unwrap_or(false) => {
            SearchFilesRankingDiagnosticsDecision {
                explain: false,
                evidence: Some(ranking_diagnostics_evidence(
                    CapabilityStatus::DisabledByPolicy,
                    "operator policy disabled ranking diagnostics; ranking explanation omitted",
                )),
            }
        }
        RankingDiagnosticsPolicy::Disabled => SearchFilesRankingDiagnosticsDecision {
            explain: false,
            evidence: None,
        },
    }
}

fn search_files_rank_mode_label(rank_by: Option<&str>) -> &'static str {
    match rank_by {
        Some("frecency") => "frecency",
        Some("path+cochange") => "path+cochange",
        _ => "default path",
    }
}

fn search_files_tier_summary(view: &SearchFilesView) -> String {
    let SearchFilesView::Found { hits, .. } = view else {
        return "no returned files".to_string();
    };
    let mut cochange = 0usize;
    let mut strong = 0usize;
    let mut basename = 0usize;
    let mut loose = 0usize;
    let mut metadata = 0usize;
    for hit in hits {
        match hit.tier {
            SearchFilesTier::CoChange => cochange += 1,
            SearchFilesTier::StrongPath => strong += 1,
            SearchFilesTier::Basename => basename += 1,
            SearchFilesTier::LoosePath => loose += 1,
            SearchFilesTier::MetadataOnly => metadata += 1,
        }
    }
    let mut parts = Vec::new();
    if cochange > 0 {
        parts.push(format!("co-change={cochange}"));
    }
    if strong > 0 {
        parts.push(format!("strong path={strong}"));
    }
    if basename > 0 {
        parts.push(format!("basename={basename}"));
    }
    if loose > 0 {
        parts.push(format!("loose path={loose}"));
    }
    if metadata > 0 {
        parts.push(format!("metadata-only={metadata}"));
    }
    if parts.is_empty() {
        "no returned files".to_string()
    } else {
        parts.join(", ")
    }
}

fn search_files_signal_explanation(
    signal: &str,
    evidence: Option<&CapabilityEvidence>,
    not_requested: bool,
) -> String {
    if not_requested {
        return format!("{signal} signal: not requested");
    }
    match evidence {
        Some(evidence) => {
            let mut line = format!("{signal} signal: {}", evidence.status);
            if let Some(detail) = evidence.detail.as_deref().map(str::trim)
                && !detail.is_empty()
            {
                line.push_str(" - ");
                line.push_str(detail.trim_end_matches('.'));
            }
            line
        }
        None => format!("{signal} signal: unavailable - no capability evidence was recorded"),
    }
}

fn search_files_final_ordering_note(
    rank_by: Option<&str>,
    cochange_evidence: Option<&CapabilityEvidence>,
    frecency_evidence: Option<&CapabilityEvidence>,
) -> String {
    match rank_by {
        Some("frecency") => match frecency_evidence.map(|evidence| evidence.status) {
            Some(CapabilityStatus::Applied) => {
                "frecency fusion applied after path ranking; ties remain deterministic by path"
                    .to_string()
            }
            Some(status) => format!(
                "frecency requested but {status}; path-ranked ordering was returned"
            ),
            None => "frecency requested but no evidence was available; path-ranked ordering was returned"
                .to_string(),
        },
        Some("path+cochange") => match cochange_evidence.map(|evidence| evidence.status) {
            Some(CapabilityStatus::Applied) | Some(CapabilityStatus::Ready) => {
                "co-change partners that passed gates were fused with path ranking; remaining files keep path tie-breakers"
                    .to_string()
            }
            Some(status) => format!(
                "path+cochange requested but {status}; path-ranked ordering was returned"
            ),
            None => "path+cochange requested but no evidence was available; path-ranked ordering was returned"
                .to_string(),
        },
        _ => "tiered path relevance ordered the results with deterministic path tie-breakers"
            .to_string(),
    }
}

fn search_files_ranking_explanation(
    view: &SearchFilesView,
    rank_by: Option<&str>,
    cochange_evidence: Option<&CapabilityEvidence>,
    frecency_evidence: Option<&CapabilityEvidence>,
) -> String {
    let rank_mode = search_files_rank_mode_label(rank_by);
    let frecency_not_requested = rank_by != Some("frecency");
    let cochange_not_requested = rank_by != Some("path+cochange");
    [
        "Ranking explanation:".to_string(),
        format!("requested rank mode: {rank_mode}"),
        format!(
            "path signal: applied - returned tier family: {}",
            search_files_tier_summary(view)
        ),
        search_files_signal_explanation("frecency", frecency_evidence, frecency_not_requested),
        search_files_signal_explanation("co-change", cochange_evidence, cochange_not_requested),
        format!(
            "final ordering: {}",
            search_files_final_ordering_note(rank_by, cochange_evidence, frecency_evidence)
        ),
    ]
    .join("\n")
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct CapabilityStatusReport {
    frecency: String,
    co_change: String,
    worktree_routing: String,
    ranking_diagnostics: String,
}

impl CapabilityStatusReport {
    fn full_text(&self) -> String {
        format!(
            "Capabilities:\n  frecency: {}\n  co-change: {}\n  worktree routing: {}\n  ranking diagnostics: {}",
            self.frecency, self.co_change, self.worktree_routing, self.ranking_diagnostics
        )
    }

    fn compact_text(&self) -> String {
        format!(
            "Capabilities: frecency={}; co-change={}; worktree={}; ranking={}",
            self.frecency, self.co_change, self.worktree_routing, self.ranking_diagnostics
        )
    }
}

fn frecency_health_status(repo_root: Option<&Path>) -> String {
    let Some(repo_root) = repo_root else {
        return "unavailable/no-repository-root".to_string();
    };
    let has_persistent_history = crate::live_index::frecency::frecency_db_path(repo_root).is_file();
    match crate::live_index::frecency::collection_policy_from_env() {
        FrecencyCollectionPolicy::Disabled => "disabled by policy".to_string(),
        FrecencyCollectionPolicy::Session => {
            if has_persistent_history {
                "ready/session+persistent".to_string()
            } else {
                "ready/session/no-history fallback-used-on-empty".to_string()
            }
        }
        FrecencyCollectionPolicy::Persistent => {
            if has_persistent_history {
                "ready/persistent".to_string()
            } else {
                "ready/persistent/no-history fallback-used-on-empty".to_string()
            }
        }
    }
}

fn cochange_store_health_status(
    store: &crate::live_index::coupling::CouplingStore,
    repo_root: &Path,
) -> String {
    match store.cold_built_at() {
        Ok(Some(_)) => {}
        Ok(None) => return "preparing/cold-build-pending fallback-used-on-request".to_string(),
        Err(error) => return format!("unavailable/store-build-state-error ({error})"),
    }

    let stored_head = match store.last_head() {
        Ok(Some(head)) => head,
        Ok(None) => return "preparing/no-head-recorded fallback-used-on-request".to_string(),
        Err(error) => return format!("unavailable/store-head-state-error ({error})"),
    };
    let current_head = match crate::git::head_sha(repo_root) {
        Ok(head) => head,
        Err(error) => return format!("unavailable/head-read-failed ({error})"),
    };
    if stored_head != current_head {
        "stale/head-mismatch fallback-used-on-request".to_string()
    } else {
        "ready/current".to_string()
    }
}

fn cochange_health_status(index: &LiveIndex, repo_root: Option<&Path>) -> String {
    let policy = crate::live_index::coupling::coupling_prepare_policy_from_env();
    if matches!(policy, CouplingPreparePolicy::Disabled) {
        return "disabled by policy".to_string();
    }

    let Some(repo_root) = repo_root else {
        return "unavailable/no-repository-root".to_string();
    };
    if git2::Repository::discover(repo_root).is_err() {
        return "unavailable/not-a-git-repo".to_string();
    }

    if let Some(store) = index.coupling_store() {
        return cochange_store_health_status(store, repo_root);
    }

    match crate::live_index::coupling::open_existing_coupling_store(repo_root) {
        Ok(Some(store)) => cochange_store_health_status(store.as_ref(), repo_root),
        Ok(None) => match policy {
            CouplingPreparePolicy::LazyOnRequest => {
                "preparing/lazy-on-request fallback-used-on-request".to_string()
            }
            CouplingPreparePolicy::WarmOnStart => {
                "preparing/warm-on-start fallback-used-on-request".to_string()
            }
            CouplingPreparePolicy::Disabled => "disabled by policy".to_string(),
        },
        Err(error) => format!("unavailable/store-open-failed ({error})"),
    }
}

fn worktree_routing_health_status() -> String {
    match crate::worktree::routing_policy_from_env() {
        WorktreeRoutingPolicy::ExplicitCallTime => "explicit-call enabled".to_string(),
        WorktreeRoutingPolicy::Disabled => "disabled by policy".to_string(),
    }
}

fn ranking_diagnostics_health_status() -> String {
    match ranking_diagnostics_policy_from_env() {
        RankingDiagnosticsPolicy::CallTimeExplain => {
            "call-time explain available/default-off".to_string()
        }
        RankingDiagnosticsPolicy::DefaultOn => "call-time explain available/default-on".to_string(),
        RankingDiagnosticsPolicy::Disabled => "disabled by policy".to_string(),
    }
}

fn capability_status_report(index: &LiveIndex, repo_root: Option<&Path>) -> CapabilityStatusReport {
    CapabilityStatusReport {
        frecency: frecency_health_status(repo_root),
        co_change: cochange_health_status(index, repo_root),
        worktree_routing: worktree_routing_health_status(),
        ranking_diagnostics: ranking_diagnostics_health_status(),
    }
}

const CHANGED_WITH_DEPRECATION_WARNING: &str = "Deprecation warning: `search_files changed_with=` is deprecated since v7.x and scheduled for removal in v8.x; prefer `rank_by=\"path+cochange\"` with `anchor_path=<path>`.";

fn append_changed_with_deprecation_warning(mut result: String) -> String {
    result.push_str("\n\n");
    result.push_str(CHANGED_WITH_DEPRECATION_WARNING);
    result
}

fn search_files_total_matches(view: &SearchFilesView) -> usize {
    match view {
        SearchFilesView::Found { total_matches, .. } => *total_matches,
        _ => 0,
    }
}

fn search_symbols_total_matches(result: &search::SymbolSearchResult) -> usize {
    result.hits.len().saturating_add(result.overflow_count)
}

fn hidden_search_symbols_noise_count(
    index: &LiveIndex,
    query: &str,
    kind: Option<&str>,
    options: &search::SymbolSearchOptions,
    visible: &search::SymbolSearchResult,
) -> usize {
    if options.noise_policy.include_vendor && options.include_personal_tooling {
        return 0;
    }

    let mut unfiltered_options = options.clone();
    unfiltered_options.noise_policy.include_vendor = true;
    unfiltered_options.include_personal_tooling = true;
    let unfiltered = search::search_symbols_with_options(index, query, kind, &unfiltered_options);
    search_symbols_total_matches(&unfiltered).saturating_sub(search_symbols_total_matches(visible))
}

fn search_files_resolve_candidate_count(view: &SearchFilesResolveView) -> usize {
    match view {
        SearchFilesResolveView::Resolved { .. }
        | SearchFilesResolveView::ResolvedMetadataOnly { .. } => 1,
        SearchFilesResolveView::Ambiguous {
            matches,
            overflow_count,
            ..
        } => matches.len().saturating_add(*overflow_count),
        _ => 0,
    }
}

fn search_files_hidden_noise_note(
    hidden_count: usize,
    include_vendor: bool,
    include_personal_tooling: bool,
) -> Option<String> {
    if hidden_count == 0 || (include_vendor && include_personal_tooling) {
        return None;
    }

    let mut flags = Vec::new();
    if !include_vendor {
        flags.push("include_vendor=true");
    }
    if !include_personal_tooling {
        flags.push("include_personal_tooling=true");
    }

    let noun = if hidden_count == 1 {
        "path candidate"
    } else {
        "path candidates"
    };
    Some(format!(
        "{hidden_count} vendor/personal-tooling {noun} hidden by default; pass {} to include suppressed noise.",
        flags.join(" or ")
    ))
}

fn search_files_filter_summary(include_vendor: bool, include_personal_tooling: bool) -> String {
    // SF-STRESS-011 honesty fix: vendor detection is a heuristic path filter, so
    // the header says "filter active (heuristic)" rather than asserting the file
    // class was actually removed. Personal-tooling paths are an exact prefix
    // match, so that claim stays definite.
    let vendor = if include_vendor {
        "vendor included"
    } else {
        "vendor filter active (heuristic)"
    };
    let personal = if include_personal_tooling {
        "personal tooling included"
    } else {
        "personal tooling filtered"
    };
    format!("filters: {vendor}; {personal}")
}

fn search_files_scope_summary(
    base_scope: impl Into<String>,
    include_vendor: bool,
    include_personal_tooling: bool,
) -> String {
    format!(
        "{}; {}",
        base_scope.into(),
        search_files_filter_summary(include_vendor, include_personal_tooling)
    )
}

fn append_search_files_filter_summary(
    result: &mut String,
    include_vendor: bool,
    include_personal_tooling: bool,
) {
    result.push_str("\n\n");
    result.push_str(&search_files_filter_summary(
        include_vendor,
        include_personal_tooling,
    ));
}

fn search_files_resolve_match_type_label(view: &SearchFilesResolveView) -> &'static str {
    match view {
        SearchFilesResolveView::Resolved { .. } => "exact (resolve)",
        SearchFilesResolveView::ResolvedMetadataOnly { .. } => {
            "exact (resolve, Tier-2 metadata-only)"
        }
        SearchFilesResolveView::Ambiguous { .. } => "constrained (resolve candidates)",
        _ => "constrained",
    }
}

fn anchored_search_evidence(anchors: Vec<String>, noun: &str) -> String {
    if anchors.is_empty() {
        format!("no {noun} available")
    } else {
        let rendered = anchors
            .into_iter()
            .map(|anchor| format!("`{anchor}`"))
            .collect::<Vec<_>>()
            .join(", ");
        format!("{noun} {rendered}")
    }
}

fn search_text_evidence(result: &search::TextSearchResult) -> String {
    let anchors = result
        .files
        .iter()
        .flat_map(|file| {
            file.matches
                .iter()
                .take(2)
                .map(move |line_match| format!("{}:{}", file.path, line_match.line_number))
        })
        .take(3)
        .collect();
    anchored_search_evidence(anchors, "line anchors")
}

fn search_symbols_evidence(result: &search::SymbolSearchResult) -> String {
    let anchors = result
        .hits
        .iter()
        .take(3)
        .map(|hit| format!("{}:{}", hit.path, hit.line))
        .collect();
    anchored_search_evidence(anchors, "symbol anchors")
}

fn search_paths_evidence<'a, I>(paths: I) -> String
where
    I: IntoIterator<Item = &'a str>,
{
    let anchors = paths
        .into_iter()
        .take(3)
        .map(std::borrow::ToOwned::to_owned)
        .collect();
    anchored_search_evidence(anchors, "paths")
}

fn normalize_untracked_search_path(raw: &str) -> String {
    let mut normalized = raw.trim().replace('\\', "/");
    while normalized.starts_with("./") {
        normalized = normalized[2..].to_string();
    }
    normalized.trim_matches('/').to_string()
}

fn untracked_path_has_component(path: &str, component: &str) -> bool {
    path.split('/')
        .any(|part| part.eq_ignore_ascii_case(component))
}

fn language_for_path(path: &str) -> Option<LanguageId> {
    Path::new(path)
        .extension()
        .and_then(|extension| extension.to_str())
        .map(str::to_ascii_lowercase)
        .and_then(|extension| LanguageId::from_extension(&extension))
}

fn untracked_common_path_filters_allow(
    path: &str,
    include_vendor: bool,
    include_personal_tooling: bool,
) -> bool {
    (include_vendor || !crate::live_index::query::is_vendor_path(path))
        && (include_personal_tooling || !crate::live_index::query::is_personal_tooling_path(path))
}

fn untracked_paths_not_in_index(server: &SymForgeServer) -> Vec<String> {
    let Some(repo_root) = server.effective_repo_root_for_git_tools() else {
        return Vec::new();
    };
    let Ok(repo) = crate::git::GitRepo::open(&repo_root) else {
        return Vec::new();
    };
    let Ok(mut paths) = repo.untracked_paths() else {
        return Vec::new();
    };

    {
        let guard = server.index.read();
        paths.retain(|path| guard.get_file(path).is_none());
    }
    paths.sort();
    paths.dedup();
    paths
}

fn untracked_file_diagnostic(paths: &[String]) -> Option<String> {
    let first = paths.first()?;
    Some(format!(
        "untracked file may match: {} untracked path(s) are not indexed. To index the first match, call analyze_file_impact(\"{}\", new_file=true).",
        paths.len(),
        first
    ))
}

fn append_untracked_file_diagnostic(output: &mut String, paths: &[String]) {
    if let Some(diagnostic) = untracked_file_diagnostic(paths) {
        output.push_str("\n\n");
        output.push_str(&diagnostic);
    }
}

fn untracked_path_matches_search_files_query(path: &str, query: &str) -> bool {
    let normalized_query = normalize_untracked_search_path(query);
    if normalized_query.is_empty() {
        return false;
    }

    let is_glob = normalized_query.contains('*')
        || normalized_query.contains('?')
        || normalized_query.contains('[');
    if is_glob
        && let Ok(glob) = globset::GlobBuilder::new(&normalized_query)
            .literal_separator(false)
            .build()
    {
        return glob.compile_matcher().is_match(path);
    }

    let path_lower = path.to_ascii_lowercase();
    let normalized_query_lower = normalized_query.to_ascii_lowercase();
    let has_path_context = normalized_query.contains('/');
    if path_lower == normalized_query_lower
        || (has_path_context && path_lower.ends_with(&normalized_query_lower))
    {
        return true;
    }

    let tokens: Vec<String> = normalized_query
        .split(|ch: char| ch == '/' || ch.is_whitespace())
        .filter(|part| !part.is_empty())
        .map(str::to_ascii_lowercase)
        .collect();
    let Some(basename_token) = tokens.last() else {
        return false;
    };
    let component_tokens = if tokens.len() > 1 {
        &tokens[..tokens.len() - 1]
    } else {
        &[][..]
    };
    let file_name = Path::new(path)
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or("");
    if file_name.eq_ignore_ascii_case(basename_token)
        && component_tokens
            .iter()
            .all(|component| untracked_path_has_component(path, component))
    {
        return true;
    }

    if basename_token.len() >= 3 {
        let file_stem = Path::new(path)
            .file_stem()
            .and_then(|stem| stem.to_str())
            .unwrap_or("");
        if file_stem.to_ascii_lowercase().starts_with(basename_token) {
            return true;
        }
    }

    tokens.iter().all(|token| path_lower.contains(token))
}

fn matching_untracked_paths_for_search_files(
    server: &SymForgeServer,
    query: &str,
    include_vendor: bool,
    include_personal_tooling: bool,
) -> Vec<String> {
    untracked_paths_not_in_index(server)
        .into_iter()
        .filter(|path| {
            untracked_common_path_filters_allow(path, include_vendor, include_personal_tooling)
                && untracked_path_matches_search_files_query(path, query)
        })
        .collect()
}

fn untracked_text_path_allowed(path: &str, options: &search::TextSearchOptions) -> bool {
    let classification = FileClassification::for_code_path(path);
    options.path_scope.matches(path)
        && options.search_scope.allows(&classification)
        && options.noise_policy.allows(&classification)
        && (options.noise_policy.include_vendor || !crate::live_index::query::is_vendor_path(path))
        && (options.include_personal_tooling
            || !crate::live_index::query::is_personal_tooling_path(path))
        && options
            .language_filter
            .as_ref()
            .is_none_or(|language| language_for_path(path).as_ref() == Some(language))
        && untracked_text_globs_allow(path, options)
}

fn untracked_text_globs_allow(path: &str, options: &search::TextSearchOptions) -> bool {
    let include_matches = match options.glob.as_deref() {
        Some(pattern) => globset::GlobBuilder::new(pattern)
            .literal_separator(false)
            .build()
            .map(|glob| glob.compile_matcher().is_match(path))
            .unwrap_or(false),
        None => true,
    };
    let exclude_matches = match options.exclude_glob.as_deref() {
        Some(pattern) => globset::GlobBuilder::new(pattern)
            .literal_separator(false)
            .build()
            .map(|glob| glob.compile_matcher().is_match(path))
            .unwrap_or(false),
        None => false,
    };
    include_matches && !exclude_matches
}

fn whole_word_contains(haystack: &str, needle: &str) -> bool {
    haystack.match_indices(needle).any(|(idx, matched)| {
        let before_is_word = haystack[..idx]
            .chars()
            .next_back()
            .is_some_and(|ch| ch == '_' || ch.is_alphanumeric());
        let after_idx = idx + matched.len();
        let after_is_word = haystack[after_idx..]
            .chars()
            .next()
            .is_some_and(|ch| ch == '_' || ch.is_alphanumeric());
        !before_is_word && !after_is_word
    })
}

fn untracked_text_matches(
    content: &str,
    query: Option<&str>,
    terms: Option<&[String]>,
    is_regex: bool,
    options: &search::TextSearchOptions,
) -> bool {
    let case_sensitive = options.case_sensitive.unwrap_or(is_regex);
    if is_regex {
        let Some(pattern) = query.map(str::trim).filter(|pattern| !pattern.is_empty()) else {
            return false;
        };
        return regex::RegexBuilder::new(pattern)
            .case_insensitive(!case_sensitive)
            .build()
            .map(|regex| regex.is_match(content))
            .unwrap_or(false);
    }

    let normalized_terms: Vec<&str> = match terms {
        Some(raw_terms) if !raw_terms.is_empty() => raw_terms
            .iter()
            .map(|term| term.trim())
            .filter(|term| !term.is_empty())
            .collect(),
        _ => query
            .map(str::trim)
            .filter(|text| !text.is_empty())
            .map(|text| vec![text])
            .unwrap_or_default(),
    };
    if normalized_terms.is_empty() {
        return false;
    }

    if case_sensitive {
        if options.whole_word {
            normalized_terms
                .iter()
                .any(|term| whole_word_contains(content, term))
        } else {
            normalized_terms.iter().any(|term| content.contains(term))
        }
    } else {
        let lowered = content.to_lowercase();
        normalized_terms.iter().any(|term| {
            let lowered_term = term.to_lowercase();
            if options.whole_word {
                whole_word_contains(&lowered, &lowered_term)
            } else {
                lowered.contains(&lowered_term)
            }
        })
    }
}

fn matching_untracked_paths_for_search_text(
    server: &SymForgeServer,
    query: Option<&str>,
    terms: Option<&[String]>,
    structural: bool,
    is_regex: bool,
    options: &search::TextSearchOptions,
) -> Vec<String> {
    if structural {
        return Vec::new();
    }
    let Some(repo_root) = server.effective_repo_root_for_git_tools() else {
        return Vec::new();
    };
    let Ok(repo) = crate::git::GitRepo::open(&repo_root) else {
        return Vec::new();
    };

    untracked_paths_not_in_index(server)
        .into_iter()
        .filter(|path| untracked_text_path_allowed(path, options))
        .filter(|path| {
            repo.file_from_workdir(path)
                .ok()
                .flatten()
                .is_some_and(|content| {
                    untracked_text_matches(&content, query, terms, is_regex, options)
                })
        })
        .collect()
}

struct AdmissionDegradationView {
    tier: AdmissionTier,
    path: String,
    size: Option<u64>,
    extension: Option<String>,
    language: Option<LanguageId>,
    reason: Option<SkipReason>,
}

fn normalize_admission_degradation_path(raw: &str) -> String {
    let mut normalized = raw.trim().replace('\\', "/");
    while normalized.starts_with("./") {
        normalized = normalized[2..].to_string();
    }
    normalized.trim_matches('/').to_string()
}

fn admission_degradation_view_from_lookup(
    view: crate::live_index::query::AdmissionTierLookupView,
) -> AdmissionDegradationView {
    AdmissionDegradationView {
        tier: view.tier,
        path: view.path,
        size: view.size,
        extension: view.extension,
        language: view.language,
        reason: view.reason,
    }
}

fn admission_degradation_view_from_disk(
    repo_root: &Path,
    path: &str,
) -> Option<AdmissionDegradationView> {
    let canonical_root = std::fs::canonicalize(repo_root).ok()?;
    let raw_path = Path::new(path);
    let candidate = if raw_path.is_absolute() {
        raw_path.to_path_buf()
    } else {
        canonical_root.join(raw_path)
    };
    let canonical_candidate = std::fs::canonicalize(candidate).ok()?;
    if !canonical_candidate.starts_with(&canonical_root) {
        return None;
    }

    let metadata = std::fs::metadata(&canonical_candidate).ok()?;
    if !metadata.is_file() {
        return None;
    }

    let size = metadata.len();
    let initial_decision = crate::discovery::classify_admission(&canonical_candidate, size, None);
    let decision = if initial_decision.tier == AdmissionTier::Normal {
        let mut sample = Vec::new();
        let mut file = std::fs::File::open(&canonical_candidate).ok()?;
        file.by_ref()
            .take(BINARY_SNIFF_BYTES as u64)
            .read_to_end(&mut sample)
            .ok()?;
        crate::discovery::classify_admission(&canonical_candidate, size, Some(&sample))
    } else {
        initial_decision
    };

    let extension = canonical_candidate
        .extension()
        .and_then(|extension| extension.to_str())
        .map(str::to_string);
    let language = extension.as_deref().and_then(LanguageId::from_extension);

    // SF-004: a small, non-binary, non-denylisted file whose extension maps to
    // no supported grammar comes back `Normal` from `classify_admission` (which
    // never inspects language). On disk it EXISTS but cannot be parsed, so it
    // must report the honest Tier-2/UnsupportedLanguage degradation rather than
    // falling through to a false "File not found". Mirror the bulk-walk demotion
    // (store.rs Phase-2) via the same shared predicate. A recognized-language
    // file that is genuinely Tier-1 keeps its `Normal` decision and returns
    // `None` below so the caller's normal handling proceeds.
    let decision = if decision.tier == AdmissionTier::Normal && language.is_none() {
        crate::discovery::unsupported_language_decision(decision)
    } else {
        decision
    };

    if decision.tier == AdmissionTier::Normal {
        return None;
    }

    let relative_path = canonical_candidate
        .strip_prefix(&canonical_root)
        .ok()
        .map(|relative| relative.to_string_lossy().replace('\\', "/"))
        .filter(|relative| !relative.is_empty())
        .unwrap_or_else(|| normalize_admission_degradation_path(path));

    Some(AdmissionDegradationView {
        tier: decision.tier,
        path: relative_path,
        size: Some(size),
        extension,
        language,
        reason: decision.reason,
    })
}

fn admission_tier_degradation_for_path(
    index: &LiveIndex,
    repo_root: Option<&Path>,
    tool_name: &str,
    path: &str,
    symbol_name: &str,
) -> Option<String> {
    let view = index
        .capture_admission_tier_lookup_view(path)
        .map(admission_degradation_view_from_lookup)
        .or_else(|| repo_root.and_then(|root| admission_degradation_view_from_disk(root, path)))?;
    match view.tier {
        AdmissionTier::Normal => None,
        AdmissionTier::MetadataOnly => Some(format!(
            "degraded result (Tier 2 metadata-only): `{tool_name}` cannot return symbol or \
             reference data for `{}` because SymForge admits this path as metadata-only instead \
             of parsing it.\n\n\
             Warning: metadata-only files are not parsed, so no symbol or reference data exists \
             for this file.\n\
             Path: {}\n\
             Size: {}\n\
             Extension: {}\n\
             Language: {}\n\
             Reason: {}\n\
             Requested symbol: `{symbol_name}`\n\n\
             No symbol or reference data is available for this file.",
            view.path,
            view.path,
            view.size
                .map(|size| format!("{size} bytes"))
                .unwrap_or_else(|| "unknown".to_string()),
            view.extension.as_deref().unwrap_or("unavailable"),
            view.language
                .as_ref()
                .map(std::string::ToString::to_string)
                .unwrap_or_else(|| "unavailable".to_string()),
            view.reason
                .map(|reason| reason.to_string())
                .unwrap_or_else(|| "unknown".to_string()),
        )),
        AdmissionTier::HardSkip => Some(format!(
            "Not available (Tier 3 hard-skipped): `{tool_name}` cannot inspect `{}` because \
             the file was hard-skipped during admission.\n\n\
             Path: {}\n\
             Size: {}\n\
             Extension: {}\n\
             Reason: {}\n\
             Requested symbol: `{symbol_name}`\n\n\
             No symbol or reference data is available for this file.",
            view.path,
            view.path,
            view.size
                .map(|size| format!("{size} bytes"))
                .unwrap_or_else(|| "unknown".to_string()),
            view.extension.as_deref().unwrap_or("unavailable"),
            view.reason
                .map(|reason| reason.to_string())
                .unwrap_or_else(|| "unknown".to_string()),
        )),
    }
}

/// File-level (non-symbol) variant of admission-tier degradation. Returns an
/// honest "not indexed" message for a path that EXISTS but was admitted as
/// Tier-2 metadata-only or Tier-3 hard-skipped, instead of a misleading
/// "File not found". Resolution reuses the same index-lookup + disk-fallback
/// path as `admission_tier_degradation_for_path`, so the containment guard in
/// `admission_degradation_view_from_disk` (path must stay within the repo root)
/// is preserved. `None` means the path is either Tier-1 (indexed) or genuinely
/// absent — the caller should fall through to its normal not-found handling.
fn admission_tier_file_degradation_for_path(
    index: &LiveIndex,
    repo_root: Option<&Path>,
    path: &str,
) -> Option<String> {
    let view = index
        .capture_admission_tier_lookup_view(path)
        .map(admission_degradation_view_from_lookup)
        .or_else(|| repo_root.and_then(|root| admission_degradation_view_from_disk(root, path)))?;
    if view.tier == AdmissionTier::Normal {
        return None;
    }
    Some(format::not_indexed_skipped_file(
        &view.path,
        view.tier,
        view.reason,
        view.size,
    ))
}

fn find_references_match_type_label(input: &FindReferencesInput, mode: &str) -> &'static str {
    if mode == "implementations" {
        return "constrained (implementations mode)";
    }
    if input.path.is_some() && input.symbol_line.is_some() {
        "exact"
    } else if input.path.is_some() {
        "constrained (path-scoped symbol)"
    } else if input.symbol_kind.is_some() || input.kind.as_deref().is_some_and(|kind| kind != "all")
    {
        "constrained (repo-wide filtered symbol)"
    } else {
        "constrained (repo-wide name match)"
    }
}

fn find_references_scope_summary(input: &FindReferencesInput, mode: &str) -> String {
    let mut parts = Vec::new();
    if mode == "implementations" {
        parts.push(format!(
            "repo-wide implementations for symbol token `{}`",
            input.name
        ));
        parts.push(format!(
            "direction `{}`",
            input.direction.as_deref().unwrap_or("auto")
        ));
        return parts.join("; ");
    }

    match input.path.as_deref() {
        Some(path) => parts.push(format!("path `{path}`")),
        None => parts.push(format!("repo-wide symbol token `{}`", input.name)),
    }
    if let Some(line) = input.symbol_line {
        parts.push(format!("exact selector line {line}"));
    }
    if let Some(symbol_kind) = input.symbol_kind.as_deref() {
        parts.push(format!("symbol kind `{symbol_kind}`"));
    }
    if let Some(reference_kind) = input.kind.as_deref().filter(|kind| *kind != "all") {
        parts.push(format!("reference kind `{reference_kind}`"));
    }
    parts.join("; ")
}

/// True when the `references`-mode `kind` filter sweeps in type/value usages,
/// whose recall is genuinely best-effort: the xref extractor resolves them
/// syntactically and misses dynamic dispatch, macro-generated, reflective, and
/// cross-language usages. Direct `call`/`import`/`macro_use` references are
/// extracted reliably, so they earn no caveat (and `implementations` mode never
/// reaches this label — it has its own branch). `None`/`"all"` default includes
/// type/value usages, so it is best-effort too.
fn find_references_kind_is_best_effort(kind: Option<&str>) -> bool {
    // Mirror `find_references_kind_filter` rather than duplicating a string
    // whitelist, so the caveat can never drift from the kinds actually returned.
    // A filter result of `None` means "no kind filter" -> all kinds returned,
    // INCLUDING best-effort type/value usages; that covers `all`/`None` AND any
    // UNRECOGNIZED kind (the filter's `_ => None` arm), so a typo'd `kind` still
    // gets the caveat instead of silently shipping a best-effort trace unmarked.
    matches!(
        find_references_kind_filter(kind),
        None | Some(ReferenceKind::TypeUsage) | Some(ReferenceKind::ValueUse)
    )
}

fn find_references_completeness_label(
    view: &crate::live_index::FindReferencesView,
    limits: &format::OutputLimits,
    kind: Option<&str>,
) -> String {
    let shown_files = view.files.len().min(limits.max_files);
    let mut shown_refs = 0usize;
    for file in view.files.iter().take(limits.max_files) {
        if shown_refs >= limits.total_hits {
            break;
        }
        let remaining_budget = limits.total_hits.saturating_sub(shown_refs);
        shown_refs += file
            .hits
            .len()
            .min(limits.max_per_file)
            .min(remaining_budget);
    }
    let omitted_refs = view.total_refs.saturating_sub(shown_refs);
    let omitted_files = view.total_files.saturating_sub(shown_files);
    // Recall-confidence caveat, targeted (not blanket): only type/value-usage
    // traces are best-effort, so only they carry it. Riding the existing
    // completeness label keeps it one site, one envelope, no ResultStatus bump.
    let recall_caveat = if find_references_kind_is_best_effort(kind) {
        " — usage-trace recall is best-effort; dynamic dispatch, macro-generated, \
         reflective, and cross-language usages may be missed"
    } else {
        ""
    };
    if omitted_refs == 0 && omitted_files == 0 {
        return format!("full for current scope{recall_caveat}");
    }
    let mut parts = vec!["truncated by result cap".to_string()];
    if omitted_refs > 0 {
        parts.push(format!("{omitted_refs} reference(s) omitted"));
    }
    if omitted_files > 0 {
        parts.push(format!("{omitted_files} file(s) omitted"));
    }
    format!("{}{recall_caveat}", parts.join("; "))
}

fn find_references_evidence(view: &crate::live_index::FindReferencesView) -> String {
    let anchors = view
        .files
        .iter()
        .flat_map(|file| {
            let file_path = file.file_path.clone();
            file.hits.iter().flat_map(move |hit| {
                hit.context_lines
                    .iter()
                    .filter(|line| line.is_reference_line)
                    .map({
                        let file_path = file_path.clone();
                        move |line| format!("{file_path}:{}", line.line_number)
                    })
            })
        })
        .take(3)
        .collect();
    anchored_search_evidence(anchors, "reference anchors")
}

/// Feature 012 (Phase 3), Principle VII honesty: a cross-project read targets
/// the daemon-owned working set, which does not exist on the local (`/mcp` HTTP,
/// stdio/embed, or daemon-degraded) execution path. When a `project`/`projects`
/// param is present and we are about to run LOCALLY, return an honest refusal
/// instead of silently ignoring the target and serving the active project only.
/// Returns the refusal message when the request is cross-project, else `None`.
///
/// C-stopgap (D16): on the `/mcp` HTTP transport there is no daemon behind the
/// handler (`proxy_tool_call` short-circuits to `None` because `daemon_client`
/// is `None`), so this is the guard that contains D16's silent-wrong half —
/// `/mcp` loudly refuses cross-project targeting rather than silently serving the
/// single bound index. `tests/serve_http_attach.rs` locks it end-to-end.
fn local_cross_project_refusal(
    project: Option<&str>,
    projects: Option<&[String]>,
) -> Option<String> {
    let has_project = project.map(|p| !p.trim().is_empty()).unwrap_or(false);
    let has_projects = projects.map(|p| !p.is_empty()).unwrap_or(false);
    if has_project || has_projects {
        Some(
            "Cross-project queries (project/projects) require the daemon: the \
             working set of open projects lives on the daemon transport, not on \
             the /mcp HTTP transport, stdio/embed, or while the daemon is \
             unreachable. Start the daemon to query across projects."
                .to_string(),
        )
    } else {
        None
    }
}

fn find_references_kind_filter(kind_filter: Option<&str>) -> Option<ReferenceKind> {
    match kind_filter {
        Some("call") => Some(ReferenceKind::Call),
        Some("import") => Some(ReferenceKind::Import),
        Some("type_usage") => Some(ReferenceKind::TypeUsage),
        Some("macro_use") => Some(ReferenceKind::MacroUse),
        Some("value_use") => Some(ReferenceKind::ValueUse),
        Some("all") | None => None,
        _ => None,
    }
}

fn should_collect_qualified_usages(input: &FindReferencesInput) -> bool {
    input.path.is_none()
        && !input.name.is_empty()
        && matches!(
            input.kind.as_deref(),
            None | Some("all") | Some("type_usage")
        )
}

fn qualified_usage_hit_view(usage: &QualifiedUsage) -> ReferenceHitView {
    let confidence = if usage.confident {
        "confident"
    } else {
        "uncertain"
    };
    let annotation = format!("[qualified-path scan: {confidence}]");

    ReferenceHitView {
        context_lines: vec![ReferenceContextLineView {
            line_number: usage.line,
            text: usage.line_text.clone(),
            is_reference_line: true,
            enclosing_annotation: Some(annotation),
        }],
    }
}

fn merge_qualified_usages_into_view(
    view: &mut FindReferencesView,
    mut usages: Vec<QualifiedUsage>,
    mut seen_ranges: HashSet<(String, (u32, u32))>,
) {
    let mut known_files: HashSet<String> = seen_ranges
        .iter()
        .map(|(file_path, _)| file_path.clone())
        .collect();
    known_files.extend(view.files.iter().map(|file| file.file_path.clone()));

    usages.sort_by(|a, b| {
        a.file_path
            .cmp(&b.file_path)
            .then(a.line.cmp(&b.line))
            .then(a.byte_range.0.cmp(&b.byte_range.0))
    });

    let mut added = 0usize;
    for usage in usages {
        let range_key = (usage.file_path.clone(), usage.byte_range);
        if !seen_ranges.insert(range_key) {
            continue;
        }
        let hit = qualified_usage_hit_view(&usage);
        if let Some(file_view) = view
            .files
            .iter_mut()
            .find(|file| file.file_path == usage.file_path)
        {
            file_view.hits.push(hit);
        } else {
            view.files.push(ReferenceFileView {
                file_path: usage.file_path.clone(),
                hits: vec![hit],
            });
        }
        known_files.insert(usage.file_path);
        added += 1;
    }

    if added > 0 {
        view.total_refs += added;
        view.total_files = known_files.len();
        view.files.sort_by(|a, b| a.file_path.cmp(&b.file_path));
    }
}

fn implementations_parse_state_for_paths(
    index: &LiveIndex,
    view: &crate::live_index::ImplementationsView,
) -> &'static str {
    search_parse_state_for_paths(
        index,
        view.entries.iter().map(|entry| entry.file_path.as_str()),
    )
}

fn implementations_completeness_label(
    view: &crate::live_index::ImplementationsView,
    limits: &format::OutputLimits,
) -> String {
    let shown = view
        .entries
        .len()
        .min(limits.max_files * limits.max_per_file);
    let omitted = view.entries.len().saturating_sub(shown);
    if omitted == 0 {
        "full for current scope".to_string()
    } else {
        format!("truncated by result cap ({omitted} implementation entry(s) omitted)")
    }
}

fn implementations_evidence(view: &crate::live_index::ImplementationsView) -> String {
    let anchors = view
        .entries
        .iter()
        .take(3)
        .map(|entry| format!("{}:{}", entry.file_path, entry.line + 1))
        .collect();
    anchored_search_evidence(anchors, "implementation anchors")
}

fn explore_is_test_like_path(
    path: &str,
    classification: Option<&crate::domain::index::FileClassification>,
) -> bool {
    let path_lower = path.replace('\\', "/").to_ascii_lowercase();
    classification.is_some_and(|c| c.is_test)
        || path_lower.contains("/tests/")
        || path_lower.contains("/test/")
        || path_lower.contains("/__tests__/")
        || path_lower.ends_with("/tests.rs")
        || path_lower.ends_with("/test.rs")
        || path_lower.ends_with("_test.rs")
        || path_lower.ends_with("_spec.rs")
}

fn explore_should_skip_path_boost(
    path: &str,
    classification: &crate::domain::index::FileClassification,
    include_noise: bool,
    include_vendor: bool,
    include_personal_tooling: bool,
) -> bool {
    let suppress_vendor = !(include_noise || include_vendor);
    let suppress_personal = !(include_noise || include_personal_tooling);
    let suppress_other = !include_noise;
    if !suppress_vendor && !suppress_personal && !suppress_other {
        return false;
    }
    if suppress_other && explore_is_test_like_path(path, Some(classification)) {
        return true;
    }
    if suppress_personal && crate::live_index::query::is_personal_tooling_path(path) {
        return true;
    }
    if suppress_vendor && classification.is_vendor {
        return true;
    }
    if suppress_other && (classification.is_generated || classification.is_config) {
        return true;
    }
    false
}

/// Whether a concept `text_query` legitimately matches `line` at a word
/// boundary, rather than as a coincidental substring inside a larger
/// identifier.
///
/// SF-STRESS-013: concept text queries are matched by plain case-insensitive
/// substring, so `"try {"` substring-matches `public string Country { ... }`
/// (`coun-TRY-{`) and floods DTO-property results into "Error Handling". When a
/// query begins with an identifier token, we require the character immediately
/// before the match to be a non-word character (or the line start), so the
/// token sits on a real word boundary. Queries that begin with punctuation
/// (e.g. `.expect(`, `#[derive(Serialize`) are already specific and pass
/// through unchanged. This only *rejects* false positives in explore; it never
/// invents new matches.
fn concept_text_query_matches_on_boundary(line: &str, query: &str) -> bool {
    let line_lower = line.to_ascii_lowercase();
    let query_lower = query.to_ascii_lowercase();

    // Anchor token = the leading run of word characters in the query.
    let anchor: String = query_lower
        .chars()
        .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
        .collect();
    if anchor.is_empty() {
        // Punctuation-led query (e.g. `.expect(`); substring containment is the
        // intended semantics and already specific.
        return line_lower.contains(&query_lower);
    }

    // Require at least one occurrence of the full query whose anchor token sits
    // on a left word boundary.
    let anchor_bytes = anchor.as_bytes();
    let mut start = 0usize;
    while let Some(rel) = line_lower[start..].find(&query_lower) {
        let pos = start + rel;
        let left_ok = pos == 0
            || !line_lower.as_bytes()[pos - 1].is_ascii_alphanumeric()
                && line_lower.as_bytes()[pos - 1] != b'_';
        if left_ok {
            // Anchor is a prefix of the query, so the right boundary of the
            // anchor is the char at pos + anchor.len(); for code idioms the
            // query already includes the trailing delimiter (e.g. `unwrap()`),
            // so a left boundary is sufficient to reject identifier-internal
            // hits like `coun|try {`.
            debug_assert!(query_lower.as_bytes().starts_with(anchor_bytes));
            return true;
        }
        // Advance past this occurrence to keep scanning.
        start = pos + 1;
        if start >= line_lower.len() {
            break;
        }
    }
    false
}

fn explore_path_penalty(
    path: &str,
    classification: Option<&crate::domain::index::FileClassification>,
) -> u64 {
    let path_lower = path.replace('\\', "/").to_ascii_lowercase();
    if explore_is_test_like_path(path, classification) {
        return 2;
    }
    if classification.is_some_and(|c| c.is_config)
        || path_lower.ends_with(".md")
        || path_lower.ends_with(".html")
        || path_lower.ends_with(".htm")
        || path_lower.contains("/docs/")
        || path_lower.contains("/doc/")
        || path_lower.contains("/plans/")
        || path_lower.contains("/manual/")
        || path_lower.contains("changelog")
        || path_lower.contains(".planning/")
        || path_lower.contains(".auto-claude")
    {
        return 2;
    }
    if path_lower.contains("/examples/")
        || path_lower.contains("/fixtures/")
        || path_lower.contains("/bench/")
        || path_lower.contains("/benches/")
        || path_lower.contains("/sample/")
        || path_lower.contains("/samples/")
    {
        return 3;
    }
    8
}

fn explore_fallback_alignment_multiplier(
    query_term_count: usize,
    matched_term_count: usize,
) -> u64 {
    if query_term_count <= 1 {
        return 8;
    }
    match (query_term_count, matched_term_count) {
        (_, 0) => 1,
        (2, 1) => 3,
        (2, _) => 8,
        (3, 1) => 2,
        (3, 2) => 6,
        (3, _) => 8,
        (_, 1) => 1,
        (_, 2) => 4,
        _ => 8,
    }
}

fn changed_paths_completeness_label(before_filter: usize, after_filter: usize) -> String {
    if before_filter == after_filter {
        "full for current scope".to_string()
    } else {
        format!("full for filtered scope ({after_filter} of {before_filter} path(s) shown)")
    }
}

fn what_changed_scope_summary(input: &WhatChangedInput, mode: &WhatChangedMode) -> String {
    let mut parts = Vec::new();
    match mode {
        WhatChangedMode::Timestamp(since_ts) => parts.push(format!("timestamp since `{since_ts}`")),
        WhatChangedMode::Uncommitted => parts.push("uncommitted working tree".to_string()),
        WhatChangedMode::GitRef(git_ref) => {
            parts.push(format!("git diff from `{git_ref}` to `HEAD`"))
        }
    }
    if let Some(path_prefix) = input
        .path_prefix
        .as_deref()
        .filter(|prefix| !prefix.trim().is_empty())
    {
        parts.push(format!(
            "path prefix `{}`",
            normalize_exact_path(path_prefix)
        ));
    }
    if let Some(language) = input.language.as_deref() {
        parts.push(format!("language `{language}`"));
    }
    if input.code_only.unwrap_or(false) {
        parts.push("code-only filter".to_string());
    }
    if input.include_symbol_diff.unwrap_or(false) {
        parts.push("symbol diff appended".to_string());
    }
    parts.join("; ")
}

fn what_changed_source_authority_label(mode: &WhatChangedMode) -> &'static str {
    match mode {
        WhatChangedMode::Timestamp(_) => "current index",
        WhatChangedMode::Uncommitted => "git working tree",
        WhatChangedMode::GitRef(_) => "git ref diff",
    }
}

fn what_changed_parse_state_label(
    mode: &WhatChangedMode,
    include_symbol_diff: bool,
) -> &'static str {
    match mode {
        WhatChangedMode::Timestamp(_) => "parsed",
        _ if include_symbol_diff => {
            "degraded (git path diff + lexical symbol diff — regex extraction may miss nested symbols)"
        }
        _ => "not-applicable (git path diff)",
    }
}

#[allow(clippy::too_many_arguments)]
fn render_diff_symbols_output(
    base: &str,
    target: &str,
    all_changed_files: usize,
    changed_files: &[&str],
    repo: &crate::git::GitRepo,
    compact: bool,
    summary_only: bool,
    path_prefix: Option<&str>,
    language: Option<&str>,
    code_only: bool,
) -> String {
    let mut scope_parts = vec![format!("git diff `{base}`...`{target}`")];
    if let Some(path_prefix) = path_prefix.filter(|prefix| !prefix.trim().is_empty()) {
        scope_parts.push(format!(
            "path prefix `{}`",
            normalize_exact_path(path_prefix)
        ));
    }
    if let Some(language) = language {
        scope_parts.push(format!("language `{language}`"));
    }
    if code_only {
        scope_parts.push("code-only filter".to_string());
    }
    if compact {
        scope_parts.push("compact output".to_string());
    }
    if summary_only {
        scope_parts.push("summary-only output".to_string());
    }
    let completeness = if changed_files.len() == all_changed_files {
        "full for filtered git delta".to_string()
    } else {
        format!(
            "full for filtered git delta ({} of {} changed file(s) shown)",
            changed_files.len(),
            all_changed_files
        )
    };
    let envelope = search_format::format_search_envelope(
        "exact (git ref diff)",
        "git ref diff",
        "high (tree-sitter AST extraction for supported languages, regex fallback for others)",
        &completeness,
        &scope_parts.join("; "),
        &search_paths_evidence(changed_files.iter().copied()),
    );
    let output =
        format::diff_symbols_result_view(base, target, changed_files, repo, compact, summary_only);
    format!("{envelope}\n\n{output}")
}

/// Strip vendor / personal-tooling paths from a `TextSearchResult` per the
/// caller's `include_vendor` / `include_personal_tooling` flags. Suppressed
/// match counts feed `suppressed_by_noise`, which renders into the existing
/// "N noise-filtered match(es) suppressed" envelope footer.
fn apply_path_predicate_filter(
    result: &mut Result<search::TextSearchResult, search::TextSearchError>,
    include_vendor: bool,
    include_personal_tooling: bool,
) {
    if include_vendor && include_personal_tooling {
        return;
    }
    if let Ok(r) = result {
        let mut filtered: usize = 0;
        r.files.retain(|file| {
            if !include_vendor && crate::live_index::query::is_vendor_path(&file.path) {
                filtered += file.matches.len();
                return false;
            }
            if !include_personal_tooling
                && crate::live_index::query::is_personal_tooling_path(&file.path)
            {
                filtered += file.matches.len();
                return false;
            }
            true
        });
        r.suppressed_by_noise = r.suppressed_by_noise.saturating_add(filtered);
    }
}

#[allow(clippy::too_many_arguments)]
fn render_search_text_output(
    server: &SymForgeServer,
    result: Result<search::TextSearchResult, search::TextSearchError>,
    query: Option<&str>,
    structural: bool,
    group_by: Option<&str>,
    terms: Option<&[String]>,
    options: &search::TextSearchOptions,
    is_regex: bool,
    auto_detected_regex: bool,
    auto_corrected_regex: bool,
) -> String {
    let envelope = match &result {
        Ok(result) if !result.files.is_empty() => {
            let guard = server.index.read();
            Some(search_format::format_search_envelope(
                &search_text_match_type_label(
                    structural,
                    is_regex,
                    terms,
                    auto_detected_regex,
                    auto_corrected_regex,
                    options.ranked,
                ),
                "current index",
                search_parse_state_for_paths(
                    &guard,
                    result.files.iter().map(|file| file.path.as_str()),
                ),
                &search_completeness_label(result.overflow_count, result.suppressed_by_noise),
                &search_scope_summary(
                    &options.path_scope,
                    options.language_filter.as_ref(),
                    &options.noise_policy,
                    options.include_personal_tooling,
                    options.glob.as_deref(),
                    options.exclude_glob.as_deref(),
                    options.ranked,
                ),
                &search_text_evidence(result),
            ))
        }
        _ => None,
    };
    let matching_untracked_paths = match &result {
        Ok(result) if result.files.is_empty() && result.suppressed_by_noise == 0 => {
            matching_untracked_paths_for_search_text(
                server, query, terms, structural, is_regex, options,
            )
        }
        _ => Vec::new(),
    };
    let confidence = if auto_corrected_regex {
        0.75f32
    } else if is_regex && auto_detected_regex {
        0.80
    } else if is_regex {
        0.85
    } else if options.ranked {
        0.80
    } else {
        0.95
    };
    let output = format::search_text_result_view(
        result,
        group_by,
        terms,
        Some(confidence),
        format::SearchSuggestionContext {
            regex: is_regex,
            include_tests: options.noise_policy.include_tests,
        },
    );
    let mut rendered = match envelope {
        Some(envelope) => format!("{envelope}\n\n{output}"),
        None => output,
    };
    append_untracked_file_diagnostic(&mut rendered, &matching_untracked_paths);
    rendered
}

fn search_text_compaction_query(query: Option<&str>, terms: Option<&[String]>) -> String {
    if let Some(q) = query.filter(|s| !s.trim().is_empty()) {
        return q.to_string();
    }
    terms
        .map(|items| {
            items
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join(" ")
        })
        .unwrap_or_default()
}

fn maybe_compact_text_search_result(
    result: &mut Result<search::TextSearchResult, search::TextSearchError>,
    query: &str,
) {
    if query.trim().is_empty() {
        return;
    }
    if let Ok(text) = result {
        crate::protocol::ccr::compact_text_search_result(text, query);
    }
}

fn resolve_text_search_enclosing_symbols(
    index: &LiveIndex,
    result: &mut Result<search::TextSearchResult, search::TextSearchError>,
) {
    let Ok(result) = result else {
        return;
    };

    for file_matches in &mut result.files {
        let Some(file) = index.get_file(&file_matches.path) else {
            continue;
        };

        for line_match in &mut file_matches.matches {
            let zero_based_line = line_match.line_number.saturating_sub(1) as u32;
            line_match.enclosing_symbol =
                crate::domain::find_enclosing_symbol(&file.symbols, zero_based_line)
                    .and_then(|idx| file.symbols.get(idx as usize))
                    .map(|symbol| search::EnclosingMatchSymbol {
                        name: symbol.name.clone(),
                        kind: symbol.kind.to_string(),
                        line_range: symbol.line_range,
                    });
        }
    }
}

fn sidecar_state_for_server(server: &SymForgeServer) -> SidecarState {
    SidecarState {
        index: Arc::clone(&server.index),
        token_stats: server.token_stats.clone().unwrap_or_else(TokenStats::new),
        repo_root: server.capture_repo_root(),
        symbol_cache: Arc::new(RwLock::new(HashMap::new())),
    }
}

fn sidecar_status_for_server(server: &SymForgeServer) -> crate::sidecar::port_file::SidecarStatus {
    let bind_host =
        std::env::var("SYMFORGE_SIDECAR_BIND").unwrap_or_else(|_| "127.0.0.1".to_string());
    if let Some(repo_root) = server.capture_repo_root() {
        let symforge_dir = repo_root.join(crate::sidecar::port_file::DIR_NAME);
        return crate::sidecar::port_file::read_sidecar_status_at(&symforge_dir, &bind_host);
    }
    crate::sidecar::port_file::read_sidecar_status(&bind_host)
}

/// Best-effort PATH-shadow report for the binary serving this runtime.
///
/// Uses `std::env::current_exe()` as "our binary" and asks `path_shadow` whether
/// a bare `symforge` on `$PATH` would run a different install. Returns `None`
/// when we win, when there is no shadow, or when `current_exe()` is unresolvable.
fn current_exe_shadow_report() -> Option<crate::path_shadow::ShadowReport> {
    let our_binary = std::env::current_exe().ok()?;
    let mut report = crate::path_shadow::detect_shadow(&our_binary)?;
    // `detect_shadow` probes our_version via a bounded `<binary> --version`
    // subprocess, which can flake/time out under load — that produced
    // "(version unknown)" on one health surface while another showed the real
    // version in the same session. We ARE the running binary, so source our
    // version from the compile-time package version instead of a subprocess.
    // (Leave the shadow's version probed, since that is genuinely a foreign
    // binary we cannot introspect statically.)
    report.our_version = Some(env!("CARGO_PKG_VERSION").to_string());
    Some(report)
}

/// Extract the `version=<token>` value emitted on the runtime-status line of a
/// `health` / `health_compact` report (see `format::format_runtime_status`).
///
/// The runtime line is ` | `-delimited, e.g.
/// `Runtime: mode=... | version=7.18.1 | project_root=...`, and round-2 guarantees
/// a `version=` token is present in EVERY mode (regression:
/// `test_runtime_status_includes_binary_version_in_every_mode`). Returns the raw
/// token (e.g. `"7.18.1"`) or `None` when no such token is present.
///
/// The `status` body (TR-01 proxy path) does NOT carry `version=`; it emits the
/// daemon binary version as `symforge_version: X` (status.rs). Accept that token
/// form too, so the staleness guard fires when `status` is proxied to a stale
/// daemon — not only when `health` is. Health is unaffected: its body always
/// carries `version=` (the regression above), so it takes the first branch.
fn extract_runtime_version(health_output: &str) -> Option<&str> {
    let after = health_output
        .split("version=")
        .nth(1)
        .or_else(|| health_output.split("symforge_version: ").nth(1))?;
    // The version token runs until the next field separator, whitespace, or EOL.
    let token = after
        .split(['|', ' ', '\n', '\r', '\t'])
        .next()
        .map(str::trim)
        .filter(|s| !s.is_empty())?;
    Some(token)
}

/// LOUD operations guard (SF-001 / SF-009 root-cause class): when the MCP
/// front-end is proxying to a daemon, the daemon's reported binary version can be
/// OLDER than the front-end's own build — a stale/shadowed daemon serving
/// pre-fix behavior, which is exactly what masked the SF-001 fix during the audit.
///
/// Compares the daemon version parsed out of the proxied health report against the
/// front-end's `frontend_version` (its `env!("CARGO_PKG_VERSION")`). Returns a
/// warning string ONLY when the daemon version is strictly OLDER than the
/// front-end. Fail-safe by construction: a missing/unparseable token or an
/// equal/newer daemon yields `None` (no warning).
///
/// Product decision: WARN, do NOT auto-restart. Auto-restarting risks killing a
/// daemon mid-session for other clients; a loud, idempotent health warning is the
/// safe, sufficient remedy and tells the operator to reconnect/restart.
fn daemon_staleness_warning(proxied_health: &str, frontend_version: &str) -> Option<String> {
    let daemon_version = extract_runtime_version(proxied_health)?;

    // `is_newer_version(latest, current)` is true iff `latest` > `current`. The
    // daemon is stale exactly when the front-end is newer than the daemon.
    if !crate::cli::version::is_newer_version(frontend_version, daemon_version) {
        return None;
    }

    Some(format!(
        "\n── \u{26a0} Daemon serving stale code ──\n\
         The MCP daemon answering this session reports version {daemon_version}, but this\n\
         front-end is version {frontend_version} (newer). The daemon is serving an OLDER\n\
         binary, so tool behavior may be stale (this is the operational root cause behind\n\
         masked fixes such as SF-001). Reconnect your MCP client (e.g. /mcp) or restart the\n\
         daemon so it picks up the newer binary; this is a WARNING only — no automatic\n\
         restart is performed."
    ))
}

/// Append `daemon_staleness_warning` to a proxied health report when the daemon is
/// older than the front-end; otherwise return the report unchanged.
fn append_daemon_staleness_warning(mut proxied_health: String, frontend_version: &str) -> String {
    if let Some(warning) = daemon_staleness_warning(&proxied_health, frontend_version) {
        proxied_health.push_str(&warning);
    }
    proxied_health
}

/// Overlay ALL of the proxy's OWN ledger/store-derived lines onto a `status`
/// body proxied from the daemon worker (D2-ROOT — proxy-owned state invisible to
/// worker-rendered responses).
///
/// In the daemon-backed stdio default, `status` is proxied to the daemon WORKER,
/// which owns the populated INDEX but has an EMPTY session ledger and NO durable
/// store wired — so its body renders `ledger_events: 0`, `last_ledger_*: none`,
/// `durable_ledger: unavailable`, and `calibration: deferred`. But the PROXY
/// owns `stel_ledger` + `stel_ledger_store` (attached in `main.rs`), and
/// economics events accumulate THERE. The operator's one observability window
/// must show the proxy's truth, not the worker's blind spot.
///
/// This rewrites every proxy-owned line/block with the proxy's own rendering
/// (`proxy`, built once from `self.stel_ledger` + `self.stel_ledger_store` via
/// [`SymForgeServer::proxy_owned_status_lines`], so the overlaid text is
/// byte-identical to what the worker WOULD render if it had the proxy's state):
/// - `ledger_events:` (present in compact AND full bodies),
/// - `last_ledger_decision:` / `last_ledger_route:` (full only),
/// - `durable_ledger:` (full only),
/// - the whole `── calibration (observational) ──` … `──` block (full only).
///
/// The INDEX lines (`index_ready`/`index_files`/`index_symbols`/`project`) stay
/// the WORKER's — it owns the warm index (TR-01) — and are NEVER overlaid.
///
/// Honesty: if the proxy's ledger is empty / its store is `Unavailable`/
/// `Disabled`, the overlaid values reflect THAT truthfully (`ledger_events: 0`,
/// `last_ledger_*: none`, `durable_ledger: unavailable`, `calibration: deferred`)
/// — the overlay makes status reflect the PROXY's real state, whatever it is,
/// not the worker's blind zero, and never invents accumulation.
///
/// Each rewrite is guarded on the line/block actually being present: a
/// `detail:compact` worker body (only `ledger_events:`, no full-only lines or
/// calibration section) or an older worker missing a line is a no-op for the
/// absent parts — exactly like the original single-line durable overlay.
fn overlay_proxy_status_lines(
    worker_body: String,
    proxy: &crate::stel::ProxyOwnedStatusLines,
) -> String {
    let trailing_newline = worker_body.ends_with('\n');
    let lines: Vec<&str> = worker_body.lines().collect();
    let mut out_lines: Vec<String> = Vec::with_capacity(lines.len());

    let mut i = 0;
    while i < lines.len() {
        let line = lines[i];
        if line.starts_with("ledger_events:") {
            // Present in BOTH compact and full bodies — proxy's session length.
            out_lines.push(proxy.ledger_events.clone());
        } else if line.starts_with("last_ledger_decision:") {
            out_lines.push(proxy.last_ledger_decision.clone());
        } else if line.starts_with("last_ledger_route:") {
            out_lines.push(proxy.last_ledger_route.clone());
        } else if line.starts_with("durable_ledger:") {
            out_lines.push(proxy.durable_ledger.clone());
        } else if line == "── calibration (observational) ──" {
            // Replace the WHOLE worker calibration block (header through its
            // closing `──`) with the proxy's rendering, then skip past it. The
            // block is the proxy-rendered section verbatim, so its line count may
            // differ — we consume the worker block by structure, not by count.
            for replacement_line in proxy.calibration_section.lines() {
                out_lines.push(replacement_line.to_string());
            }
            // Advance the worker cursor past its calibration header...
            i += 1;
            // ...and past its body up to and including the section's closing
            // `──` banner (the first standalone `──` after the header).
            while i < lines.len() && lines[i] != "──" {
                i += 1;
            }
            if i < lines.len() {
                // Skip the closing `──` (already included by the replacement).
                i += 1;
            }
            continue;
        } else {
            // Everything else — the static labels and the WORKER-owned index/
            // project lines — is preserved verbatim.
            out_lines.push(line.to_string());
        }
        i += 1;
    }

    let mut out = out_lines.join("\n");
    // Preserve a trailing newline if the original body had one (joining lines
    // drops it), so the overlay is byte-faithful apart from the swapped lines.
    if trailing_newline {
        out.push('\n');
    }
    out
}

fn symbol_candidate_paths(index: &crate::live_index::store::LiveIndex, name: &str) -> Vec<String> {
    let mut candidates: Vec<String> = index
        .all_files()
        .filter_map(|(path, file)| {
            if file.symbols.iter().any(|s| s.name == name) {
                Some(path.to_string())
            } else {
                None
            }
        })
        .collect();
    candidates.sort();
    candidates.dedup();
    candidates
}

fn format_ambiguous_symbol_context(name: &str, candidates: &[String]) -> String {
    let mut output = format!(
        "Ambiguous symbol selector: {} symbols named \"{}\" found.\nPass `path` or `file` to disambiguate.\nCandidate paths:",
        candidates.len(),
        name
    );
    for path in candidates {
        output.push_str(&format!("\n- {path}"));
    }
    output
}

fn render_symbol_context_header(
    file: &IndexedFile,
    name: &str,
    symbol_kind: Option<&str>,
    symbol_line: Option<u32>,
    verbosity: &str,
    max_tokens: Option<u64>,
) -> Option<String> {
    use crate::live_index::query::{SymbolSelectorMatch, resolve_symbol_selector};

    match resolve_symbol_selector(file, name, symbol_kind, symbol_line) {
        SymbolSelectorMatch::Selected(_, sym) => {
            let body = std::str::from_utf8(
                &file.content[sym.byte_range.0 as usize..sym.byte_range.1 as usize],
            )
            .ok()?;
            let (rendered, actual_level) = format::resolve_verbosity(
                body,
                Some(verbosity),
                max_tokens,
                0.7, // standalone symbol — allocate 70% of budget to body
            );
            let mut output = format!(
                "{}\n[{}, {}:{}-{}]",
                rendered,
                sym.kind,
                file.relative_path,
                sym.line_range.0 + 1,
                sym.line_range.1 + 1
            );
            if actual_level != "full" && actual_level != verbosity {
                output.push_str(&format!(
                    "\n[adaptive verbosity: {} — fits within {} token budget]",
                    actual_level,
                    max_tokens.unwrap_or(0)
                ));
            }
            Some(output)
        }
        SymbolSelectorMatch::NotFound | SymbolSelectorMatch::Ambiguous(_) => None,
    }
}

enum CapturedGetSymbolsEntry {
    SymbolLookup {
        file: Arc<IndexedFile>,
        name: String,
        kind: Option<String>,
        symbol_line: Option<u32>,
    },
    CodeSlice {
        file: Arc<IndexedFile>,
        start_byte: usize,
        end_byte: Option<usize>,
    },
    FileNotFound {
        path: String,
    },
}

// ─── Tool handlers ───────────────────────────────────────────────────────────

/// Loading guard helper — returns `Some(message)` when index is NOT ready.
///
/// Call at the top of every handler except `health`. If `Some` is returned,
/// return that string immediately. Otherwise continue with the handler body.
macro_rules! loading_guard {
    ($guard:expr) => {
        match $guard.index_state() {
            IndexState::Ready => {}
            IndexState::Empty => return format::empty_guard_message(),
            IndexState::Loading => return format::loading_guard_message(),
            IndexState::CircuitBreakerTripped { summary } => {
                return format!("Index degraded: {summary}");
            }
        }
    };
}

fn loading_guard_message_from_published(
    published: &crate::live_index::PublishedIndexState,
) -> Option<String> {
    match published.status {
        crate::live_index::PublishedIndexStatus::Ready => None,
        crate::live_index::PublishedIndexStatus::Empty => Some(format::empty_guard_message()),
        crate::live_index::PublishedIndexStatus::Loading => Some(format::loading_guard_message()),
        crate::live_index::PublishedIndexStatus::Degraded => Some(format!(
            "Index degraded: {}",
            published
                .degraded_summary
                .as_deref()
                .unwrap_or("circuit breaker tripped")
        )),
    }
}

/// Outcome of a name-only `get_symbol` lookup (Wave 1 Fix 2).
enum SymbolNameLookup {
    /// Exactly one exact-name match — its path is used as if the caller passed it.
    Unique { path: String },
    /// More than one exact-name match — a ready-to-return disambiguation listing.
    Ambiguous(String),
    /// No exact-name match — a ready-to-return loud not-found (D18 style).
    NotFound(String),
}

/// Render the disambiguation listing for a name-only `get_symbol` hit that
/// matched multiple symbols. Shows path + start line + kind per candidate,
/// capped at 20 with a count disclosure, and names how to disambiguate.
fn render_symbol_name_ambiguity(
    name: &str,
    hits: &[crate::live_index::search::SymbolSearchHit],
    overflowed: bool,
) -> String {
    const MAX_CANDIDATES: usize = 20;
    // Under the 500-hit search cap the exact count can under-report; when the
    // search overflowed, disclose the total as a lower bound (Wave 1 Fix 4).
    let total = if overflowed {
        format!("more than {}", hits.len())
    } else {
        hits.len().to_string()
    };
    let mut output = format!(
        "Ambiguous symbol selector: {total} symbols named \"{name}\" found across the index.\n\
         Pass `path` (and `symbol_line` if a file has several) to disambiguate.\n\
         Candidates:",
    );
    for hit in hits.iter().take(MAX_CANDIDATES) {
        output.push_str(&format!(
            "\n- {} (line {}, {})",
            hit.path, hit.line, hit.kind
        ));
    }
    if hits.len() > MAX_CANDIDATES {
        output.push_str(&format!(
            "\n... and {} more (use search_symbols to list them all)",
            hits.len() - MAX_CANDIDATES
        ));
    }
    output
}

#[tool_router(router = core_tool_router, vis = "pub(crate)")]
impl SymForgeServer {
    /// Resolve a bare symbol `name` (no path) to a file path by an EXACT
    /// name search across the index, honoring the `kind` filter and the
    /// `symbol_line` disambiguator (Wave 1 Fix 2). Reuses the same search
    /// machinery `search_symbols` uses so name resolution is consistent with it.
    fn resolve_symbol_path_by_name(
        &self,
        name: &str,
        kind: Option<&str>,
        symbol_line: Option<u32>,
    ) -> SymbolNameLookup {
        use crate::live_index::search::{
            ResultLimit, SymbolMatchTier, SymbolSearchOptions, search_symbols_with_options,
        };
        let guard = self.index.read();
        // Permissive noise policy (the default) so a symbol defined only in a
        // test/vendor/generated file is still resolvable by exact name — an
        // explicit path already reaches those files. A generous limit keeps the
        // ambiguity count honest without changing the O(symbols) scan cost.
        let options = SymbolSearchOptions {
            result_limit: ResultLimit::new(500),
            ..Default::default()
        };
        let result = search_symbols_with_options(&guard, name, kind, &options);
        // Under the 500-hit search cap, `overflow_count > 0` means more matches
        // exist than were returned, so the ambiguity total must be a lower bound,
        // never an exact under-report (Wave 1 Fix 4).
        let overflowed = result.overflow_count > 0;
        // Exact tier + exact (case-sensitive) name only — a name selector must
        // not silently resolve to a prefix/substring neighbor.
        let mut exact: Vec<crate::live_index::search::SymbolSearchHit> = result
            .hits
            .into_iter()
            .filter(|hit| hit.tier == SymbolMatchTier::Exact && hit.name == name)
            .collect();
        // `symbol_line` narrows to matches at that 1-based start line when it
        // resolves at least one candidate (e.g. two files, one line each).
        if let Some(line) = symbol_line {
            let narrowed: Vec<_> = exact
                .iter()
                .filter(|hit| hit.line == line)
                .cloned()
                .collect();
            if !narrowed.is_empty() {
                exact = narrowed;
            }
        }
        match exact.len() {
            0 => {
                // Kind-mismatch guard (Wave 1 Fix 1): before claiming the name is
                // absent, re-check WITHOUT the kind filter. If it exists under other
                // kinds, "No symbol named X" is factually false — name the kinds it
                // DOES have so the caller can drop or correct the filter.
                if let Some(requested_kind) = kind {
                    let unfiltered = search_symbols_with_options(&guard, name, None, &options);
                    let mut kinds: Vec<String> = unfiltered
                        .hits
                        .into_iter()
                        .filter(|hit| hit.tier == SymbolMatchTier::Exact && hit.name == name)
                        .map(|hit| hit.kind)
                        .collect();
                    kinds.sort();
                    kinds.dedup();
                    if !kinds.is_empty() {
                        return SymbolNameLookup::NotFound(format!(
                            "`{name}` exists in the index, but not as kind={requested_kind} \
                             (found: {}). Drop the kind filter or pass the correct kind.",
                            kinds.join(", ")
                        ));
                    }
                }
                SymbolNameLookup::NotFound(format!(
                    "No symbol named `{name}` in the index. \
                     Use search_symbols(query=\"{name}\") for a fuzzy lookup, \
                     or pass an explicit `path` if the file is not indexed."
                ))
            }
            1 => SymbolNameLookup::Unique {
                path: exact.remove(0).path,
            },
            _ => {
                SymbolNameLookup::Ambiguous(render_symbol_name_ambiguity(name, &exact, overflowed))
            }
        }
    }

    /// Look up symbol(s) by file path and name. Single mode: provide path + name for one symbol.
    /// Batch mode: provide targets[] array for multiple symbols or code slices in one call.
    /// When multiple symbols share the same name (e.g. `handle` in different impl blocks),
    /// pass symbol_line (1-based) to disambiguate; omitting it auto-selects by kind tier or
    /// returns an Ambiguous error listing candidate lines.
    /// NOT for finding symbols by name (use search_symbols first).
    /// NOT for understanding who calls it (use find_references or get_symbol_context).
    /// NOT for edit preparation (use get_symbol_context with bundle=true).
    #[tool(
        name = "get_symbol",
        description = "Prefer this over reading an entire file when you already know the symbol or have narrowed to one file. Retrieves the complete source code of a specific symbol with doc comments. Single mode: provide path + name. Batch mode: provide targets[] array for 2+ symbols or code slices in one call (each target is file path + symbol name or byte range). When multiple symbols share the same name, pass symbol_line (1-based) to disambiguate; auto-selects by kind tier when possible. Use search_symbols first if you only know part of the name. NOT for understanding callers (use find_references or get_symbol_context). NOT for edit preparation (use get_symbol_context with bundle=true).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn get_symbol_tool(
        &self,
        params: Parameters<GetSymbolInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.get_symbol(params).await;
        let outcome_class = classify_get_symbol_output(&output);
        self.record_tool_completion("get_symbol", &output, started.elapsed(), outcome_class);
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn get_symbol(&self, params: Parameters<GetSymbolInput>) -> String {
        if let Some(result) = self.proxy_tool_call("get_symbol", &params.0).await {
            return result;
        }

        // Batch mode: targets[] provided
        if let Some(ref targets) = params.0.targets {
            if targets.is_empty() {
                return "Error: targets array is empty.".to_string();
            }
            let captured = {
                let guard = self.index.read();
                loading_guard!(guard);

                targets
                    .iter()
                    .map(|target| match target.name.as_deref() {
                        Some(name) => match guard.capture_shared_file(&target.path) {
                            Some(file) => CapturedGetSymbolsEntry::SymbolLookup {
                                file,
                                name: name.to_string(),
                                kind: target.kind.clone(),
                                symbol_line: target.symbol_line,
                            },
                            None => CapturedGetSymbolsEntry::FileNotFound {
                                path: target.path.clone(),
                            },
                        },
                        None => match guard.capture_shared_file(&target.path) {
                            None => CapturedGetSymbolsEntry::FileNotFound {
                                path: target.path.clone(),
                            },
                            Some(file) => CapturedGetSymbolsEntry::CodeSlice {
                                file,
                                start_byte: target.start_byte.unwrap_or(0) as usize,
                                end_byte: target.end_byte.map(|e| e as usize),
                            },
                        },
                    })
                    .collect::<Vec<_>>()
            };

            // Frecency bump — batch commitment path. Collect the file path
            // for every resolved entry (skip FileNotFound since we did not
            // actually touch them), dedup, and emit one bump call at the end
            // per Implementation Notes §"Bump dedup per tool invocation".
            // Collection policy is resolved inside bump_frecency.
            let bump_paths: Vec<PathBuf> = captured
                .iter()
                .filter_map(|entry| match entry {
                    CapturedGetSymbolsEntry::SymbolLookup { file, .. }
                    | CapturedGetSymbolsEntry::CodeSlice { file, .. } => {
                        Some(PathBuf::from(&file.relative_path))
                    }
                    CapturedGetSymbolsEntry::FileNotFound { .. } => None,
                })
                .collect::<std::collections::HashSet<_>>()
                .into_iter()
                .collect();
            let has_symbol_lookup = captured
                .iter()
                .any(|entry| matches!(entry, CapturedGetSymbolsEntry::SymbolLookup { .. }));
            let batch_baseline_chars: usize = captured
                .iter()
                .filter_map(|entry| match entry {
                    CapturedGetSymbolsEntry::SymbolLookup { file, .. }
                    | CapturedGetSymbolsEntry::CodeSlice { file, .. } => Some(
                        format::competent_manual_baseline_chars(file.as_ref().content.len()),
                    ),
                    CapturedGetSymbolsEntry::FileNotFound { .. } => None,
                })
                .sum();
            let mut output = captured
                .into_iter()
                .map(|entry| match entry {
                    CapturedGetSymbolsEntry::SymbolLookup {
                        file,
                        name,
                        kind,
                        symbol_line,
                    } => format::symbol_detail_from_indexed_file(
                        file.as_ref(),
                        &name,
                        kind.as_deref(),
                        symbol_line,
                    ),
                    CapturedGetSymbolsEntry::CodeSlice {
                        file,
                        start_byte,
                        end_byte,
                    } => format::code_slice_from_indexed_file(file.as_ref(), start_byte, end_byte),
                    CapturedGetSymbolsEntry::FileNotFound { path } => format::not_found_file(&path),
                })
                .collect::<Vec<_>>()
                .join("\n---\n");
            // Append the next-step hint ONCE for the whole batch — an agent
            // learns it after the first occurrence, so repeating it per entry is
            // pure token overhead.
            if has_symbol_lookup {
                output.push_str(&format::compact_next_step_hint(&[
                    "get_symbol_context (callers/callees/types)",
                    "find_references (usages)",
                    "edit_within_symbol / replace_symbol_body (edits)",
                ]));
            }
            self.record_tool_savings_named(
                "get_symbol",
                format::estimate_tokens_from_chars(batch_baseline_chars),
                (output.len() / 4) as u64,
            );
            self.bump_frecency(&bump_paths);
            return output;
        }

        // Single mode: path + name
        let mut params = params;

        // Name-only lookup (Wave 1 Fix 2): `path` is OPTIONAL. When the caller
        // supplies a `name` but no `path`, resolve the path by an EXACT name
        // search across the index (the same machinery `search_symbols` uses),
        // honoring `kind` and the `symbol_line` disambiguator. This also powers
        // the compact `read` intent, which routes here via the STEL planner —
        // one fix, two surfaces. Both empty (and no `targets`) is a clean
        // invalid-request, never `File not found: .`.
        if params.0.path.trim().is_empty() {
            if params.0.name.trim().is_empty() {
                return "Invalid request: get_symbol needs a `name` (optionally with `path`), \
                        or a `targets` array. Add `path`/`symbol_line` to disambiguate a common \
                        name, or use search_symbols for a fuzzy lookup."
                    .to_string();
            }
            match self.resolve_symbol_path_by_name(
                params.0.name.trim(),
                params.0.kind.as_deref(),
                params.0.symbol_line,
            ) {
                SymbolNameLookup::Unique { path } => params.0.path = path,
                SymbolNameLookup::Ambiguous(message) | SymbolNameLookup::NotFound(message) => {
                    return message;
                }
            }
        }

        let force_refresh = params.0.force_refresh == Some(true);
        let params_hash = crate::protocol::session::hash_symbol_params(
            params.0.kind.as_deref(),
            params.0.symbol_line,
            params.0.max_tokens,
        );
        if let Some(meta) = self.session_context.try_symbol_cache_hit(
            &params.0.path,
            &params.0.name,
            params_hash,
            force_refresh,
        ) {
            return self.format_read_cache_hit(&meta, "session_repeat_read");
        }

        let file = {
            // The single-project overlay READ was REMOVED: it was redundant (the
            // shared live index already holds the edit via reindex_after_write) and
            // carried a narrow staleness shadow risk (overlay-first with no freshness
            // gate could shadow a base advanced by a watcher event). The base read is
            // always at-least-as-fresh. See
            // docs/reviews/overlay-redundancy-decision.md.
            let guard = self.index.read();
            loading_guard!(guard);
            guard.capture_shared_file(&params.0.path)
        };

        // Honest Tier-2/Tier-3 response before any miss handling: a path like
        // package-lock.json EXISTS but is admitted metadata-only, so it has no
        // symbols to return. Name the tier and point at get_file_content for raw
        // reads instead of "File not found". Only runs when the file is not in
        // the index (Tier-1 files resolve above).
        if file.is_none() {
            let repo_root = self.capture_repo_root();
            let degraded = {
                let guard = self.index.read();
                loading_guard!(guard);
                admission_tier_file_degradation_for_path(
                    &guard,
                    repo_root.as_deref(),
                    &params.0.path,
                )
            };
            if let Some(result) = degraded {
                return result;
            }
        }

        // Estimate mode: return token cost without full content
        if params.0.estimate == Some(true) {
            if let Some(ref file) = file {
                let file_tokens = file.content.len() / 4;
                let sym_tokens = file
                    .symbols
                    .iter()
                    .find(|s| s.name == params.0.name)
                    .map(|s| (s.byte_range.1 - s.byte_range.0) as usize / 4)
                    .unwrap_or(0);
                return format!(
                    "Estimate for get_symbol(path=\"{}\", name=\"{}\"):\n  Symbol body: ~{} tokens\n  Raw file: ~{} tokens",
                    params.0.path, params.0.name, sym_tokens, file_tokens
                );
            } else {
                return format::not_found_file(&params.0.path);
            }
        }

        match file {
            Some(file) => {
                let raw_chars = file.content.len();
                let line_count = format::indexed_file_line_count(&file.content);
                let is_small_file = format::is_small_indexed_file(raw_chars, line_count);
                let body = format::symbol_detail_from_indexed_file(
                    file.as_ref(),
                    &params.0.name,
                    params.0.kind.as_deref(),
                    params.0.symbol_line,
                );
                let hint = if is_small_file {
                    String::new()
                } else {
                    format::compact_next_step_hint(&[
                        "get_symbol_context (callers/callees/types)",
                        "find_references (usages)",
                        "edit_within_symbol / replace_symbol_body (edits)",
                    ])
                    .to_string()
                };
                let output = format!("{body}{hint}");
                let max_tokens = format::resolve_read_max_tokens(params.0.max_tokens, raw_chars);
                self.record_tool_savings_named(
                    "get_symbol",
                    format::estimate_tokens_from_chars(format::competent_manual_baseline_chars(
                        raw_chars,
                    )),
                    (output.len() / 4) as u64,
                );
                let tokens = (output.len() / 4) as u32;
                let prior_dedup = if force_refresh {
                    self.session_context.prior_fetch_for_dedup(
                        crate::protocol::session::FetchKind::Symbol,
                        &params.0.path,
                        &params.0.name,
                        params_hash,
                    )
                } else {
                    None
                };
                self.session_context.record_symbol_fetch(
                    &params.0.path,
                    &params.0.name,
                    params_hash,
                    tokens,
                );
                // Frecency bump — commitment tool, single-symbol happy path.
                // Collection policy is resolved inside bump_frecency. See wiki
                // `[[SymForge Frecency-Weighted File Ranking]]` §"Bump hooks".
                self.bump_frecency(&[PathBuf::from(&params.0.path)]);
                let mut final_output = format::enforce_token_budget(output, Some(max_tokens));
                if force_refresh && let Some(prior) = prior_dedup {
                    final_output = format::append_dedup_hint_footer(
                        final_output,
                        "symbol",
                        prior.fetched_at.elapsed().as_secs(),
                        prior.approx_tokens,
                    );
                }
                final_output
            }
            None => {
                let suggestions = {
                    let guard = self.index.read();
                    suggest_similar_files(&guard, &params.0.path)
                };
                format::not_found_file_with_suggestions(&params.0.path, &suggestions)
            }
        }
    }

    /// Start here. Project overview with adjustable detail level. Modes: (1) default/compact: ~500 token
    /// overview with file count, languages, and directory tree. (2) detail='full': complete symbol outline
    /// of every file — warning: large output. (3) detail='tree': browsable file tree with per-file symbol
    /// counts and language tags — supports path and depth params for subtree browsing.
    /// NOT for file details (use get_file_context) or finding symbols (use search_symbols).
    #[tool(
        description = "Start here for project orientation and the first code-reading pass before any broad raw file read. Returns a structural overview of the repository. Modes: (1) default/compact: ~500 token overview with file count, languages, and directory tree. (2) detail='full': complete symbol outline of every file — warning: large output; may CCR-compress with symforge_retrieve hash when over max_tokens. (3) detail='tree': browsable file tree with per-file symbol counts and language tags — supports path and depth params for subtree browsing. NOT for file details (use get_file_context) or finding symbols (use search_symbols).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn get_repo_map(&self, params: Parameters<GetRepoMapInput>) -> String {
        if let Some(result) = self.proxy_tool_call("get_repo_map", &params.0).await {
            return result;
        }
        // Single loading guard covering EVERY local path (estimate, compact, and
        // the `full`/`tree` outline branches), consistent with how
        // `search_symbols`/`search_text` guard at the top. Without this, an
        // outline-only call on an empty/unloaded index could fall through to a
        // bare empty map instead of the "index still loading / run index_folder"
        // guidance. The per-branch guards below remain as harmless redundancy.
        {
            let guard = self.index.read();
            loading_guard!(guard);
        }
        if params.0.estimate == Some(true) {
            let guard = self.index.read();
            loading_guard!(guard);
            let file_count = guard.file_count();
            drop(guard);
            let detail = params.0.detail.as_deref().unwrap_or("compact");
            let est = match detail {
                "full" => {
                    let max = params.0.max_files.unwrap_or(200) as usize;
                    max.min(file_count) * 30
                }
                "tree" => file_count * 10,
                _ => 500,
            };
            return format!(
                "Estimate for get_repo_map: ~{} tokens (detail={}, files={})",
                est, detail, file_count
            );
        }
        let detail = if let Some(ref d) = params.0.detail {
            d.as_str()
        } else if let Some(max_tokens) = params.0.max_tokens {
            // Adaptive detail: auto-select "full" when the estimated output fits
            // within the token budget, otherwise fall back to "compact".
            let guard = self.index.read();
            let file_count = guard.file_count();
            drop(guard);
            let max_files = params.0.max_files.unwrap_or(200) as usize;
            let full_estimate = max_files.min(file_count) * 30;
            if (full_estimate as u64) <= max_tokens {
                "full"
            } else {
                "compact"
            }
        } else {
            "compact"
        };
        let output = match detail {
            "full" => {
                let published = self.index.published_state();
                if let Some(message) = loading_guard_message_from_published(&published) {
                    return message;
                }
                let view = self.index.published_repo_outline();
                if let Some(ref path) = params.0.path {
                    // Filter outline to files under the given path prefix
                    let filtered_files: Vec<_> = view
                        .files
                        .iter()
                        .filter(|fo| fo.relative_path.starts_with(path.as_str()))
                        .cloned()
                        .collect();
                    let filtered_symbols: usize =
                        filtered_files.iter().map(|f| f.symbol_count).sum();
                    let filtered_view = crate::live_index::query::RepoOutlineView {
                        total_files: filtered_files.len(),
                        total_symbols: filtered_symbols,
                        files: filtered_files,
                    };
                    let max_files = params.0.max_files.unwrap_or(200) as usize;
                    if filtered_view.files.len() > max_files {
                        let remaining = filtered_view.files.len() - max_files;
                        let truncated_files: Vec<_> = filtered_view
                            .files
                            .iter()
                            .take(max_files)
                            .cloned()
                            .collect();
                        let truncated_view = crate::live_index::query::RepoOutlineView {
                            total_files: filtered_view.total_files,
                            total_symbols: filtered_view.total_symbols,
                            files: truncated_files,
                        };
                        let mut output =
                            format::repo_outline_view(&truncated_view, &self.project_name);
                        output.push_str(&format!(
                            "\n\n... and {} more files (increase max_files= to see more)",
                            remaining
                        ));
                        output
                    } else {
                        format::repo_outline_view(&filtered_view, &self.project_name)
                    }
                } else {
                    let max_files = params.0.max_files.unwrap_or(200) as usize;
                    if view.files.len() > max_files {
                        let truncated_files: Vec<_> =
                            view.files.iter().take(max_files).cloned().collect();
                        let remaining = view.files.len() - max_files;
                        let truncated_view = crate::live_index::query::RepoOutlineView {
                            total_files: view.total_files,
                            total_symbols: view.total_symbols,
                            files: truncated_files,
                        };
                        let mut output =
                            format::repo_outline_view(&truncated_view, &self.project_name);
                        output.push_str(&format!(
                            "\n\n... and {} more files (use path= to scope or increase max_files=)",
                            remaining
                        ));
                        output
                    } else {
                        format::repo_outline_view(&view, &self.project_name)
                    }
                }
            }
            "tree" => {
                let published = self.index.published_state();
                if let Some(message) = loading_guard_message_from_published(&published) {
                    return message;
                }
                let path = params.0.path.as_deref().unwrap_or("");
                let depth = params.0.depth.unwrap_or(2).min(5);
                let view = self.index.published_repo_outline();
                let guard = self.index.read();
                let skipped = guard.skipped_files().to_vec();
                drop(guard);
                format::file_tree_view_with_skipped(&view.files, &skipped, path, depth)
            }
            _ => {
                let guard = self.index.read();
                loading_guard!(guard);
                drop(guard);

                let state = sidecar_state_for_server(self);
                match repo_map_text(&state) {
                    Ok(result) => {
                        let hint = format::compact_next_step_hint(&[
                            "get_file_context (open one file)",
                            "search_symbols (find by name)",
                            "search_text (find text/patterns)",
                            "diff_symbols (review changes)",
                        ]);
                        let doctrine = "\nDoctrine: the map orients; the tools prove. \
                             Completeness: ranked and truncated by result cap - absence \
                             from the map is not absence from the repo; confirm with \
                             search_symbols / search_text before concluding something is missing.";
                        format!("{result}{hint}{doctrine}")
                    }
                    Err(StatusCode::NOT_FOUND) => "Repository map unavailable.".to_string(),
                    Err(StatusCode::INTERNAL_SERVER_ERROR) => {
                        "Repository map failed: internal error.".to_string()
                    }
                    Err(other) => format!("Repository map failed: HTTP {}", other.as_u16()),
                }
            }
        };
        self.session_context.record_summary_output(
            "get_repo_map",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        if detail == "full" {
            self.apply_ccr_budget("get_repo_map", output, params.0.max_tokens)
        } else {
            format::enforce_token_budget(output, params.0.max_tokens)
        }
    }

    /// Rich file summary: symbol outline, imports, consumers, references, and git activity.
    /// Use sections=['outline'] for a compact symbol outline only.
    /// Use sections=['outline','imports'] to limit output. Best tool for understanding a file before editing.
    /// Much smaller than reading the raw file.
    /// NOT for reading actual source code (use get_file_content or get_symbol).
    #[tool(
        description = "Prefer this over raw file reads for code understanding — it usually saves 70-95% of tokens by returning the file's symbol outline and structure first. Rich file summary: symbol outline, imports, consumers, references, and git activity. Use sections=['outline'] for a fast first pass, or sections=['outline','imports'] to stay compact. Best tool for understanding a file before editing or before deciding whether you need exact raw text. NOT for reading actual source code (use get_file_content or get_symbol).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn get_file_context(&self, params: Parameters<GetFileContextInput>) -> String {
        if let Some(result) = self.proxy_tool_call("get_file_context", &params.0).await {
            return result;
        }
        let force_refresh = params.0.force_refresh == Some(true);
        let params_hash = crate::protocol::session::hash_file_context_params(
            params.0.max_tokens,
            params.0.sections.as_deref(),
        );
        if let Some(meta) = self.session_context.try_file_context_cache_hit(
            &params.0.path,
            params_hash,
            force_refresh,
        ) {
            return self.format_read_cache_hit(&meta, "session_repeat_read");
        }
        // Honest Tier-2/Tier-3 response: the path may EXIST on disk but be
        // deliberately admitted as metadata-only (e.g. package-lock.json) or
        // hard-skipped. Return an actionable "not indexed" message pointing at
        // get_file_content for raw reads, instead of a misleading
        // "File not found". Resolution reuses the index lookup + repo-root-bound
        // disk fallback shared with the symbol-level degradation path.
        {
            let repo_root = self.capture_repo_root();
            let degraded = {
                let guard = self.index.read();
                loading_guard!(guard);
                admission_tier_file_degradation_for_path(
                    &guard,
                    repo_root.as_deref(),
                    &params.0.path,
                )
            };
            if let Some(result) = degraded {
                return result;
            }
        }
        if params.0.estimate == Some(true) {
            let guard = self.index.read();
            loading_guard!(guard);
            if let Some(file) = guard.capture_shared_file(&params.0.path) {
                let file_tokens = file.content.len() / 4;
                let outline_tokens = file.content.len() / 50; // ~5-10% of raw
                return format!(
                    "Estimate for get_file_context(path=\"{}\"):\n  Outline: ~{} tokens\n  Raw file: ~{} tokens\n  Savings: ~{}%",
                    params.0.path,
                    outline_tokens,
                    file_tokens,
                    (outline_tokens * 100)
                        .checked_div(file_tokens)
                        .map(|pct| 100usize.saturating_sub(pct))
                        .unwrap_or(0)
                );
            } else {
                return format::not_found_file(&params.0.path);
            }
        }
        const LARGE_FILE_CONTEXT_DEFAULT_TOKENS: u64 = 1000;
        let (raw_chars, line_count, symbol_count, reference_count) = {
            let guard = self.index.read();
            loading_guard!(guard);
            let stats = guard
                .capture_shared_file(&params.0.path)
                .map(|f| {
                    (
                        f.content.len(),
                        format::indexed_file_line_count(&f.content),
                        f.symbols.len(),
                        f.references.len(),
                    )
                })
                .unwrap_or((0, 0, 0, 0));
            drop(guard);
            stats
        };
        let is_small_file = format::is_small_indexed_file(raw_chars, line_count);
        let large_default_summary = !is_small_file
            && params.0.sections.is_none()
            && (raw_chars > 200_000 || symbol_count > 250 || reference_count > 800);

        let state = sidecar_state_for_server(self);
        let include_tests = include_tests_from_sections(params.0.sections.as_ref());
        let sections = if is_small_file {
            Some(vec!["outline".to_string()])
        } else if large_default_summary {
            Some(vec!["outline".to_string(), "imports".to_string()])
        } else {
            visible_sections(&params.0.sections)
        };
        let context_max_tokens = Some(format::resolve_read_max_tokens(
            params
                .0
                .max_tokens
                .or_else(|| large_default_summary.then_some(LARGE_FILE_CONTEXT_DEFAULT_TOKENS)),
            raw_chars,
        ));
        let outline = OutlineParams {
            path: params.0.path.clone(),
            max_tokens: context_max_tokens,
            sections: sections.clone(),
        };
        match outline_tool_text(&state, &outline) {
            Ok(result) => {
                let mut result =
                    format::collapse_large_test_modules(result, include_tests, sections.as_deref());
                if large_default_summary {
                    let note = format!(
                        "Large file summary: outline+imports only ({} symbols, {} references); omitted consumers/references/git; request sections=[\"consumers\"], sections=[\"references\"], sections=[\"git\"] or higher max_tokens.",
                        symbol_count, reference_count
                    );
                    result = if let Some((envelope, rest)) = result.split_once("\n\n") {
                        format!("{envelope}\n\n{note}\n\n{rest}")
                    } else {
                        format!("{note}\n\n{result}")
                    };
                }
                let hint = if is_small_file {
                    String::new()
                } else {
                    format::compact_next_step_hint(&[
                        "get_symbol (body)",
                        "find_references (callers/imports)",
                        "search_text (string/pattern usage)",
                        "get_file_content (exact raw text)",
                    ])
                };
                let body = format!("{result}{hint}");
                let footer = format::compact_savings_footer(body.len(), raw_chars);
                let mut output =
                    format::enforce_token_budget(format!("{body}{footer}"), context_max_tokens);
                let tokens = (output.len() / 4) as u32;
                let prior_dedup = if force_refresh {
                    self.session_context.prior_fetch_for_dedup(
                        crate::protocol::session::FetchKind::FileContext,
                        &params.0.path,
                        "",
                        params_hash,
                    )
                } else {
                    None
                };
                self.session_context
                    .record_file_context_fetch(&params.0.path, params_hash, tokens);
                self.session_context
                    .record_listed_file(&params.0.path, tokens);
                if let Some(prior) = prior_dedup {
                    output = format::append_dedup_hint_footer(
                        output,
                        "file context",
                        prior.fetched_at.elapsed().as_secs(),
                        prior.approx_tokens,
                    );
                }
                // Frecency bump — commitment tool. Reached only on the happy
                // path after a successful outline fetch; collection policy is
                // resolved inside bump_frecency. See wiki `[[SymForge Frecency-Weighted
                // File Ranking]]` §"Bump hooks".
                self.bump_frecency(&[PathBuf::from(&params.0.path)]);
                output
            }
            Err(StatusCode::NOT_FOUND) => format::not_found_file(&params.0.path),
            Err(StatusCode::INTERNAL_SERVER_ERROR) => {
                "File context failed: internal error.".to_string()
            }
            Err(other) => format!("File context failed: HTTP {}", other.as_u16()),
        }
    }

    /// Symbol usage analysis with three modes. (1) Default: definition + callers grouped by file + callees + type usages.
    /// (2) bundle=true: symbol body + full definitions of all referenced custom types, resolved recursively — best
    /// for edit preparation (requires path). (3) sections=[...]: comprehensive trace analysis — definition, callers,
    /// callees, implementations, type dependencies, git activity. Valid sections: 'dependents', 'siblings',
    /// 'implementations', 'git' (empty array = all). Set verbosity='signature' for ~80% smaller output.
    /// NOT for just the symbol body (use get_symbol).
    #[tool(
        name = "get_symbol_context",
        description = "Symbol usage analysis with three modes. (1) Default: definition + callers grouped by file + callees + type usages. (2) bundle=true: symbol body + full definitions of all referenced custom types, resolved recursively — best for edit preparation (requires path). (3) sections=[...]: comprehensive trace analysis — definition, callers, callees, implementations, type dependencies, git activity. Valid sections: 'dependents', 'siblings', 'implementations', 'git' (empty array = all). Set verbosity='signature' for ~80% smaller output. NOT for just the symbol body (use get_symbol).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn get_symbol_context_tool(
        &self,
        params: Parameters<GetSymbolContextInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.get_symbol_context(params).await;
        let outcome_class = classify_get_symbol_context_output(&output);
        self.record_tool_completion(
            "get_symbol_context",
            &output,
            started.elapsed(),
            outcome_class,
        );
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn get_symbol_context(
        &self,
        params: Parameters<GetSymbolContextInput>,
    ) -> String {
        if let Some(result) = self.proxy_tool_call("get_symbol_context", &params.0).await {
            return result;
        }
        if let Some(path) = params.0.path.as_deref().or(params.0.file.as_deref()) {
            let repo_root = self.capture_repo_root();
            let degraded = {
                let guard = self.index.read();
                loading_guard!(guard);
                admission_tier_degradation_for_path(
                    &guard,
                    repo_root.as_deref(),
                    "get_symbol_context",
                    path,
                    &params.0.name,
                )
            };
            if let Some(result) = degraded {
                return result;
            }
        }
        if params.0.estimate == Some(true) {
            let path = params.0.path.as_deref().unwrap_or("");
            let guard = self.index.read();
            loading_guard!(guard);
            if let Some(file) = guard.capture_shared_file(path) {
                let sym_tokens = file
                    .symbols
                    .iter()
                    .find(|s| s.name == params.0.name)
                    .map(|s| (s.byte_range.1 - s.byte_range.0) as usize / 4)
                    .unwrap_or(0);
                let ref_count = file
                    .references
                    .iter()
                    .filter(|r| r.name == params.0.name)
                    .count();
                let bundle_est = sym_tokens * 3; // rough: body + deps
                return format!(
                    "Estimate for get_symbol_context(name=\"{}\"):\n  Symbol body: ~{} tokens\n  Callers: ~{} tokens\n  Bundle: ~{} tokens",
                    params.0.name,
                    sym_tokens,
                    ref_count * 15 + 50,
                    bundle_est
                );
            } else {
                return format!("Symbol '{}' not found in '{}'", params.0.name, path);
            }
        }
        if params.0.bundle.unwrap_or(false) {
            let path = match params.0.path.as_deref() {
                Some(p) => p.to_string(),
                None => return "Error: bundle=true requires the 'path' parameter.".to_string(),
            };
            let refreshed =
                freshen_exact_path_for_targeted_retrieval(self, &search::PathScope::exact(&path));
            let (view, raw_chars, parse_state) = {
                let guard = self.index.read();
                loading_guard!(guard);
                let raw = guard
                    .capture_shared_file(&path)
                    .map(|f| f.content.len())
                    .unwrap_or(0);
                let parse_state = guard
                    .capture_shared_file(&path)
                    .map(|f| parse_state_for_file(f.as_ref()))
                    .unwrap_or("parsed");
                let v = guard.capture_context_bundle_view(
                    &path,
                    &params.0.name,
                    params.0.symbol_kind.as_deref(),
                    params.0.symbol_line,
                );
                (v, raw, parse_state)
            };
            let verbosity = params.0.verbosity.as_deref().unwrap_or("full");
            let result = format::context_bundle_result_view_with_max_tokens(
                &view,
                verbosity,
                params.0.max_tokens,
            );
            let result = if let crate::live_index::ContextBundleView::Found(found) = &view {
                let scope = match params.0.max_tokens {
                    Some(max_tokens) => format!(
                        "path `{}`; bundle mode; max_tokens={max_tokens}",
                        found.file_path
                    ),
                    None => format!("path `{}`; bundle mode", found.file_path),
                };
                let envelope = search_format::format_search_envelope(
                    if params.0.symbol_line.is_some() {
                        "exact"
                    } else {
                        "constrained"
                    },
                    context_source_authority_label(refreshed),
                    parse_state,
                    &context_bundle_completeness_label(found.as_ref(), &result),
                    &scope,
                    &format!(
                        "symbol anchor `{}:{}`",
                        found.file_path,
                        found.line_range.0.saturating_add(1)
                    ),
                );
                format!("{envelope}\n\n{result}")
            } else {
                result
            };
            let footer = format::compact_savings_footer(result.len(), raw_chars);
            self.record_read_savings(format::saved_tokens_vs_competent_manual(
                result.len(),
                raw_chars,
            ));
            let output = format!("{result}{footer}");
            self.session_context
                .record_symbol(&path, &params.0.name, (output.len() / 4) as u32);
            // Frecency bump — commitment tool, bundle-mode happy path.
            // Collection policy is resolved inside bump_frecency.
            self.bump_frecency(&[PathBuf::from(&path)]);
            return output;
        }

        // Trace mode: comprehensive symbol analysis (absorbed from trace_symbol)
        if params.0.sections.is_some() {
            let path = match params.0.path.as_deref() {
                Some(p) => p.to_string(),
                None => return "Error: sections requires the 'path' parameter.".to_string(),
            };

            // Convert sections: Some(empty vec) = all sections (like trace_symbol's None)
            let include_tests = include_tests_from_sections(params.0.sections.as_ref());
            let sections_param = visible_sections(&params.0.sections)
                .and_then(|s| if s.is_empty() { None } else { Some(s) });
            let sections_param = encode_include_tests_marker(sections_param, include_tests);

            let trace_input = TraceSymbolInput {
                path: path.clone(),
                name: params.0.name.clone(),
                kind: params.0.symbol_kind.clone(),
                symbol_line: params.0.symbol_line,
                sections: sections_param,
                verbosity: params.0.verbosity.clone(),
                max_tokens: params.0.max_tokens,
                estimate: None,
            };
            let trace_result = self.trace_symbol(Parameters(trace_input)).await;
            self.session_context.record_symbol(
                &path,
                &params.0.name,
                (trace_result.len() / 4) as u32,
            );
            // Frecency bump — commitment tool, trace-mode happy path.
            // Collection policy is resolved inside bump_frecency.
            self.bump_frecency(&[PathBuf::from(&path)]);
            return format::enforce_token_budget(trace_result, params.0.max_tokens);
        }

        // Default: symbol context mode
        if let Some(result) = self.proxy_tool_call("get_symbol_context", &params.0).await {
            return result;
        }
        let file_path_hint = params.0.path.as_deref().or(params.0.file.as_deref());
        // Auto-resolve path from index when not provided
        let resolved_path: Option<String>;
        let file_path_hint = if file_path_hint.is_some() {
            resolved_path = None;
            file_path_hint
        } else {
            let guard = self.index.read();
            let candidates = symbol_candidate_paths(&guard, &params.0.name);
            drop(guard);
            if candidates.len() == 1 {
                resolved_path = Some(candidates.into_iter().next().unwrap());
                resolved_path.as_deref()
            } else if candidates.len() > 1 {
                return format_ambiguous_symbol_context(&params.0.name, &candidates);
            } else {
                resolved_path = None;
                None
            }
        };
        let verbosity = params.0.verbosity.as_deref().unwrap_or("full");
        let max_tokens = params.0.max_tokens;

        // Capture the symbol definition from the index so we can prepend it
        // (the sidecar only returns reference locations, not the definition itself).
        let (symbol_header, impl_block_tip, callees_text, raw_chars) = {
            let guard = self.index.read();
            loading_guard!(guard);

            let file = file_path_hint.and_then(|p| guard.capture_shared_file(p));
            let raw = file.as_ref().map(|f| f.content.len()).unwrap_or(0);

            let header = file.and_then(|f| {
                render_symbol_context_header(
                    f.as_ref(),
                    &params.0.name,
                    params.0.symbol_kind.as_deref(),
                    params.0.symbol_line,
                    verbosity,
                    max_tokens,
                )
            });

            let (impl_block_tip, callees_text) = file_path_hint
                .map(|path| {
                    let view = guard.capture_context_bundle_view(
                        path,
                        &params.0.name,
                        params.0.symbol_kind.as_deref(),
                        params.0.symbol_line,
                    );
                    let tip = format::context_bundle_impl_suggestion_tip(&view);
                    let callees = format::context_bundle_callees_text(&view);
                    (tip, callees)
                })
                .unwrap_or_default();

            (header, impl_block_tip, callees_text, raw)
        };

        let state = sidecar_state_for_server(self);
        let symbol_context = SymbolContextParams {
            name: params.0.name.clone(),
            file: params.0.file.clone(),
            path: params.0.path.clone(),
            symbol_kind: params.0.symbol_kind.clone(),
            symbol_line: params.0.symbol_line,
        };
        match symbol_context_tool_text(&state, &symbol_context) {
            Ok(refs_text) => {
                let mut output = String::new();
                if let Some(header) = &symbol_header {
                    output.push_str(header);
                    output.push_str("\n\n");
                }
                output.push_str(&refs_text);
                if !callees_text.is_empty() {
                    output.push('\n');
                    output.push_str(&callees_text);
                }
                if !impl_block_tip.is_empty() {
                    output.push_str(impl_block_tip.trim_start_matches('\n'));
                }
                output.push_str(&format::compact_next_step_hint(&[
                    "get_symbol_context (callers/callees/types)",
                    "find_references (usages)",
                    "edit_within_symbol / replace_symbol_body (edits)",
                ]));
                let footer = format::compact_savings_footer(output.len(), raw_chars);
                // Frecency bump — commitment tool, default-mode happy path.
                // Resolve the bump path the same way the output did:
                // explicit params first, auto-resolved path as fallback.
                // Collection policy is resolved inside bump_frecency.
                if let Some(bump_path) = params
                    .0
                    .path
                    .as_deref()
                    .or(params.0.file.as_deref())
                    .map(PathBuf::from)
                    .or_else(|| resolved_path.as_deref().map(PathBuf::from))
                {
                    self.bump_frecency(&[bump_path]);
                }
                format::enforce_token_budget(format!("{output}{footer}"), max_tokens)
            }
            Err(_) => {
                // Sidecar unavailable — fall back to the index definition so callers
                // always get at least the symbol body instead of an opaque error.
                if let Some(header) = symbol_header {
                    let mut body = format!(
                        "{header}\n\n(Reference data unavailable — showing definition only)"
                    );
                    if !impl_block_tip.is_empty() {
                        body.push('\n');
                        body.push_str(impl_block_tip.trim_start_matches('\n'));
                    }
                    body.push_str(&format::compact_next_step_hint(&[
                        "get_symbol_context (callers/callees/types)",
                        "find_references (usages)",
                    ]));
                    let footer = format::compact_savings_footer(body.len(), raw_chars);
                    self.record_read_savings(format::saved_tokens_vs_competent_manual(
                        body.len(),
                        raw_chars,
                    ));
                    let output = format!("{body}{footer}");
                    if let Some(ref p) = resolved_path {
                        self.session_context.record_symbol(
                            p,
                            &params.0.name,
                            (output.len() / 4) as u32,
                        );
                    } else if let Some(ref p) = params.0.path {
                        self.session_context.record_symbol(
                            p,
                            &params.0.name,
                            (output.len() / 4) as u32,
                        );
                    }
                    // Frecency bump — commitment tool, fallback-definition
                    // branch (sidecar unavailable but we still returned a
                    // useful symbol body to the caller). Collection policy is
                    // resolved inside bump_frecency.
                    if let Some(bump_path) = params
                        .0
                        .path
                        .as_deref()
                        .or(params.0.file.as_deref())
                        .map(PathBuf::from)
                        .or_else(|| resolved_path.as_deref().map(PathBuf::from))
                    {
                        self.bump_frecency(&[bump_path]);
                    }
                    format::enforce_token_budget(output, max_tokens)
                } else {
                    format!("Symbol \"{}\" not found in index.", params.0.name)
                }
            }
        }
    }

    /// Call AFTER editing a file. Re-reads from disk, updates the index, reports added/removed/modified
    /// symbols and affected dependents. Set include_co_changes=true to also see git temporal coupling data
    /// (files that historically change together with this file). Always call this after making edits.
    #[tool(
        description = "Call AFTER editing a file. Re-reads from disk, updates the index, reports added/removed/modified symbols and affected dependents. Set include_co_changes=true to also see git temporal coupling data (files that historically change together). Always call this after making edits to keep the index current. NOT for listing changed files across the repo (use what_changed). NOT for a symbol-level diff between git refs (use diff_symbols).",
        annotations(
            read_only_hint = false,
            destructive_hint = false,
            idempotent_hint = true,
            open_world_hint = false
        )
    )]
    pub(crate) async fn analyze_file_impact(
        &self,
        params: Parameters<AnalyzeFileImpactInput>,
    ) -> String {
        if let Some(result) = self.proxy_tool_call("analyze_file_impact", &params.0).await {
            return result;
        }
        if params.0.estimate == Some(true) {
            let with_co = params.0.include_co_changes.unwrap_or(false);
            let co_limit = params.0.co_changes_limit.unwrap_or(10) as usize;
            let est = 200 + if with_co { co_limit * 13 } else { 0 };
            return format!(
                "Estimate for analyze_file_impact: ~{} tokens (include_co_changes={})",
                est, with_co
            );
        }
        {
            let guard = self.index.read();
            loading_guard!(guard);
        }

        let state = sidecar_state_for_server(self);
        let impact = ImpactParams {
            path: params.0.path.clone(),
            new_file: params.0.new_file,
        };
        let mut result = match impact_tool_text(state, &impact).await {
            Ok(result) => result,
            Err(StatusCode::NOT_FOUND) => {
                return format!("File not found on disk: {}", params.0.path);
            }
            Err(StatusCode::INTERNAL_SERVER_ERROR) => {
                return "Impact analysis failed: internal error.".to_string();
            }
            Err(other) => return format!("Impact analysis failed: HTTP {}", other.as_u16()),
        };

        // Append co-changes if requested
        if params.0.include_co_changes.unwrap_or(false) {
            let temporal = self.index.git_temporal();
            match temporal.state {
                crate::live_index::git_temporal::GitTemporalState::Ready => {
                    let limit = params.0.co_changes_limit.unwrap_or(10) as usize;
                    let path = params.0.path.as_str();
                    match temporal.files.get(path) {
                        Some(history) => {
                            result.push_str("\n\n");
                            result.push_str(&format::co_changes_result_view(path, history, limit));
                        }
                        None => {
                            result.push_str("\n\nNo git co-change data found for this file.");
                        }
                    }
                }
                crate::live_index::git_temporal::GitTemporalState::Pending
                | crate::live_index::git_temporal::GitTemporalState::Computing => {
                    result.push_str(
                        "\n\nGit temporal data is still loading. Co-changes unavailable.",
                    );
                }
                crate::live_index::git_temporal::GitTemporalState::Unavailable(ref reason) => {
                    result.push_str(&format!("\n\nGit temporal data unavailable: {reason}"));
                }
            }
        }

        self.session_context.record_summary_output(
            "analyze_file_impact",
            (result.len() / 4).min(u32::MAX as usize) as u32,
        );
        result
    }

    /// Find symbols by name substring across the project — returns name, kind, file, line range.
    /// Use when you know part of a symbol name but not the file. Supports kind filter, language filter,
    /// and path prefix scope. Query is optional: omit it to browse by kind or path_prefix (at least
    /// one of query, kind, or path_prefix is required).
    /// NOT for text content search (use search_text). NOT for file path search (use search_files).
    #[tool(
        name = "search_symbols",
        description = "Prefer this before grep when you are looking for a function, class, type, or other symbol by name. Finds symbols across the repository in milliseconds and returns name, kind, file, and line range. Use when you know part of a symbol name but not the file. Supports kind filter, language filter, and path prefix scope. Query is optional — omit it to browse all symbols matching kind/path_prefix (browse mode defaults to limit=20, sorted by path+line). At least one of query, kind, or path_prefix is required. Large result sets may CCR-compress; use symforge_retrieve with the footer hash for the full ranked list. NOT for text content search (use search_text). NOT for file path search (use search_files).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn search_symbols_tool(
        &self,
        params: Parameters<SearchSymbolsInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.search_symbols(params).await;
        let outcome_class = classify_search_symbols_output(&output);
        self.record_tool_completion("search_symbols", &output, started.elapsed(), outcome_class);
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn search_symbols(&self, params: Parameters<SearchSymbolsInput>) -> String {
        let query_str = params.0.query.as_deref().unwrap_or("").trim();
        let is_browse = query_str.is_empty();
        if is_browse && params.0.kind.is_none() && params.0.path_prefix.is_none() {
            return "search_symbols requires at least one of: query, kind, or path_prefix"
                .to_string();
        }
        if let Some(result) = self.proxy_tool_call("search_symbols", &params.0).await {
            return result;
        }
        // Feature 012 (Phase 3): no daemon here -> no working set. Honest refusal
        // for a cross-project request instead of a silent single-project answer.
        if let Some(refusal) =
            local_cross_project_refusal(params.0.project.as_deref(), params.0.projects.as_deref())
        {
            return refusal;
        }
        let options = match search_symbols_options_from_input(&params.0) {
            Ok(options) => options,
            Err(message) => return message,
        };
        let mut result = {
            let guard = self.index.read();
            loading_guard!(guard);
            search::search_symbols_with_options(
                &guard,
                query_str,
                params.0.kind.as_deref(),
                &options,
            )
        };
        let hidden_noise_count = {
            let guard = self.index.read();
            hidden_search_symbols_noise_count(
                &guard,
                query_str,
                params.0.kind.as_deref(),
                &options,
                &result,
            )
        };
        // In browse mode, sort by relevance: public symbols first, then kind priority,
        // then penalize very short/common names, then alphabetical tiebreaker.
        if is_browse {
            let scores: Vec<(bool, f32, bool)> = {
                let guard = self.index.read();
                result
                    .hits
                    .iter()
                    .map(|hit| {
                        let is_pub = guard
                            .get_file(&hit.path)
                            .map(|f| LiveIndex::has_pub_symbol(f, &hit.name))
                            .unwrap_or(false);
                        let kind_score = search::symbol_kind_priority(&hit.kind);
                        let is_short_common = hit.name.len() <= 3;
                        (is_pub, kind_score, is_short_common)
                    })
                    .collect()
            };
            let mut indices: Vec<usize> = (0..result.hits.len()).collect();
            indices.sort_by(|&i, &j| {
                scores[j]
                    .0
                    .cmp(&scores[i].0) // public first
                    .then(
                        scores[j]
                            .1
                            .partial_cmp(&scores[i].1) // higher kind priority first
                            .unwrap_or(std::cmp::Ordering::Equal),
                    )
                    .then(scores[i].2.cmp(&scores[j].2)) // non-short names first
                    .then(result.hits[i].name.cmp(&result.hits[j].name)) // alphabetical
            });
            result.hits = indices
                .into_iter()
                .map(|i| result.hits[i].clone())
                .collect();
        }
        let envelope = if result.hits.is_empty() {
            None
        } else {
            let guard = self.index.read();
            Some(search_format::format_search_envelope(
                search_symbols_match_type_label(&result, is_browse),
                "current index",
                search_parse_state_for_paths(
                    &guard,
                    result.hits.iter().map(|hit| hit.path.as_str()),
                ),
                &search_completeness_label(result.overflow_count, hidden_noise_count),
                &search_scope_summary(
                    &options.path_scope,
                    options.language_filter.as_ref(),
                    &options.noise_policy,
                    options.include_personal_tooling,
                    None,
                    None,
                    false,
                ),
                &search_symbols_evidence(&result),
            ))
        };
        let output = format::search_symbols_result_view(&result, query_str);
        let hint = format::compact_next_step_hint(&[
            "get_symbol (body)",
            "get_symbol_context (callers/callees)",
            "get_file_context (file overview)",
        ]);
        let output = match envelope {
            Some(envelope) => format!("{envelope}\n\n{output}{hint}"),
            None => format!("{output}{hint}"),
        };
        let output = if !is_browse
            && query_str.len() >= 2
            && result.hits.len() < options.result_limit.get() / 2
        {
            let text_fallback = {
                let guard = self.index.read();
                loading_guard!(guard);
                let mut text_options = search::TextSearchOptions::for_current_code_search();
                text_options.path_scope = options.path_scope.clone();
                text_options.noise_policy = options.noise_policy;
                text_options.include_personal_tooling = options.include_personal_tooling;
                text_options.language_filter = options.language_filter.clone();
                text_options.total_limit = 15;
                text_options.max_per_file = 1;
                search::search_text_with_options(
                    &guard,
                    Some(query_str),
                    None,
                    false,
                    &text_options,
                )
                .unwrap_or_else(|_| search::TextSearchResult {
                    label: String::new(),
                    total_matches: 0,
                    files: vec![],
                    suppressed_by_noise: 0,
                    overflow_count: 0,
                })
            };
            let symbol_paths: std::collections::HashSet<&str> =
                result.hits.iter().map(|h| h.path.as_str()).collect();
            let extra_paths: Vec<String> = text_fallback
                .files
                .iter()
                .filter(|file| !symbol_paths.contains(file.path.as_str()))
                .filter_map(|file| {
                    file.matches
                        .first()
                        .map(|m| format!("{}:{}", file.path, m.line_number))
                })
                .take(10)
                .collect();
            if extra_paths.is_empty() {
                output
            } else {
                format!(
                    "{output}\n\nText path fallback (sparse symbol hits):\n{}",
                    extra_paths.join("\n")
                )
            }
        } else {
            output
        };
        self.record_tool_savings_named(
            "search_symbols",
            format::estimate_tokens_from_chars(format::estimate_listing_baseline_chars(
                output.len(),
            )),
            (output.len() / 4) as u64,
        );
        self.session_context.record_summary_output(
            "search_symbols",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        // Session tracking: record each symbol hit as list-only until its body is fetched.
        for hit in &result.hits {
            self.session_context
                .record_listed_symbol(&hit.path, &hit.name);
        }
        // Intentionally NO frecency bump here — search_symbols is a discovery
        // tool. See wiki `[[SymForge Frecency-Weighted File Ranking]]`
        // §"Search tools deliberately do NOT bump" for the positive-feedback-
        // loop rationale.
        self.apply_ccr_budget("search_symbols", output, params.0.max_tokens)
    }
    /// Shows matches with enclosing symbol context. Use group_by='symbol' to deduplicate,
    /// follow_refs=true to inline callers. Set structural=true to match AST patterns using
    /// ast-grep syntax ($VAR for metavariables, $$$ for multi-node wildcards).
    /// NOT for symbol name search (use search_symbols). NOT for file path search (use search_files).
    #[tool(
        name = "search_text",
        description = "Prefer this over grep/ripgrep for code search — it returns matches with enclosing symbol context instead of raw lines alone. Full-text search across file contents: literal, OR-terms, regex, or structural AST patterns. Use group_by='symbol' to deduplicate and follow_refs=true to inline callers. Set structural=true with query as an ast-grep pattern to match code by AST structure (e.g., 'fn $NAME($$$) { $$$ }'). Matches are ranked and capped per file; large output may CCR-compress with symforge_retrieve hash. NOT for symbol name search (use search_symbols). NOT for file path search (use search_files).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn search_text_tool(
        &self,
        params: Parameters<SearchTextInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.search_text(params).await;
        let outcome_class = classify_search_text_output(&output);
        self.record_tool_completion("search_text", &output, started.elapsed(), outcome_class);
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn search_text(&self, params: Parameters<SearchTextInput>) -> String {
        if let Some(result) = self.proxy_tool_call("search_text", &params.0).await {
            return result;
        }
        // Feature 012 (Phase 3): honest refusal for a cross-project request with
        // no daemon (no working set on the local path).
        if let Some(refusal) =
            local_cross_project_refusal(params.0.project.as_deref(), params.0.projects.as_deref())
        {
            return refusal;
        }
        if params.0.estimate == Some(true) {
            let limit = params.0.limit.unwrap_or(50) as usize;
            let per_file = params.0.max_per_file.unwrap_or(5) as usize;
            let est = limit * 20 + 50;
            return format!(
                "Estimate for search_text: ~{} tokens (limit={}, max_per_file={})",
                est, limit, per_file
            );
        }
        // Structural (AST-pattern) search mode.
        if params.0.structural.unwrap_or(false) {
            let pattern = match params.0.query.as_deref() {
                Some(p) if !p.trim().is_empty() => p.trim(),
                _ => return "Error: `query` is required for structural search.".to_string(),
            };
            let options = match search_text_options_from_input(&params.0) {
                Ok(o) => o,
                Err(message) => return message,
            };
            let mut result = {
                let guard = self.index.read();
                loading_guard!(guard);
                let mut result = search::search_structural(&guard, pattern, &options);
                resolve_text_search_enclosing_symbols(&guard, &mut result);
                result
            };
            apply_path_predicate_filter(
                &mut result,
                params.0.include_vendor.unwrap_or(false),
                params.0.include_personal_tooling.unwrap_or(false),
            );
            maybe_compact_text_search_result(&mut result, pattern);
            let output = render_search_text_output(
                self,
                result,
                Some(pattern),
                true,
                params.0.group_by.as_deref(),
                params.0.terms.as_deref(),
                &options,
                false,
                false,
                false,
            );
            let hint = format::compact_next_step_hint(&[
                "inspect_match (deep-dive one hit)",
                "get_file_context (file overview)",
                "search_symbols (name-based lookup)",
            ]);
            let result = format!("{output}{hint}");
            self.session_context.record_summary_output(
                "search_text",
                (result.len() / 4).min(u32::MAX as usize) as u32,
            );
            return self.apply_ccr_budget("search_text", result, params.0.max_tokens);
        }

        let mut options = match search_text_options_from_input(&params.0) {
            Ok(options) => options,
            Err(message) => return message,
        };
        let mut is_regex = params.0.regex.unwrap_or(false);
        let mut auto_detected_regex = false;
        let original_query = params.0.query.clone();

        // Auto-detect regex patterns: if regex is not explicitly set and the
        // query contains unambiguous regex sequences (\w, \d, \s, \b, .+, .*),
        // enable regex mode automatically. These sequences never appear
        // literally in code, so treating them as literals always gives 0 results.
        if !is_regex && let Some(ref q) = params.0.query {
            let has_regex_escape = q.contains("\\w")
                || q.contains("\\d")
                || q.contains("\\s")
                || q.contains("\\b")
                || q.contains("\\W")
                || q.contains("\\D")
                || q.contains("\\S");
            if has_regex_escape {
                is_regex = true;
                auto_detected_regex = true;
                // Relax noise policy for auto-detected regex — the user
                // is doing a targeted pattern search and expects grep-like
                // completeness, so include test files by default.
                if params.0.include_tests.is_none() {
                    options.noise_policy.include_tests = true;
                }
            }
        }

        // Extract churn scores from GitTemporalIndex BEFORE acquiring the
        // LiveIndex read lock to avoid lock ordering issues.
        if options.ranked {
            let git_temporal = self.index.git_temporal();
            if matches!(
                git_temporal.state,
                crate::live_index::git_temporal::GitTemporalState::Ready
            ) {
                let churn_map: std::collections::HashMap<String, f32> = git_temporal
                    .files
                    .iter()
                    .map(|(path, history)| (path.clone(), history.churn_score))
                    .collect();
                if !churn_map.is_empty() {
                    options.churn_scores = Some(churn_map);
                }
            }
        }

        let mut result = {
            let guard = self.index.read();
            loading_guard!(guard);
            let mut r = search::search_text_with_options(
                &guard,
                params.0.query.as_deref(),
                params.0.terms.as_deref(),
                is_regex,
                &options,
            );
            resolve_text_search_enclosing_symbols(&guard, &mut r);
            // Enrich with callers if follow_refs is set
            if params.0.follow_refs.unwrap_or(false)
                && let Ok(ref mut text_result) = r
            {
                let limit = params.0.follow_refs_limit.unwrap_or(3) as usize;
                enrich_with_callers(&guard, text_result, limit);
            }
            r
        };
        apply_path_predicate_filter(
            &mut result,
            params.0.include_vendor.unwrap_or(false),
            params.0.include_personal_tooling.unwrap_or(false),
        );

        // Auto-correct double-escaped regex patterns: if regex=true and the
        // result is InvalidRegex or Ok-but-empty, try fixing common
        // double-escaped character classes (\\s → \s, \\d → \d, etc.).
        if is_regex {
            let should_retry = match &result {
                Err(search::TextSearchError::InvalidRegex { .. }) => true,
                Ok(r) if r.files.is_empty() => true,
                _ => false,
            };
            if should_retry
                && let Some(ref query) = original_query
                && let Some(fixed) = fix_common_double_escapes(query)
            {
                let mut retry_result = {
                    let guard = self.index.read();
                    loading_guard!(guard);
                    let mut r = search::search_text_with_options(
                        &guard,
                        Some(fixed.as_str()),
                        params.0.terms.as_deref(),
                        true,
                        &options,
                    );
                    resolve_text_search_enclosing_symbols(&guard, &mut r);
                    if params.0.follow_refs.unwrap_or(false)
                        && let Ok(ref mut text_result) = r
                    {
                        let limit = params.0.follow_refs_limit.unwrap_or(3) as usize;
                        enrich_with_callers(&guard, text_result, limit);
                    }
                    r
                };
                apply_path_predicate_filter(
                    &mut retry_result,
                    params.0.include_vendor.unwrap_or(false),
                    params.0.include_personal_tooling.unwrap_or(false),
                );
                // Use the retry result if it actually produced matches
                if let Ok(ref retry_ok) = retry_result
                    && !retry_ok.files.is_empty()
                {
                    let mut output = render_search_text_output(
                        self,
                        retry_result,
                        Some(fixed.as_str()),
                        false,
                        params.0.group_by.as_deref(),
                        params.0.terms.as_deref(),
                        &options,
                        true,
                        auto_detected_regex,
                        true,
                    );
                    output.push_str(&format!(
                        "\n(auto-corrected double-escaped regex: `{}` → `{}`)",
                        query, fixed
                    ));
                    output.push_str(&format::compact_next_step_hint(&[
                        "inspect_match (deep-dive one hit)",
                        "get_file_context (file overview)",
                        "search_symbols (name-based lookup)",
                    ]));
                    self.session_context.record_summary_output(
                        "search_text",
                        (output.len() / 4).min(u32::MAX as usize) as u32,
                    );
                    return self.apply_ccr_budget("search_text", output, params.0.max_tokens);
                }
            }
        }

        let compaction_query =
            search_text_compaction_query(params.0.query.as_deref(), params.0.terms.as_deref());
        maybe_compact_text_search_result(&mut result, &compaction_query);
        let output = render_search_text_output(
            self,
            result,
            params.0.query.as_deref(),
            false,
            params.0.group_by.as_deref(),
            params.0.terms.as_deref(),
            &options,
            is_regex,
            auto_detected_regex,
            false,
        );
        let hint = format::compact_next_step_hint(&[
            "inspect_match (deep-dive one hit)",
            "get_file_context (file overview)",
            "search_symbols (name-based lookup)",
        ]);
        let result = format!("{output}{hint}");
        self.session_context.record_summary_output(
            "search_text",
            (result.len() / 4).min(u32::MAX as usize) as u32,
        );
        // Intentionally NO frecency bump here — search_text is a discovery
        // tool. Bumping on discovery would create a positive feedback loop
        // (hot files get searched more, which would bump them more, which
        // would rank them higher still). See wiki `[[SymForge Frecency-
        // Weighted File Ranking]]` §"Search tools deliberately do NOT bump".
        self.apply_ccr_budget("search_text", result, params.0.max_tokens)
    }

    /// Internal: trace_symbol logic, called by get_symbol_context when sections are provided.
    /// The daemon compatibility alias routes through get_symbol_context so this
    /// canonical path owns trace-mode behavior.
    pub(crate) async fn trace_symbol(&self, params: Parameters<TraceSymbolInput>) -> String {
        if let Some(result) = self.proxy_tool_call("trace_symbol", &params.0).await {
            return result;
        }
        let sections = visible_sections(&params.0.sections);
        if params.0.estimate == Some(true) {
            let section_count = sections
                .as_ref()
                .map(|s| if s.is_empty() { 4 } else { s.len() })
                .unwrap_or(4);
            let est = 200 + section_count * 200;
            return format!(
                "Estimate for trace_symbol: ~{} tokens ({} sections)",
                est, section_count
            );
        }

        let mut trace_view = {
            let guard = self.index.read();
            loading_guard!(guard);
            guard.capture_trace_symbol_view(
                &params.0.path,
                &params.0.name,
                params.0.kind.as_deref(),
                params.0.symbol_line,
                sections.as_deref(),
                include_tests_from_sections(params.0.sections.as_ref()),
            )
        };

        // Fill in git activity if it was requested (or if all sections requested)
        if let crate::live_index::TraceSymbolView::Found(ref mut found) = trace_view {
            let wants_git = sections
                .as_ref()
                .map(|s| s.iter().any(|v| v.eq_ignore_ascii_case("git")))
                .unwrap_or(true);

            if wants_git {
                let temporal = self.index.git_temporal();
                if temporal.state == crate::live_index::git_temporal::GitTemporalState::Ready
                    && let Some(history) = temporal.files.get(&params.0.path)
                {
                    use crate::live_index::git_temporal::{churn_bar, churn_label, relative_time};

                    found.git_activity = Some(crate::live_index::GitActivityView {
                        churn_score: history.churn_score,
                        churn_bar: churn_bar(history.churn_score),
                        churn_label: churn_label(history.churn_score).to_string(),
                        commit_count: history.commit_count,
                        last_relative: relative_time(history.last_commit.days_ago),
                        last_hash: history.last_commit.hash.clone(),
                        last_message: history.last_commit.message_head.clone(),
                        last_author: history.last_commit.author.clone(),
                        last_timestamp: history.last_commit.timestamp.clone(),
                        owners: history
                            .contributors
                            .iter()
                            .map(|c| format!("{} {:.0}%", c.author, c.percentage))
                            .collect(),
                        co_changes: history
                            .co_changes
                            .iter()
                            .map(|e| (e.path.clone(), e.coupling_score, e.shared_commits))
                            .collect(),
                    });
                }
            }
        }

        let verbosity = params.0.verbosity.as_deref().unwrap_or("full");
        let output = format::trace_symbol_result_view(
            &trace_view,
            &params.0.name,
            verbosity,
            params.0.max_tokens,
        );
        self.session_context.record_symbol(
            &params.0.path,
            &params.0.name,
            (output.len() / 4) as u32,
        );
        output
    }

    /// Inspect a specific line in full symbol context: shows the enclosing symbol, parent chain,
    /// and siblings. Works standalone with just path + line, or after search_text to deep-dive a match.
    #[tool(
        description = "Inspect a specific line in full symbol context: enclosing symbol, parent chain (e.g. module → class → method), and sibling symbols. Works standalone with just path + line number, or after search_text to deep-dive a specific hit. NOT for finding all occurrences of a pattern (use search_text). NOT for understanding a symbol's callers and callees (use get_symbol_context).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn inspect_match(&self, params: Parameters<InspectMatchInput>) -> String {
        if let Some(result) = self.proxy_tool_call("inspect_match", &params.0).await {
            return result;
        }
        if params.0.estimate == Some(true) {
            let context = params.0.context.unwrap_or(3) as usize;
            let siblings = params.0.sibling_limit.unwrap_or(10) as usize;
            let est = (context * 2 + 1) * 20 + siblings * 8 + 80;
            return format!(
                "Estimate for inspect_match: ~{} tokens (context={}, siblings={})",
                est, context, siblings
            );
        }

        let view = {
            let guard = self.index.read();
            loading_guard!(guard);
            guard.capture_inspect_match_view(
                &params.0.path,
                params.0.line,
                params.0.context,
                params.0.sibling_limit,
            )
        };

        let output = format::inspect_match_result_view(&view);
        self.session_context.record_summary_output(
            "inspect_match",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        format::enforce_token_budget(output, params.0.max_tokens)
    }

    /// Find files by path, filename, or folder — ranked by relevance. With changed_with=path,
    /// finds co-changing files via git temporal coupling. Set rank_by="path+cochange" with
    /// anchor_path to fuse path matches with the coupling store. Set resolve=true for exact path resolution.
    /// NOT for file content search (use search_text). NOT for symbol names (use search_symbols).
    #[tool(
        name = "search_files",
        description = "Prefer this over a shell find/glob for locating files: it ranks by relevance (frecency + path match) and resolves an ambiguous or partial path to one exact project path. Find files by path, filename, or folder — ranked by relevance. Modes: (1) default: fuzzy search ranked by relevance, (2) changed_with=path: co-changing files via git temporal coupling, (3) rank_by=\"path+cochange\" with anchor_path: fuse path matches with coupling-store evidence, (4) resolve=true: resolve an ambiguous filename or partial path to one exact project path. NOT for file content search (use search_text). NOT for symbol names (use search_symbols).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn search_files_tool(
        &self,
        params: Parameters<SearchFilesInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.search_files(params).await;
        let outcome_class = classify_search_files_output(&output);
        self.record_tool_completion("search_files", &output, started.elapsed(), outcome_class);
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn search_files(&self, params: Parameters<SearchFilesInput>) -> String {
        if let Some(result) = self.proxy_tool_call("search_files", &params.0).await {
            return result;
        }
        let include_vendor = params.0.include_vendor.unwrap_or(false);
        let include_personal_tooling = params.0.include_personal_tooling.unwrap_or(false);
        if params.0.estimate == Some(true) {
            let limit = params.0.limit.unwrap_or(20) as usize;
            let est = limit * 10 + 30;
            return format!(
                "Estimate for search_files: ~{} tokens (limit={})",
                est, limit
            );
        }

        // Resolve mode: exact path resolution
        if params.0.resolve.unwrap_or(false) {
            if params.0.query.is_empty() {
                return "search_files with resolve=true requires a non-empty `query`.".to_string();
            }
            let view = {
                let guard = self.index.read();
                loading_guard!(guard);
                guard.capture_search_files_resolve_view_with_noise(
                    &params.0.query,
                    include_vendor,
                    include_personal_tooling,
                )
            };
            let hidden_noise_count = if include_vendor && include_personal_tooling {
                0
            } else {
                let guard = self.index.read();
                let unfiltered = guard.capture_search_files_resolve_view(&params.0.query);
                search_files_resolve_candidate_count(&unfiltered)
                    .saturating_sub(search_files_resolve_candidate_count(&view))
            };
            let envelope = match &view {
                SearchFilesResolveView::Resolved { path } => {
                    let guard = self.index.read();
                    Some(search_format::format_search_envelope(
                        search_files_resolve_match_type_label(&view),
                        "current index",
                        search_parse_state_for_paths(&guard, std::iter::once(path.as_str())),
                        &search_completeness_label(0, hidden_noise_count),
                        &search_files_scope_summary(
                            "resolve=true against indexed file paths",
                            include_vendor,
                            include_personal_tooling,
                        ),
                        &search_paths_evidence(std::iter::once(path.as_str())),
                    ))
                }
                SearchFilesResolveView::ResolvedMetadataOnly { path, reason } => {
                    // Tier-2 path: never parsed, so report the metadata-only
                    // parse state honestly instead of the misleading "parsed".
                    Some(search_format::format_search_envelope(
                        search_files_resolve_match_type_label(&view),
                        "current index",
                        "metadata-only (not parsed)",
                        &search_completeness_label(0, hidden_noise_count),
                        &search_files_scope_summary(
                            "resolve=true against indexed file paths",
                            include_vendor,
                            include_personal_tooling,
                        ),
                        &format!("Tier-2 metadata-only path `{path}` ({reason}); never parsed"),
                    ))
                }
                SearchFilesResolveView::Ambiguous {
                    matches,
                    overflow_count,
                    ..
                } => {
                    let guard = self.index.read();
                    Some(search_format::format_search_envelope(
                        search_files_resolve_match_type_label(&view),
                        "current index",
                        search_parse_state_for_paths(
                            &guard,
                            matches.iter().map(std::string::String::as_str),
                        ),
                        &search_completeness_label(*overflow_count, hidden_noise_count),
                        &search_files_scope_summary(
                            "resolve=true against indexed file paths",
                            include_vendor,
                            include_personal_tooling,
                        ),
                        &search_paths_evidence(matches.iter().map(std::string::String::as_str)),
                    ))
                }
                _ => None,
            };
            let output = format::search_files_resolve_result_view(&view);
            let had_envelope = envelope.is_some();
            let result = match envelope {
                Some(envelope) => format!("{envelope}\n\n{output}"),
                None => output,
            };
            let mut result = result;
            if !had_envelope {
                append_search_files_filter_summary(
                    &mut result,
                    include_vendor,
                    include_personal_tooling,
                );
            }
            if let Some(note) = search_files_hidden_noise_note(
                hidden_noise_count,
                include_vendor,
                include_personal_tooling,
            ) {
                result.push_str("\n\n");
                result.push_str(&note);
            }
            if matches!(view, SearchFilesResolveView::NotFound { .. }) {
                let matching_untracked_paths = matching_untracked_paths_for_search_files(
                    self,
                    &params.0.query,
                    include_vendor,
                    include_personal_tooling,
                );
                append_untracked_file_diagnostic(&mut result, &matching_untracked_paths);
            }
            let result = format::enforce_token_budget(result, params.0.max_tokens);
            self.session_context.record_summary_output(
                "search_files",
                (result.len() / 4).min(u32::MAX as usize) as u32,
            );
            return result;
        }

        // Deprecated since v7.x: prefer `rank_by="path+cochange"` with `anchor_path`.
        // Keep this compatibility path behavior unchanged for one release cycle.
        if let Some(ref target_path) = params.0.changed_with {
            let temporal = self.index.git_temporal();
            match temporal.state {
                crate::live_index::git_temporal::GitTemporalState::Ready => {}
                crate::live_index::git_temporal::GitTemporalState::Unavailable(ref reason) => {
                    return append_changed_with_deprecation_warning(format!(
                        "Git temporal data unavailable: {reason}"
                    ));
                }
                _ => {
                    return append_changed_with_deprecation_warning(
                        "Git temporal data is still loading. Try again in a few seconds."
                            .to_string(),
                    );
                }
            }
            let commit_count = temporal.stats.total_commits_analyzed;
            if let Some(history) = temporal.files.get(target_path.as_str()) {
                let hits: Vec<SearchFilesHit> = history
                    .co_changes
                    .iter()
                    .map(|entry| SearchFilesHit {
                        tier: SearchFilesTier::CoChange,
                        path: entry.path.clone(),
                        coupling_score: Some(entry.coupling_score),
                        shared_commits: Some(entry.shared_commits),
                        metadata_reason: None,
                    })
                    .collect();
                let weak_hits: Vec<SearchFilesHit> = history
                    .weak_co_changes
                    .iter()
                    .map(|entry| SearchFilesHit {
                        tier: SearchFilesTier::CoChange,
                        path: entry.path.clone(),
                        coupling_score: Some(entry.coupling_score),
                        shared_commits: Some(entry.shared_commits),
                        metadata_reason: None,
                    })
                    .collect();
                if hits.is_empty() {
                    if !weak_hits.is_empty() {
                        let total = weak_hits.len();
                        let mut result =
                            format::search_files_result_view(&SearchFilesView::Found {
                                query: format!("weak co-changes with {target_path}"),
                                total_matches: total,
                                overflow_count: 0,
                                hits: weak_hits,
                            });
                        let envelope = {
                            let guard = self.index.read();
                            search_format::format_search_envelope(
                                "weak heuristic (git-temporal coupling)",
                                "current index + git temporal",
                                search_parse_state_for_paths(
                                    &guard,
                                    history
                                        .weak_co_changes
                                        .iter()
                                        .map(|entry| entry.path.as_str()),
                                ),
                                "full for current scope",
                                &format!(
                                    "weak git-temporal co-change candidates for `{target_path}`"
                                ),
                                &search_paths_evidence(
                                    history
                                        .weak_co_changes
                                        .iter()
                                        .map(|entry| entry.path.as_str()),
                                ),
                            )
                        };
                        result = format!("{envelope}\n\n{result}");
                        result.push_str(
                            "\n\nLow confidence: these candidates missed the strong threshold (2 shared commits and Jaccard >= 0.15). Use them as hints, not proof.",
                        );
                        if commit_count < 50 {
                            result.push_str(&format!(
                                "\nOnly {commit_count} commit(s) were analyzed, so coupling may strengthen as history grows."
                            ));
                        }
                        return append_changed_with_deprecation_warning(result);
                    }
                    let result = if commit_count < 50 {
                        format!(
                            "No high-confidence co-change data for '{target_path}'. Only {commit_count} commit(s) analyzed — strong co-change needs at least 2 shared commits and Jaccard >= 0.15. Results improve with more history."
                        )
                    } else {
                        format!(
                            "No high-confidence co-change data for '{target_path}' (analyzed {commit_count} commits). This file may change independently of others or only have weak coupling signals."
                        )
                    };
                    return append_changed_with_deprecation_warning(result);
                }
                let total = hits.len();
                let mut result = format::search_files_result_view(&SearchFilesView::Found {
                    query: format!("co-changes with {target_path}"),
                    total_matches: total,
                    overflow_count: 0,
                    hits,
                });
                let envelope = {
                    let guard = self.index.read();
                    search_format::format_search_envelope(
                        "heuristic (git-temporal coupling)",
                        "current index + git temporal",
                        search_parse_state_for_paths(
                            &guard,
                            history.co_changes.iter().map(|entry| entry.path.as_str()),
                        ),
                        "full for current scope",
                        &format!("git-temporal co-changes for `{target_path}`"),
                        &search_paths_evidence(
                            history.co_changes.iter().map(|entry| entry.path.as_str()),
                        ),
                    )
                };
                result = format!("{envelope}\n\n{result}");
                if commit_count < 50 {
                    result.push_str(&format!(
                        "\n\n⚠ Low confidence: only {commit_count} commit(s) analyzed. Coupling scores may shift as history grows."
                    ));
                }
                return append_changed_with_deprecation_warning(result);
            }
            if commit_count < 20 {
                return append_changed_with_deprecation_warning(format!(
                    "'{target_path}' not found in git history ({commit_count} commit(s) analyzed). Co-change analysis needs more history to produce useful results."
                ));
            }
            return append_changed_with_deprecation_warning(format!(
                "No git history found for '{target_path}'. Check the file path is correct and that it has been committed."
            ));
        }

        if params.0.query.is_empty() {
            return "search_files requires a non-empty `query` (or use `changed_with` to find co-changing files).".to_string();
        }

        let rank_by_path_cochange = params.0.rank_by.as_deref() == Some("path+cochange");
        let rank_by_frecency = params.0.rank_by.as_deref() == Some("frecency");
        let ranking_diagnostics = search_files_debug_ranking_requested(&params.0);
        let debug_ranking = ranking_diagnostics.explain;
        let mut cochange_evidence: Option<CapabilityEvidence> = None;
        let mut frecency_evidence: Option<CapabilityEvidence> = None;
        let mut hidden_noise_count = 0usize;
        let cochange_repo_root = if rank_by_path_cochange {
            self.capture_repo_root()
        } else {
            None
        };
        let mut view = {
            let guard = self.index.read();
            loading_guard!(guard);
            let cochange_resolution = if rank_by_path_cochange {
                match params.0.anchor_path.as_deref() {
                    Some(anchor_path) => Some(search_files_coupling_neighbors(
                        &guard,
                        cochange_repo_root.as_deref(),
                        anchor_path,
                    )),
                    None => Some(SearchFilesCoChangeResolution {
                        neighbors: None,
                        evidence: cochange_ranking_evidence(
                            CapabilityStatus::FallbackUsed,
                            CapabilityFreshness::Unknown,
                            CapabilityCost::Free,
                            "`rank_by=\"path+cochange\"` requires `anchor_path=<path>`; path ranking returned",
                        ),
                    }),
                }
            } else {
                None
            };
            if let Some(resolution) = &cochange_resolution {
                cochange_evidence = Some(resolution.evidence.clone());
            }
            let coupling_neighbors = cochange_resolution
                .as_ref()
                .and_then(|resolution| resolution.neighbors.as_ref());
            let coupling_context = params.0.anchor_path.as_deref().zip(coupling_neighbors);
            // Optional path-prefix scoping, mirroring the `path_scope` axis of
            // search_symbols/search_text: the scope is applied inside the capture
            // (pre-count predicate), so total_matches/overflow_count/hits are all
            // consistently scoped — including the overflow set, not just the
            // visible hits.
            let path_scope = normalize_path_prefix(params.0.path_prefix.as_deref());
            let view = guard.capture_search_files_view_with_noise(
                &params.0.query,
                params.0.limit.unwrap_or(20) as usize,
                params.0.current_file.as_deref(),
                coupling_context,
                include_vendor,
                include_personal_tooling,
                &path_scope,
            );
            if !(include_vendor && include_personal_tooling) {
                // Same path_scope so hidden_noise_count compares like-for-like
                // (noise hidden WITHIN the requested prefix, not repo-wide).
                let unfiltered = guard.capture_search_files_view_with_noise(
                    &params.0.query,
                    params.0.limit.unwrap_or(20) as usize,
                    params.0.current_file.as_deref(),
                    coupling_context,
                    true,
                    true,
                    &path_scope,
                );
                hidden_noise_count = search_files_total_matches(&unfiltered)
                    .saturating_sub(search_files_total_matches(&view));
            }
            if rank_by_path_cochange && let Some((anchor_path, neighbors)) = coupling_context {
                let applied_hits = match &view {
                    SearchFilesView::Found { hits, .. } => hits
                        .iter()
                        .filter(|hit| hit.tier == SearchFilesTier::CoChange)
                        .count(),
                    _ => 0,
                };
                cochange_evidence = if applied_hits > 0 {
                    Some(cochange_ranking_evidence(
                        CapabilityStatus::Applied,
                        CapabilityFreshness::Current,
                        CapabilityCost::Low,
                        format!(
                            "anchor_path={anchor_path} loaded {} usable coupling partner(s); rows with shared-commit counts show applied evidence",
                            neighbors.len()
                        ),
                    ))
                } else {
                    let candidate_paths: Vec<&str> = match &view {
                        SearchFilesView::Found { hits, .. } => {
                            hits.iter().map(|hit| hit.path.as_str()).collect()
                        }
                        _ => Vec::new(),
                    };
                    Some(cochange_ranking_evidence(
                        CapabilityStatus::FallbackUsed,
                        CapabilityFreshness::Current,
                        CapabilityCost::Low,
                        cochange_fallback_detail(
                            &params.0.query,
                            anchor_path,
                            neighbors,
                            &candidate_paths,
                        ),
                    ))
                };
            }
            view
        };
        // Optional frecency-fusion rerank. Activated when the caller requests
        // `rank_by="frecency"`, independent of the old persistent-collection
        // feature flag. Discovery still never opens a writeable frecency store:
        // this branch only reads existing persistent rows and current-process
        // session rows, then reports explicit evidence for every fallback.
        if rank_by_frecency {
            match crate::live_index::frecency::collection_policy_from_env() {
                crate::capability::FrecencyCollectionPolicy::Disabled => {
                    frecency_evidence = Some(frecency_ranking_evidence(
                        CapabilityStatus::DisabledByPolicy,
                        "operator policy disabled frecency collection and ranking; path ranking returned",
                    ));
                }
                _ => match &mut view {
                    SearchFilesView::Found { hits, .. } if hits.is_empty() => {
                        frecency_evidence = Some(frecency_ranking_evidence(
                            CapabilityStatus::FallbackUsed,
                            "no returned candidates to score; path ranking returned",
                        ));
                    }
                    SearchFilesView::Found { hits, .. } => {
                        if let Some(repo_root) = self.capture_repo_root() {
                            let candidate_count = hits.len();
                            let hit_paths: Vec<std::path::PathBuf> = hits
                                .iter()
                                .map(|hit| std::path::PathBuf::from(&hit.path))
                                .collect();
                            let path_refs: Vec<&std::path::Path> =
                                hit_paths.iter().map(|path| path.as_path()).collect();
                            let now_ts = std::time::SystemTime::now()
                                .duration_since(std::time::UNIX_EPOCH)
                                .map(|duration| duration.as_secs() as i64)
                                .unwrap_or(0);
                            match crate::live_index::frecency::ranking_scores_for_paths(
                                &repo_root, &path_refs, now_ts,
                            ) {
                                Ok(Some(snapshot)) if !snapshot.scores.is_empty() => {
                                    let scored_count = snapshot.scores.len();
                                    let breakdowns =
                                        crate::live_index::search::score_hits_by_frecency_fusion(
                                            hits,
                                            &snapshot.scores,
                                        );
                                    let taken = std::mem::take(hits);
                                    *hits =
                                        crate::live_index::search::reorder_hits_by_frecency_fusion(
                                            taken,
                                            &breakdowns,
                                        );
                                    frecency_evidence = Some(frecency_ranking_evidence(
                                        CapabilityStatus::Applied,
                                        format!(
                                            "{scored_count}/{candidate_count} returned candidates had frecency scores from {}; requested frecency ranking applied",
                                            snapshot.source
                                        ),
                                    ));
                                }
                                Ok(Some(snapshot)) => {
                                    frecency_evidence = Some(frecency_ranking_evidence(
                                        CapabilityStatus::FallbackUsed,
                                        format!(
                                            "{} is empty or has no scores for returned candidates; path ranking returned",
                                            snapshot.source
                                        ),
                                    ));
                                }
                                Ok(None) => {
                                    frecency_evidence = Some(frecency_ranking_evidence(
                                        CapabilityStatus::FallbackUsed,
                                        "no frecency history found; path ranking returned",
                                    ));
                                }
                                Err(reason) => {
                                    frecency_evidence = Some(frecency_ranking_evidence(
                                        CapabilityStatus::Unavailable,
                                        format!(
                                            "unable to read frecency history: {reason}; path ranking returned"
                                        ),
                                    ));
                                }
                            }
                        } else {
                            frecency_evidence = Some(frecency_ranking_evidence(
                                CapabilityStatus::Unavailable,
                                "no repository root is bound; path ranking returned",
                            ));
                        }
                    }
                    _ => {
                        frecency_evidence = Some(frecency_ranking_evidence(
                            CapabilityStatus::FallbackUsed,
                            "no returned candidates to score; path ranking returned",
                        ));
                    }
                },
            }
        }
        let envelope = match &view {
            SearchFilesView::Found {
                hits,
                overflow_count,
                ..
            } => {
                let guard = self.index.read();
                let scope = match params.0.current_file.as_deref() {
                    Some(current_file) => {
                        format!("ranked indexed file paths; current file boost `{current_file}`")
                    }
                    None => "ranked indexed file paths".to_string(),
                };
                Some(search_format::format_search_envelope(
                    search_files_match_type_label(&view),
                    if rank_by_path_cochange {
                        "current index + optional coupling store"
                    } else if rank_by_frecency {
                        "current index + optional frecency history"
                    } else {
                        "current index"
                    },
                    search_parse_state_for_paths(&guard, hits.iter().map(|hit| hit.path.as_str())),
                    &search_completeness_label(*overflow_count, hidden_noise_count),
                    &search_files_scope_summary(scope, include_vendor, include_personal_tooling),
                    &search_paths_evidence(hits.iter().map(|hit| hit.path.as_str())),
                ))
            }
            _ => None,
        };
        let output = format::search_files_result_view(&view);
        let had_envelope = envelope.is_some();
        let mut result = match envelope {
            Some(envelope) => format!("{envelope}\n\n{output}"),
            None => output,
        };
        if !had_envelope {
            append_search_files_filter_summary(
                &mut result,
                include_vendor,
                include_personal_tooling,
            );
        }
        if let Some(evidence) = cochange_evidence.as_ref() {
            result.push_str("\n\n");
            result.push_str(&format::capability_evidence_line(evidence));
        }
        if let Some(evidence) = frecency_evidence.as_ref() {
            result.push_str("\n\n");
            result.push_str(&format::capability_evidence_line(evidence));
        }
        if let Some(evidence) = ranking_diagnostics.evidence.as_ref() {
            result.push_str("\n\n");
            result.push_str(&format::capability_evidence_line(evidence));
        }
        if debug_ranking {
            result.push_str("\n\n");
            result.push_str(&search_files_ranking_explanation(
                &view,
                params.0.rank_by.as_deref(),
                cochange_evidence.as_ref(),
                frecency_evidence.as_ref(),
            ));
        }
        if let Some(note) = search_files_hidden_noise_note(
            hidden_noise_count,
            include_vendor,
            include_personal_tooling,
        ) {
            result.push_str("\n\n");
            result.push_str(&note);
        }
        if matches!(view, SearchFilesView::NotFound { .. }) {
            let matching_untracked_paths = matching_untracked_paths_for_search_files(
                self,
                &params.0.query,
                include_vendor,
                include_personal_tooling,
            );
            append_untracked_file_diagnostic(&mut result, &matching_untracked_paths);
        }
        self.session_context.record_summary_output(
            "search_files",
            (result.len() / 4).min(u32::MAX as usize) as u32,
        );
        // Intentionally NO frecency bump here — search_files is a discovery
        // tool, and bumping on discovery creates a positive feedback loop
        // where files that rank high are searched more, which makes them
        // rank even higher. Bumps fire only on commitment (get_file_context,
        // get_file_content, get_symbol, get_symbol_context, and the 7 edit
        // tools via EditHook). See wiki `[[SymForge Frecency-Weighted File
        // Ranking]]` §"Search tools deliberately do NOT bump".
        result
    }

    /// Resolve the co-change anchor for a fused-find `search_files` step.
    ///
    /// US4 find fusion: the STEL planner is index-free, so it emits the
    /// `search_files` path step with `rank_by="path+cochange"` but NO
    /// `anchor_path`. Anchor resolution belongs where the index lives — here.
    ///
    /// The path matcher reads a multi-word query as `component…/basename`, so a
    /// fuzzy bag of words whose trailing token is not a file basename (e.g.
    /// `"stel planner find"`) yields no path candidates. To stay robust to token
    /// order we try the full query first, then each individual token, and take
    /// the first top Tier-1 path hit. `search_files`'s own
    /// `CO_CHANGE_ANCHOR_CONFIDENCE_FLOOR=basename` gate still decides whether
    /// the boost applies, so a weak anchor degrades to pure path ranking with no
    /// special-casing. Returns `None` when nothing path-like matches.
    ///
    /// Reads only the index path view (never `get_*`), so this stays on the
    /// frecency-neutral discovery surface.
    pub(crate) fn resolve_find_fusion_cochange_anchor(&self, query: &str) -> Option<String> {
        let guard = self.index.read();
        let top_hit = |q: &str| -> Option<String> {
            match guard.capture_search_files_view(q, 5, None, None) {
                SearchFilesView::Found { hits, .. } => hits
                    .into_iter()
                    .find(|hit| hit.tier != SearchFilesTier::MetadataOnly)
                    .map(|hit| hit.path),
                _ => None,
            }
        };
        if let Some(hit) = top_hit(query) {
            return Some(hit);
        }
        query
            .split_whitespace()
            .filter(|tok| tok.chars().any(char::is_alphanumeric))
            .find_map(top_hit)
    }

    /// Inject the resolved co-change anchor into a fused-find `search_files` step.
    ///
    /// Recognizes the find-fusion path step by its exact emitted shape
    /// (`tool == "search_files"` AND `rank_by == "path+cochange"` AND no
    /// `anchor_path`) — the only planner route that emits that shape.
    ///
    /// When an anchor resolves, the path step is retargeted to that anchor:
    /// `query` becomes the anchor path and `anchor_path` is set, so the path
    /// side surfaces the best-matching file PLUS its boosted co-change partners
    /// (the broad multi-file listing is already carried by the fusion's
    /// `search_text` step). The `CO_CHANGE_ANCHOR_CONFIDENCE_FLOOR=basename`
    /// gate inside `search_files` still decides whether the boost actually
    /// applies. When no anchor resolves, `rank_by` is dropped so the step runs
    /// as plain path ranking on the original query (graceful
    /// co-change-unavailable degradation). Every other step is unchanged.
    fn inject_find_fusion_cochange_anchor(
        &self,
        tool: &str,
        args: &serde_json::Value,
    ) -> serde_json::Value {
        let is_fusion_path_step = tool == "search_files"
            && args.get("rank_by").and_then(serde_json::Value::as_str) == Some("path+cochange")
            && args.get("anchor_path").is_none();
        if !is_fusion_path_step {
            return args.clone();
        }
        let query = args
            .get("query")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default();
        let mut args = args.clone();
        let Some(map) = args.as_object_mut() else {
            return args;
        };
        match self.resolve_find_fusion_cochange_anchor(query) {
            Some(anchor) => {
                // Retarget the path side to the anchor's basename STEM. The stem
                // names the anchor's own basename, so the anchor clears the
                // `CO_CHANGE_ANCHOR_CONFIDENCE_FLOOR=basename` gate (via the
                // SF-006 stem-equals-basename anchor promotion), while files
                // that share the stem prefix (a common co-change-partner naming
                // pattern) remain candidates the boost can promote. Falls back
                // to the full anchor path when it has no usable stem.
                let path_query = std::path::Path::new(&anchor)
                    .file_stem()
                    .and_then(|stem| stem.to_str())
                    .filter(|stem| stem.len() >= 3)
                    .map(str::to_string)
                    .unwrap_or_else(|| anchor.clone());
                map.insert("query".to_string(), serde_json::Value::String(path_query));
                map.insert("anchor_path".to_string(), serde_json::Value::String(anchor));
            }
            None => {
                // No path-like anchor → pure path ranking on the original query.
                // Drop the co-change request so search_files does not emit a
                // fallback-evidence note for a speculative request.
                map.remove("rank_by");
            }
        }
        args
    }

    /// US5 economics grounding (010 FR-014, D2): stamp real target byte sizes onto
    /// the plan steps so the L2 gate predicts from actual work instead of the
    /// plan-only `400/800` constants. The plan-only planner has no index; the
    /// index lives here, so this is where real sizes are resolved (mirrors
    /// `inject_find_fusion_cochange_anchor`).
    ///
    /// Grounding is restricted to the **single-file read family** —
    /// `get_file_context`, `get_file_content`, `get_symbol` — whose competent
    /// manual baseline genuinely IS "read this one resolved file" (the model the
    /// byte-grounded estimator captures). Listing/trace/search tools
    /// (`find_references`, `find_dependents`, `search_*`, `explore`,
    /// `get_repo_map`) are deliberately NOT grounded to a single file: their
    /// manual equivalent is grep-then-window across MANY files, which a single
    /// resolved definition byte length would badly *under*-state (wrongly pushing
    /// an expensive trace toward bypass). Those steps keep the plan-only floor
    /// (the documented interim estimate for figures not yet grounded, FR-001),
    /// so grounding only ever *adds* honest single-file signal and never
    /// fabricates or understates a baseline.
    ///
    /// For a grounded step it resolves the target file — `args["path"]` directly,
    /// or the file a `get_symbol` `args["name"]` is defined in (single unambiguous
    /// match only) — and records its `content.len()` as an [`IndexRef`].
    /// Resolution is deterministic for a fixed index state (same query + same repo
    /// ⇒ same sizes ⇒ same decision; Constitution IV).
    fn ground_plan_economics(&self, plan: &mut crate::stel::StelPlan) {
        let guard = self.index.read();
        if !guard.is_ready() {
            return;
        }
        for step in &mut plan.steps {
            if !step.index_refs.is_empty() {
                continue;
            }
            // Only single-file read tools have a "read this one file" manual
            // baseline. Symbol-name resolution applies to `get_symbol` only;
            // `find_references` shares the `name` arg but is a multi-file trace.
            let resolve_symbol = step.tool == "get_symbol";
            if !matches!(
                step.tool.as_str(),
                "get_file_context" | "get_file_content" | "get_symbol"
            ) {
                continue;
            }
            let resolved_path = step
                .args
                .get("path")
                .and_then(serde_json::Value::as_str)
                .map(str::trim)
                .filter(|path| !path.is_empty())
                .map(str::to_string)
                .or_else(|| {
                    if !resolve_symbol {
                        return None;
                    }
                    // Resolve a path-less `get_symbol` step to the file the symbol
                    // is defined in, but only when exactly one file defines it —
                    // an ambiguous symbol has no single manual baseline, so we
                    // leave it on the plan-only floor.
                    let name = step
                        .args
                        .get("name")
                        .and_then(serde_json::Value::as_str)
                        .map(str::trim)
                        .filter(|name| !name.is_empty())?;
                    let candidates = symbol_candidate_paths(&guard, name);
                    if candidates.len() == 1 {
                        candidates.into_iter().next()
                    } else {
                        None
                    }
                });
            let Some(path) = resolved_path else {
                continue;
            };
            if let Some(file) = guard.capture_shared_file(&path) {
                step.index_refs
                    .push(crate::stel::controller::index_ref_for_target(
                        path,
                        file.content.len() as u64,
                    ));
            }
        }
    }

    fn project_id_for_root(root: &Path) -> String {
        let normalized = root.display().to_string().replace('\\', "/");
        let stable_path = if cfg!(windows) {
            normalized.to_lowercase()
        } else {
            normalized
        };
        format!(
            "project-{}",
            crate::hash::digest_hex(stable_path.as_bytes())
        )
    }

    fn runtime_status_for(
        &self,
        published: &crate::live_index::PublishedIndexState,
        mode: format::RuntimeMode,
        project_id: Option<String>,
        session_id: Option<String>,
        project_root: Option<PathBuf>,
    ) -> format::RuntimeStatus {
        let project_root = project_root.or_else(|| self.capture_repo_root());
        let project_id = project_id.unwrap_or_else(|| {
            project_root
                .as_deref()
                .map(Self::project_id_for_root)
                .unwrap_or_else(|| "project-unknown".to_string())
        });
        let session_id =
            session_id.unwrap_or_else(|| format!("local-process-{}", std::process::id()));

        format::RuntimeStatus {
            mode,
            project_root: project_root.map(|root| root.to_string_lossy().replace('\\', "/")),
            project_id,
            session_id,
            index_generation: published.generation,
            project_generation: self.index.current_project_generation(),
            reset_project_generation: self.index.current_reset_project_generation(),
            load_source: published.load_source,
        }
    }

    fn local_runtime_mode(&self) -> format::RuntimeMode {
        if self.daemon_client.is_some() && self.daemon_degraded.load(Ordering::Relaxed) {
            format::RuntimeMode::DaemonDegradedLocalFallback
        } else {
            format::RuntimeMode::LocalProcess
        }
    }

    fn health_for_runtime(
        &self,
        mode: format::RuntimeMode,
        project_id: Option<String>,
        session_id: Option<String>,
        project_root: Option<PathBuf>,
        quarantine_window: format::QuarantineWindow,
    ) -> String {
        let published = self.index.published_state();
        let runtime_status =
            self.runtime_status_for(&published, mode, project_id, session_id, project_root);
        let watcher_guard = self.watcher_info.lock();
        let rejected_stale_mutations = self.index.current_rejected_stale_mutations();
        let mut result = format::health_report_from_published_state_windowed(
            &published,
            &watcher_guard,
            rejected_stale_mutations,
            quarantine_window,
        );
        result.push('\n');
        result.push_str(&format::format_runtime_status(&runtime_status));
        let sidecar_status = sidecar_status_for_server(self);
        result.push('\n');
        result.push_str(&format::format_sidecar_status(&sidecar_status));

        // Append token savings section if the sidecar's TokenStats are available.
        if let Some(ref stats) = self.token_stats {
            let snap = stats.summary();
            let savings = format::format_token_savings(&snap);
            if !savings.is_empty() {
                result.push('\n');
                result.push_str(&savings);
            }

            // Append per-tool call counts.
            let counts = stats.tool_call_counts();
            let counts_section = format::format_tool_call_counts(&counts);
            if !counts_section.is_empty() {
                result.push('\n');
                result.push_str(&counts_section);
            }

            // Append per-tool token efficiency breakdown.
            let token_details = stats.tool_token_details();
            let breakdown = format::format_tool_token_breakdown(&token_details);
            if !breakdown.is_empty() {
                result.push('\n');
                result.push_str(&breakdown);
            }
        }

        let adoption =
            crate::cli::hook::load_hook_adoption_snapshot(self.capture_repo_root().as_deref());
        let adoption_section = format::format_hook_adoption(&adoption);
        if !adoption_section.is_empty() {
            result.push('\n');
            result.push_str(&adoption_section);
        }

        // Append git temporal summary.
        result.push('\n');
        result.push_str(&format::git_temporal_health_line(
            &self.index.git_temporal(),
        ));

        let capabilities = {
            let repo_root = self.capture_repo_root();
            let guard = self.index.read();
            capability_status_report(&guard, repo_root.as_deref())
        };
        result.push('\n');
        result.push_str(&capabilities.full_text());

        // Append worktree-awareness misuse counter (rolling last-hour window).
        result.push('\n');
        result.push_str(&format!(
            "── Worktree-awareness misuse ──\nedit tool calls without working_directory (last hour): {}",
            self.worktree_misuse.current_window_count(),
        ));

        // Append frecency diagnostics when SYMFORGE_FRECENCY=1. The feature-flag
        // guard mirrors the one in `frecency::bump`; when the flag is unset,
        // the health output remains compact unless the feature is explicitly enabled.
        if std::env::var(crate::live_index::frecency::FRECENCY_FLAG_ENV).as_deref() == Ok("1")
            && let Some(repo_root) = self.capture_repo_root()
            && let Ok(store) = crate::live_index::frecency::FrecencyStore::open(
                &crate::live_index::frecency::frecency_db_path(&repo_root),
            )
        {
            let now_ts = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .map(|d| d.as_secs() as i64)
                .unwrap_or(0);
            if let Ok(top) = store.top_frecent(10, now_ts) {
                result.push('\n');
                result.push_str(&format::format_frecency_top(&top));
            }
            // "Last 10 frecency bumps" is additionally gated on
            // the ranking diagnostics default-on policy; it is a debug-only
            // surface for ranker tuning, not the default health view.
            if ranking_diagnostics_policy_from_env() == RankingDiagnosticsPolicy::DefaultOn
                && let Ok(last) = store.last_10_bumps()
            {
                result.push('\n');
                result.push_str(&format::format_frecency_last_bumps(&last));
            }
        }

        // Surface a version-drift warning when this daemon's binary is older
        // than another installed copy (e.g. an npm-updated package). Read-only;
        // never copies or replaces the binary (see version_registry).
        if let Some(drift) = crate::version_registry::drift_banner_default() {
            result.push('\n');
            result.push_str(&drift);
        }

        // Surface a PATH-shadow warning when a bare `symforge` would run a
        // DIFFERENT install than the binary serving this runtime. Read-only;
        // emits the exact remediation commands, never executes them.
        if let Some(report) = current_exe_shadow_report() {
            result.push('\n');
            result.push_str(&crate::path_shadow::format_shadow_warning(&report));
        }

        result
    }

    fn health_compact_for_runtime(
        &self,
        mode: format::RuntimeMode,
        project_id: Option<String>,
        session_id: Option<String>,
        project_root: Option<PathBuf>,
    ) -> String {
        let published = self.index.published_state();
        let runtime_status =
            self.runtime_status_for(&published, mode, project_id, session_id, project_root);
        let watcher_guard = self.watcher_info.lock();
        let rejected_stale_mutations = self.index.current_rejected_stale_mutations();
        let mut result = format::health_report_compact_from_published_state(
            &published,
            &watcher_guard,
            rejected_stale_mutations,
        );
        result.push('\n');
        result.push_str(&format::format_runtime_status_compact(&runtime_status));
        let sidecar_status = sidecar_status_for_server(self);
        result.push('\n');
        result.push_str(&format::format_sidecar_status_compact(&sidecar_status));

        if let Some(ref stats) = self.token_stats {
            let snap = stats.summary();
            let total_saved =
                snap.read_saved_tokens + snap.edit_saved_tokens + snap.grep_saved_tokens;
            let total_fires =
                snap.read_fires + snap.edit_fires + snap.write_fires + snap.grep_fires;
            if total_fires > 0 {
                result.push_str(&format!(
                    "\nToken savings: ~{} tokens saved across {} hook fires",
                    total_saved, total_fires
                ));
            }

            let counts = stats.tool_call_counts();
            let total_tool_calls: usize = counts.iter().map(|(_, count)| *count).sum();
            if total_tool_calls > 0 {
                result.push_str(&format!(
                    "\nTool calls: {} recorded across {} tools",
                    total_tool_calls,
                    counts.len()
                ));
            }
        }

        let git_temporal = format::git_temporal_health_line(&self.index.git_temporal());
        let git_temporal_summary = git_temporal
            .lines()
            .next()
            .unwrap_or("Git temporal: unknown");
        result.push_str(&format!(
            "\n{} | Worktree misuse/hour: {}",
            git_temporal_summary,
            self.worktree_misuse.current_window_count()
        ));

        let capabilities = {
            let repo_root = self.capture_repo_root();
            let guard = self.index.read();
            capability_status_report(&guard, repo_root.as_deref())
        };
        result.push('\n');
        result.push_str(&capabilities.compact_text());

        if let Some(drift) = crate::version_registry::drift_banner_default() {
            result.push('\n');
            result.push_str(&drift);
        }

        // Compact PATH-shadow banner (one line, points at full health for the
        // exact fix). See `health_for_runtime` for the full block.
        if let Some(report) = current_exe_shadow_report() {
            result.push('\n');
            result.push_str(&crate::path_shadow::format_shadow_warning_compact(&report));
        }

        result
    }

    pub(crate) fn health_for_daemon_session(
        &self,
        project_id: String,
        session_id: String,
        project_root: PathBuf,
        quarantine_window: format::QuarantineWindow,
    ) -> String {
        self.health_for_runtime(
            format::RuntimeMode::DaemonReusedSession,
            Some(project_id),
            Some(session_id),
            Some(project_root),
            quarantine_window,
        )
    }

    pub(crate) fn health_compact_for_daemon_session(
        &self,
        project_id: String,
        session_id: String,
        project_root: PathBuf,
    ) -> String {
        self.health_compact_for_runtime(
            format::RuntimeMode::DaemonReusedSession,
            Some(project_id),
            Some(session_id),
            Some(project_root),
        )
    }

    /// Diagnostic: index status, file/symbol counts, load time, watcher state, token savings,
    /// project/session identity, hook adoption metrics, git temporal status. Always responds
    /// even during loading. Use to verify SymForge is working.
    #[tool(
        description = "Diagnostic: index status, file/symbol counts, project/session identity, load time, watcher state, token savings, hook adoption metrics, git temporal status. Always responds even during loading. Use to verify SymForge is working. Optional quarantine_limit/quarantine_offset page the parse/span quarantine registry (default 10) so the full list of partial/failed files is retrievable. NOT for diagnosing a specific file or symbol (use get_file_context or get_symbol).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn health(&self, params: Parameters<HealthInput>) -> String {
        let input = params.0;
        if let Some(result) = self.proxy_tool_call("health", &input).await {
            // Ops guard (SF-001/SF-009 root-cause class): warn loudly if the daemon
            // we proxied to is serving an OLDER binary than this front-end.
            return append_daemon_staleness_warning(result, env!("CARGO_PKG_VERSION"));
        }
        let window = format::QuarantineWindow::from_args(
            input.quarantine_offset(),
            input.quarantine_limit(),
        );
        let result = self.health_for_runtime(self.local_runtime_mode(), None, None, None, window);
        self.session_context
            .record_summary_output("health", (result.len() / 4).min(u32::MAX as usize) as u32);
        result
    }

    /// Compact diagnostic: essential health fields only. Use when token budget matters.
    #[tool(
        description = "Compact diagnostic: essential index, project/session identity, watcher, admission, and token-savings health fields only. Prefer this when token budget matters; use health for full diagnostic lists. NOT for diagnosing a specific file or symbol (use get_file_context or get_symbol).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn health_compact(&self) -> String {
        if let Some(result) = self.proxy_tool_call_without_params("health_compact").await {
            // Ops guard (SF-001/SF-009 root-cause class): warn loudly if the daemon
            // we proxied to is serving an OLDER binary than this front-end.
            return append_daemon_staleness_warning(result, env!("CARGO_PKG_VERSION"));
        }

        let result = self.health_compact_for_runtime(self.local_runtime_mode(), None, None, None);
        self.session_context.record_summary_output(
            "health_compact",
            (result.len() / 4).min(u32::MAX as usize) as u32,
        );
        result
    }

    /// Serialize the current in-memory index to `.symforge/index.bin` immediately.
    #[tool(
        name = "checkpoint_now",
        description = "Serialize the current in-memory index to `.symforge/index.bin` immediately. Uses the same atomic snapshot path as shutdown persistence and reports failures explicitly. When export_artifact=true, additionally exports the Best-tier team artifact (`.symforge/index.bin.zst` + `artifact.json`, plus a `.gitattributes` merge=ours hint) for sharing a bootstrap cache across a team — see contracts/team-artifact.md.",
        annotations(
            read_only_hint = false,
            destructive_hint = false,
            idempotent_hint = true,
            open_world_hint = false
        )
    )]
    pub(crate) async fn checkpoint_now(&self, params: Parameters<CheckpointNowInput>) -> String {
        // Proxy-first: in daemon-proxy mode the daemon owns the authoritative
        // live index, while this process holds only `LiveIndex::empty()`.
        // Forward to the daemon (where `daemon_client` is None and `repo_root`
        // is real) so the checkpoint runs against the populated index. On
        // local-fallback the proxy returns None and the in-process logic below
        // checkpoints the locally reloaded index.
        let daemon_configured = self.daemon_client.is_some();
        if let Some(result) = self.proxy_tool_call("checkpoint_now", &params.0).await {
            return result;
        }
        let repo_root = match self.capture_repo_root() {
            Some(root) => root,
            None => return "Checkpoint failed: no repository root configured.".to_string(),
        };
        let index = Arc::clone(&self.index);
        let checkpoint_root = repo_root.clone();
        let verify_after_write = params.0.verify_after_write.unwrap_or(false);
        let export_artifact = params.0.export_artifact.unwrap_or(false);
        match tokio::task::spawn_blocking(move || {
            let report =
                crate::live_index::persist::checkpoint_shared_index(&index, &checkpoint_root)?;
            if verify_after_write
                && crate::live_index::persist::load_snapshot(&checkpoint_root).is_none()
            {
                anyhow::bail!(
                    "checkpoint verification failed: snapshot did not deserialize after write"
                );
            }
            let artifact_report = if export_artifact {
                let guard = index.read();
                Some(crate::live_index::persist::export_artifact(
                    &guard,
                    &checkpoint_root,
                )?)
            } else {
                None
            };
            anyhow::Ok((report, artifact_report))
        })
        .await
        {
            Ok(Ok((report, artifact_report))) => {
                let mut message = format!(
                    "Checkpoint complete: wrote {} bytes for {} file(s) to {}",
                    report.bytes,
                    report.files,
                    report.path.display()
                );
                // Honest receipt (review finding 2, post-v7.19.0): reaching this
                // point with a daemon CONFIGURED means the proxy failed and we
                // fell back to checkpointing the locally reloaded index, which
                // may lag the daemon's authoritative live index. Say so, instead
                // of an output indistinguishable from the daemon path — the
                // snapshot written here can be staler than one the daemon would
                // have written.
                if daemon_configured {
                    message.push_str(
                        "\nnote: daemon unreachable; this checkpoint wrote the locally reloaded \
                         index, which may lag the daemon's live index. Re-run checkpoint_now once \
                         the daemon is reachable to persist its authoritative state.",
                    );
                }
                if let Some(artifact) = artifact_report {
                    message.push_str(&format!(
                        "\nArtifact exported: {} ({} bytes compressed from {} for {} file(s))",
                        artifact.path.display(),
                        artifact.compressed_bytes,
                        artifact.raw_bytes,
                        artifact.files
                    ));
                }
                message
            }
            Ok(Err(error)) => format!("Checkpoint failed: {error}"),
            Err(join_error) => format!("Checkpoint failed: checkpoint task panicked: {join_error}"),
        }
    }

    /// Reindex a directory from scratch — replaces the current index, restarts watcher, triggers
    /// git temporal analysis. Use when switching projects. Destructive to current index.
    #[tool(
        description = "Reindex a directory from scratch — replaces the current index, restarts watcher, triggers git temporal analysis. Use when switching projects. Destructive to current index. NOT for re-reading a single changed file (use analyze_file_impact). NOT for reading content from an existing index (use get_file_content).",
        annotations(
            // Destructive: replaces the active index (discards current contents),
            // matching the description. Also idempotent: re-running with the same
            // path converges to the same index. Destructive + idempotent are
            // independent MCP hints, so both are honestly true here.
            read_only_hint = false,
            destructive_hint = true,
            idempotent_hint = true,
            open_world_hint = false
        )
    )]
    pub async fn index_folder(&self, params: Parameters<IndexFolderInput>) -> String {
        let is_additive = params.0.add == Some(true);
        if let Some(result) = self.proxy_tool_call("index_folder", &params.0).await {
            // Feature 012 (Phase 2): an ADDITIVE open does NOT retarget the
            // session — it adds a second project to the daemon-owned working set
            // while the active project (and this front-end's `repo_root` /
            // `self.index`) stays put. So skip the retarget bookkeeping below;
            // resetting the local index here would wrongly drop the active
            // project's local-fallback state.
            if is_additive {
                return result;
            }
            // The daemon has rebound the session to the new project. Update our
            // local repo_root so that local-fallback tools (what_changed,
            // analyze_file_impact) and ensure_local_index use the correct root
            // if the daemon connection degrades later.
            if result.starts_with("Indexed ") {
                let new_root = PathBuf::from(&params.0.path);
                self.set_repo_root(Some(new_root));
                // Trust-critical: invalidate any stale in-process index left
                // over from a previous local-fallback load. Without this, a
                // server that already populated `self.index` for the OLD
                // project (via `ensure_local_index`) would keep serving the old
                // project from every tool that falls back to local execution
                // (search_symbols, search_text, get_file_context, conventions,
                // explore, ...), because `ensure_local_index` only reloads when
                // the index is empty. Resetting to empty forces the next local
                // fallback to reload from the NEW root, so no tool can silently
                // mix projects after a daemon-proxied `index_folder` switch.
                self.index.reset_to_empty();
            }
            return result;
        }
        let input = params.0;
        // Feature 012 (Phase 2), Principle VII honesty: additive multi-project
        // opens live ONLY in the daemon-owned working set. On stdio/embed (no
        // daemon) or when the daemon is unreachable, there is no working set to
        // add to — refuse honestly instead of silently falling back to a
        // single-project retarget that would discard the active project.
        if input.add == Some(true) {
            return "index_folder(add:true) requires the daemon: additive \
                multi-project opens are only available over the daemon transport, \
                not on stdio/embed. Start the daemon (the default desktop topology) \
                to open multiple projects in one session."
                .to_string();
        }
        let root = PathBuf::from(&input.path);
        if !root.exists() {
            return format!("Path does not exist: {}", input.path);
        }
        if !root.is_dir() {
            return format!("Path is not a directory: {}", input.path);
        }
        // Trust boundary: canonicalize and reject sensitive system paths.
        let root = match root.canonicalize() {
            Ok(p) => p,
            Err(e) => return format!("Cannot resolve path: {e}"),
        };
        if crate::paths::is_sensitive_path(&root) {
            return format!(
                "Refused to index sensitive system path: {}.                  Use a project directory instead.",
                root.display()
            );
        }
        // Bounded discovery: a huge NON-sensitive tree (a deep monorepo, a
        // generated-file bomb, a user-pointed scratch dir) can no longer OOM or
        // panic the reload. `discovery::discover_all_files`/`discover_files`
        // enforce a file-count and cumulative-byte ceiling
        // (`SYMFORGE_MAX_INDEX_FILES` / `SYMFORGE_MAX_INDEX_BYTES`, generous
        // defaults) DURING the walk and return a graceful "tree too large to
        // index" error before the in-memory index build commits. The reload
        // below propagates that error to the caller instead of crashing.
        let reset_requested = index_folder_reset_requested();
        let current_root = self.capture_repo_root();
        let idempotency = match input.idempotency_key.as_deref() {
            Some(raw_key) => match crate::idempotency::begin_index_folder_replay(
                &root,
                current_root.as_deref(),
                &root,
                raw_key,
                reset_requested,
            ) {
                Ok(crate::idempotency::ReplayStart::FirstExecution(active)) => Some(active),
                Ok(crate::idempotency::ReplayStart::Replay(response)) => return response,
                Err(error) => return crate::idempotency::format_tool_error(&error),
            },
            None => None,
        };
        let reset_report = if reset_requested {
            match crate::live_index::persist::reset_snapshot_state(&root) {
                Ok(report) => Some(report),
                Err(error) => {
                    let output = format!("Reset failed: {error}");
                    if let Some(idempotency) = &idempotency {
                        let _ = idempotency.fail(output.clone());
                    }
                    return output;
                }
            }
        } else {
            None
        };
        let previous_watcher = self.watcher_handle.lock().take();
        if let Some(previous_watcher) = previous_watcher {
            previous_watcher.stop_token.store(true, Ordering::Release);
            let mut previous_task = previous_watcher.task;
            if tokio::time::timeout(Duration::from_secs(2), &mut previous_task)
                .await
                .is_err()
            {
                tracing::warn!(
                    "watcher: previous watcher did not stop within 2s before index reload"
                );
                previous_task.abort();
            }
        }
        let index = Arc::clone(&self.index);
        let reload_root = root.clone();
        match tokio::task::spawn_blocking(move || index.reload(&reload_root)).await {
            Ok(Ok(())) => {
                if reset_report.is_some() {
                    self.index.mark_index_folder_reset();
                }
                let published = self.index.published_state();
                let file_count = published.file_count;
                let symbol_count = published.symbol_count;

                self.set_repo_root(Some(root.clone()));

                // Restart the file watcher at the new root so freshness continues.
                let watcher_handle = crate::watcher::restart_watcher(
                    root.clone(),
                    Arc::clone(&self.index),
                    Arc::clone(&self.watcher_info),
                    None,
                );
                self.watcher_handle.lock().replace(watcher_handle);
                tracing::info!(root = %root.display(), "file watcher restarted after index_folder");

                // Refresh git temporal data for the new root.
                let expected_gen = self.index.current_project_generation();
                crate::live_index::git_temporal::spawn_git_temporal_computation(
                    Arc::clone(&self.index),
                    root.clone(),
                    expected_gen,
                );

                let mut output = format!("Indexed {} files, {} symbols.", file_count, symbol_count);
                if let Some(reset_report) = reset_report {
                    output.push_str(&format!(
                        "\nReset: scope={} | removed={} | missing={}",
                        crate::live_index::persist::SNAPSHOT_RESET_SCOPE_LABEL,
                        reset_report.removed_count(),
                        reset_report.missing_count()
                    ));
                    let runtime_status = self.runtime_status_for(
                        &published,
                        self.local_runtime_mode(),
                        None,
                        None,
                        Some(root.clone()),
                    );
                    output.push('\n');
                    output.push_str(&format::format_runtime_status(&runtime_status));
                }
                if let Some(idempotency) = &idempotency
                    && let Err(error) = idempotency.complete(output.clone())
                {
                    output.push_str(&format!(
                        "\nIdempotency warning: failed to store replay result: {error}"
                    ));
                }
                self.session_context.record_summary_output(
                    "index_folder",
                    (output.len() / 4).min(u32::MAX as usize) as u32,
                );
                output
            }
            Ok(Err(e)) => {
                let output = format!("Index failed: {e}");
                if let Some(idempotency) = &idempotency {
                    let _ = idempotency.fail(output.clone());
                }
                output
            }
            Err(join_err) => {
                let output = format!("Index failed: reload task panicked: {join_err}");
                if let Some(idempotency) = &idempotency {
                    let _ = idempotency.fail(output.clone());
                }
                output
            }
        }
    }

    /// List changed files: uncommitted=true for working tree, git_ref for ref comparison, since for
    /// timestamp filter. Use to see what files changed.
    /// Set code_only=true to exclude non-source files (docs, configs, lock files).
    /// Set include_symbol_diff=true to also get a symbol-level diff in the same response (git modes only).
    #[tool(
        description = "List changed files: uncommitted=true for working tree, git_ref for ref comparison, since for timestamp filter. Filter with path_prefix and/or language. Set code_only=true to exclude non-source files (docs, configs, lock files). Set include_symbol_diff=true to also include a symbol-level diff in the same response (git_ref and uncommitted modes only), saving a round-trip vs calling diff_symbols separately. NOT for symbol-level change detail alone (use diff_symbols). NOT for finding files by name or content (use search_files or search_text).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn what_changed(&self, params: Parameters<WhatChangedInput>) -> String {
        if let Some(result) = self.proxy_tool_call("what_changed", &params.0).await {
            return result;
        }
        if params.0.estimate == Some(true) {
            let with_diff = params.0.include_symbol_diff.unwrap_or(false);
            let est = if with_diff { 500 } else { 200 };
            return format!(
                "Estimate for what_changed: ~{} tokens (include_symbol_diff={})",
                est, with_diff
            );
        }
        let effective_repo_root = self.effective_repo_root_for_git_tools();
        let requested_git_mode = params.0.uncommitted.unwrap_or(false)
            || params
                .0
                .git_ref
                .as_deref()
                .map(str::trim)
                .is_some_and(|git_ref| !git_ref.is_empty());
        if params.0.since.is_none() && !requested_git_mode && effective_repo_root.is_none() {
            // Surface-aware recovery (TR-02 / FR-012): `index_folder` is gated on
            // the compact surface, so name only callable recovery there. `since=`
            // is always valid and is offered on every surface.
            let attach = match crate::protocol::surface_probe::surface_profile_from_env() {
                crate::protocol::surface_probe::SurfaceProfile::Compact => {
                    "set SYMFORGE_WORKSPACE_ROOT (or run `symforge init`) and reconnect"
                }
                crate::protocol::surface_probe::SurfaceProfile::Full
                | crate::protocol::surface_probe::SurfaceProfile::Meta => {
                    "call index_folder(path=...)"
                }
            };
            return format!("No repo root attached; {attach} or pass since=...");
        }
        let mode = match determine_what_changed_mode(&params.0, effective_repo_root.is_some()) {
            Ok(mode) => mode,
            Err(message) => return message,
        };

        match &mode {
            WhatChangedMode::Timestamp(since_ts) => {
                let view = {
                    let guard = self.index.read();
                    loading_guard!(guard);
                    guard.capture_what_changed_timestamp_view()
                };
                if *since_ts < view.loaded_secs {
                    match filter_paths_by_prefix_and_language(
                        view.paths.clone(),
                        params.0.path_prefix.as_deref(),
                        params.0.language.as_deref(),
                        params.0.code_only.unwrap_or(false),
                    ) {
                        Ok(filtered) => {
                            if filtered.is_empty() {
                                return if view.paths.is_empty() {
                                    "Index is empty — no files tracked.".to_string()
                                } else {
                                    "No indexed files matched the requested filters since the last index load.".to_string()
                                };
                            }
                            let envelope = {
                                let guard = self.index.read();
                                search_format::format_search_envelope(
                                    "exact (timestamp compare)",
                                    what_changed_source_authority_label(&mode),
                                    search_parse_state_for_paths(
                                        &guard,
                                        filtered.iter().map(|path| path.as_str()),
                                    ),
                                    &changed_paths_completeness_label(
                                        view.paths.len(),
                                        filtered.len(),
                                    ),
                                    &what_changed_scope_summary(&params.0, &mode),
                                    &search_paths_evidence(
                                        filtered.iter().map(|path| path.as_str()),
                                    ),
                                )
                            };
                            let output = format::what_changed_paths_result(
                                &filtered,
                                "No indexed files matched the requested filters since the last index load.",
                            );
                            let result = format!("{envelope}\n\n{output}");
                            self.session_context.record_summary_output(
                                "what_changed",
                                (result.len() / 4).min(u32::MAX as usize) as u32,
                            );
                            result
                        }
                        Err(error) => {
                            self.session_context.record_summary_output(
                                "what_changed",
                                (error.len() / 4).min(u32::MAX as usize) as u32,
                            );
                            error
                        }
                    }
                } else {
                    let result = format::what_changed_timestamp_view(&view, *since_ts);
                    self.session_context.record_summary_output(
                        "what_changed",
                        (result.len() / 4).min(u32::MAX as usize) as u32,
                    );
                    result
                }
            }
            WhatChangedMode::Uncommitted => {
                let guard = self.index.read();
                loading_guard!(guard);
                drop(guard);

                let Some(repo_root) = effective_repo_root.as_deref() else {
                    return "Git change detection unavailable; pass `since` for timestamp mode."
                        .to_string();
                };
                let repo = match crate::git::GitRepo::open(repo_root) {
                    Ok(r) => r,
                    Err(e) => return format!("Git change detection failed: {e}"),
                };
                match repo.uncommitted_paths() {
                    Ok(paths) => {
                        let total_paths = paths.len();
                        match filter_paths_by_prefix_and_language(
                            paths,
                            params.0.path_prefix.as_deref(),
                            params.0.language.as_deref(),
                            params.0.code_only.unwrap_or(false),
                        ) {
                            Ok(filtered) => {
                                if filtered.is_empty() {
                                    return if total_paths == 0 {
                                        "No uncommitted changes detected.".to_string()
                                    } else {
                                        "No uncommitted changes matched the requested filters."
                                            .to_string()
                                    };
                                }
                                let include_symbol_diff =
                                    params.0.include_symbol_diff.unwrap_or(false);
                                let envelope = search_format::format_search_envelope(
                                    "exact (uncommitted working tree)",
                                    what_changed_source_authority_label(&mode),
                                    what_changed_parse_state_label(&mode, include_symbol_diff),
                                    &changed_paths_completeness_label(total_paths, filtered.len()),
                                    &what_changed_scope_summary(&params.0, &mode),
                                    &search_paths_evidence(
                                        filtered.iter().map(|path| path.as_str()),
                                    ),
                                );
                                let mut output = format::what_changed_paths_result(
                                    &filtered,
                                    "No uncommitted changes detected.",
                                );
                                if include_symbol_diff {
                                    let changed_refs: Vec<&str> =
                                        filtered.iter().map(|s| s.as_str()).collect();
                                    let sym_diff = format::diff_symbols_result_view(
                                        "HEAD",
                                        "",
                                        &changed_refs,
                                        &repo,
                                        true,
                                        false,
                                    );
                                    output.push_str("\n\n");
                                    output.push_str(&sym_diff);
                                }
                                let result = format!("{envelope}\n\n{output}");
                                self.session_context.record_summary_output(
                                    "what_changed",
                                    (result.len() / 4).min(u32::MAX as usize) as u32,
                                );
                                format::enforce_token_budget(result, params.0.max_tokens)
                            }
                            Err(e) => e,
                        }
                    }
                    Err(e) => format!("Git change detection failed: {e}"),
                }
            }
            WhatChangedMode::GitRef(git_ref) => {
                let guard = self.index.read();
                loading_guard!(guard);
                drop(guard);

                let Some(repo_root) = effective_repo_root.as_deref() else {
                    return "Git change detection unavailable; pass `since` for timestamp mode."
                        .to_string();
                };
                let repo = match crate::git::GitRepo::open(repo_root) {
                    Ok(r) => r,
                    Err(e) => return format!("Git change detection failed: {e}"),
                };
                match repo.changed_paths_from_ref(git_ref) {
                    Ok(paths) => {
                        let total_paths = paths.len();
                        match filter_paths_by_prefix_and_language(
                            paths,
                            params.0.path_prefix.as_deref(),
                            params.0.language.as_deref(),
                            params.0.code_only.unwrap_or(false),
                        ) {
                            Ok(filtered) => {
                                if filtered.is_empty() {
                                    return if total_paths == 0 {
                                        format!(
                                            "No changes detected relative to git ref '{git_ref}'."
                                        )
                                    } else {
                                        format!(
                                            "No changes relative to git ref '{git_ref}' matched the requested filters."
                                        )
                                    };
                                }
                                let include_symbol_diff =
                                    params.0.include_symbol_diff.unwrap_or(false);
                                let envelope = search_format::format_search_envelope(
                                    "exact (git ref diff)",
                                    what_changed_source_authority_label(&mode),
                                    what_changed_parse_state_label(&mode, include_symbol_diff),
                                    &changed_paths_completeness_label(total_paths, filtered.len()),
                                    &what_changed_scope_summary(&params.0, &mode),
                                    &search_paths_evidence(
                                        filtered.iter().map(|path| path.as_str()),
                                    ),
                                );
                                let mut output = format::what_changed_paths_result(
                                    &filtered,
                                    &format!(
                                        "No changes detected relative to git ref '{git_ref}'."
                                    ),
                                );
                                if include_symbol_diff {
                                    let base =
                                        git_ref.strip_prefix("branch:").unwrap_or(git_ref.as_str());
                                    let changed_refs: Vec<&str> =
                                        filtered.iter().map(|s| s.as_str()).collect();
                                    let sym_diff = format::diff_symbols_result_view(
                                        base,
                                        "HEAD",
                                        &changed_refs,
                                        &repo,
                                        true,
                                        false,
                                    );
                                    output.push_str("\n\n");
                                    output.push_str(&sym_diff);
                                }
                                let result = format!("{envelope}\n\n{output}");
                                self.session_context.record_summary_output(
                                    "what_changed",
                                    (result.len() / 4).min(u32::MAX as usize) as u32,
                                );
                                result
                            }
                            Err(e) => e,
                        }
                    }
                    Err(e) => format!("Git change detection failed: {e}"),
                }
            }
        }
    }

    /// Git-aware change impact: merge `base_branch`/`since` ref diffs with
    /// uncommitted working-tree changes into a changed-file set, then walk the
    /// call graph up to `depth` hops to compute a blast radius with per-node
    /// risk tiers. See contracts/detect-impact.md (frozen 2026-06-30).
    #[tool(
        description = "Git-aware change impact analysis. Merges base_branch/since ref diffs with uncommitted working-tree changes (include_untracked, default true) into a changed-file set, then walks the call graph up to depth hops (default 2, max 5 — clamped with a warning above) to compute a blast radius: symbols that transitively call what changed, tiered by hop distance (1=high, 2=medium, 3+=low; an entry point like fn main at hop 1 is critical). scope=symbols (default) returns per-symbol blast entries; scope=files aggregates to file granularity. Response embeds a JSON payload (changed_files, changed_symbols, blast_radius, risk_summary, pagination) after a `--- impact payload ---` marker. Requires a git repository. Does NOT re-index files or bump frecency (use analyze_file_impact for that).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn detect_impact(&self, params: Parameters<DetectImpactInput>) -> String {
        if let Some(result) = self.proxy_tool_call("detect_impact", &params.0).await {
            return result;
        }

        {
            let guard = self.index.read();
            loading_guard!(guard);
        }

        let Some(repo_root) = self.effective_repo_root_for_git_tools() else {
            return "Error: Git unavailable: not inside a git repository. detect_impact requires \
                    git for change detection; use find_dependents or what_changed(since=...) for \
                    non-git impact/change queries."
                .to_string();
        };
        let repo = match crate::git::GitRepo::open(&repo_root) {
            Ok(r) => r,
            Err(e) => return format!("Error: Git unavailable: {e}"),
        };

        let requested_depth = params.0.depth;
        let effective_depth = requested_depth.min(DETECT_IMPACT_MAX_DEPTH);

        // contracts/detect-impact.md § Input: `base_branch` defaults to `main`
        // when the caller supplies neither `base_branch` nor `since`. Without
        // this, the STEL-upgraded path (`route_impact` plans only
        // `{"scope":"files"}`) would silently fall through to uncommitted-only
        // and return an empty blast radius on a clean tree with committed-but-
        // unmerged work — the silent no-op the depth-default already guards
        // against. A repo with no `main` branch degrades to the "Invalid git
        // ref" error below (git2 ref resolution fails), never a panic; pass an
        // explicit `base_branch`/`since` for non-`main` default branches.
        //
        // Wave-1 defect fix (2026-07-02, contracts/detect-impact.md § 2026-07-02
        // addendum): the DEFAULT substitution now prefers `origin/main` over
        // local `main`. A local `main` that lags the remote (e.g. 83 commits
        // behind) produces a confidently-wrong blast radius against a stale base;
        // the shared remote ref is the intended comparison. An EXPLICIT
        // caller-passed `base_branch:"main"` still means local `main` (unchanged).
        // The resolved ref (and any staleness) is disclosed in the response
        // header so the output is self-describing.
        let mut staleness_note: Option<String> = None;
        let base_branch: Option<String> =
            if params.0.base_branch.is_none() && params.0.since.is_none() {
                let origin = repo.resolve_ref_commit("origin/main");
                let local = repo.resolve_ref_commit("main");
                let resolved = match (origin, local) {
                    (Some(origin_oid), Some(local_oid)) => {
                        if origin_oid != local_oid {
                            // Direction-aware disclosure (Wave 1 Fix 3): behind is the
                            // motivating stale-local case; ahead means unpushed local
                            // work landed in the base; both means diverged. `ahead` =
                            // commits in local not in origin; `behind` = the reverse.
                            staleness_note = Some(match repo.ahead_behind(local_oid, origin_oid) {
                                Some((ahead, behind)) if behind > 0 && ahead == 0 => {
                                    "local main is behind origin/main; using origin/main"
                                        .to_string()
                                }
                                Some((ahead, behind)) if ahead > 0 && behind == 0 => {
                                    "local main is ahead of origin/main (unpushed commits); using \
                                 origin/main — the blast radius includes your unpushed work \
                                 relative to the shared base"
                                        .to_string()
                                }
                                Some((ahead, behind)) if ahead > 0 && behind > 0 => {
                                    "local main and origin/main have diverged; using origin/main"
                                        .to_string()
                                }
                                // No common ancestor (or the unreachable both-zero given
                                // origin != local): fall back to the direction-neutral note.
                                _ => "local main differs from origin/main; using origin/main"
                                    .to_string(),
                            });
                        }
                        "origin/main"
                    }
                    (Some(_), None) => "origin/main",
                    // No origin/main (or neither ref exists): fall back to local
                    // `main`. When neither exists, merge_git_changed_paths surfaces
                    // the existing "Invalid git ref" error below, unchanged.
                    (None, _) => "main",
                };
                Some(resolved.to_string())
            } else {
                params.0.base_branch.clone()
            };
        // The base ref disclosed in the response header: the resolved default or
        // the explicit caller value; `None` when only `since` was supplied.
        let base_disclosure: Option<String> = base_branch.clone();

        let changed_files = match repo.merge_git_changed_paths(
            base_branch.as_deref(),
            params.0.since.as_deref(),
            params.0.include_untracked,
        ) {
            Ok(paths) => paths,
            Err(e) => return format!("Error: Invalid git ref: {e}"),
        };

        let (changed_symbols, blast_radius) = {
            let guard = self.index.read();
            let mut changed_symbols: Vec<crate::live_index::graph::SymbolId> = Vec::new();
            for path in &changed_files {
                if let Some(file) = guard.files.get(path) {
                    for sym in &file.symbols {
                        changed_symbols.push(crate::live_index::graph::SymbolId {
                            path: path.clone(),
                            name: sym.name.clone(),
                            kind: sym.kind,
                        });
                    }
                }
            }
            let graph = crate::live_index::graph::GraphProjection::from_index(&guard);
            let blast_radius = crate::live_index::graph::compute_impact(
                &graph,
                &changed_symbols,
                effective_depth as u32,
            );
            (changed_symbols, blast_radius)
        };

        // scope=files aggregates per-symbol blast nodes to file granularity
        // (nearest hop / matching risk wins per file); scope=symbols (default)
        // keeps one entry per symbol.
        let mut blast_entries: Vec<(String, u32, crate::live_index::graph::RiskTier)> =
            match params.0.scope {
                ImpactScope::Symbols => blast_radius
                    .iter()
                    .map(|node| (node.symbol.name.clone(), node.hop, node.risk))
                    .collect(),
                ImpactScope::Files => {
                    let mut by_file: HashMap<String, (u32, crate::live_index::graph::RiskTier)> =
                        HashMap::new();
                    for node in &blast_radius {
                        by_file
                            .entry(node.symbol.path.clone())
                            .and_modify(|(hop, risk)| {
                                if node.hop < *hop {
                                    *hop = node.hop;
                                    *risk = node.risk;
                                }
                            })
                            .or_insert((node.hop, node.risk));
                    }
                    by_file
                        .into_iter()
                        .map(|(path, (hop, risk))| (path, hop, risk))
                        .collect()
                }
            };
        // Fix 1 (Wave 1, 2026-07-02): keep the most severe blast nodes when the
        // list is capped — sort by risk severity desc, then hop asc, then name.
        blast_entries.sort_by(|a, b| {
            b.2.severity_rank()
                .cmp(&a.2.severity_rank())
                .then(a.1.cmp(&b.1))
                .then_with(|| a.0.cmp(&b.0))
        });

        // risk_summary counts the FULL blast set (it is counts, not entries), so
        // it stays complete even though the returned entries are capped.
        let mut risk_counts: HashMap<&'static str, u32> = HashMap::new();
        for (_, _, risk) in &blast_entries {
            *risk_counts.entry(risk.as_str()).or_insert(0) += 1;
        }

        // Fix 1: bound the JSON PAYLOAD — cap each list at DETECT_IMPACT_MAX_RETURNED
        // and disclose the full totals + truncation in `pagination`. This bounds the
        // serialized/emitted entries at 200/list; it does NOT make the tool
        // sub-linear. The changed_symbols collection above, the BFS in
        // compute_impact, the blast clone+sort, and the risk counting all remain
        // O(full set) by necessity: risk_summary and the pagination totals must
        // reflect the COMPLETE set, so everything is still counted. A large explicit
        // diff still costs linear time; what the cap removes is the multi-MB payload
        // (the 54 MB / 291K-entry dump).
        let cap = DETECT_IMPACT_MAX_RETURNED;

        let changed_files_total = changed_files.len();
        let changed_files_json: Vec<&String> = changed_files.iter().take(cap).collect();

        let changed_symbols_total = changed_symbols.len();
        let changed_symbols_json: Vec<serde_json::Value> = changed_symbols
            .iter()
            .take(cap)
            .map(
                |s| serde_json::json!({"name": s.name, "path": s.path, "kind": s.kind.to_string()}),
            )
            .collect();

        let blast_total = blast_entries.len();
        let blast_radius_json: Vec<serde_json::Value> = blast_entries
            .iter()
            .take(cap)
            .map(|(symbol, hop, risk)| serde_json::json!({"symbol": symbol, "hop": hop, "risk": risk.as_str()}))
            .collect();

        let changed_files_returned = changed_files_json.len();
        let changed_symbols_returned = changed_symbols_json.len();
        let blast_returned = blast_radius_json.len();

        let list_page = |total: usize, returned: usize| {
            serde_json::json!({
                "total": total,
                "returned": returned,
                "truncated": total > returned,
            })
        };

        let payload = serde_json::json!({
            "changed_files": changed_files_json,
            "changed_symbols": changed_symbols_json,
            "blast_radius": blast_radius_json,
            "risk_summary": {
                "critical": risk_counts.get("critical").copied().unwrap_or(0),
                "high": risk_counts.get("high").copied().unwrap_or(0),
                "medium": risk_counts.get("medium").copied().unwrap_or(0),
                "low": risk_counts.get("low").copied().unwrap_or(0),
            },
            // Per-list pagination (total / returned / truncated). The frozen
            // contract's flat single-list `pagination` shape did not anticipate
            // the changed_files/changed_symbols explosion; this per-list shape is
            // the honest disclosure (contracts/detect-impact.md § 2026-07-02).
            "pagination": {
                "changed_files": list_page(changed_files_total, changed_files_returned),
                "changed_symbols": list_page(changed_symbols_total, changed_symbols_returned),
                "blast_radius": list_page(blast_total, blast_returned),
            },
        });

        let result = format::detect_impact_result(
            &payload,
            requested_depth,
            effective_depth,
            base_disclosure.as_deref(),
            staleness_note.as_deref(),
        );
        self.session_context.record_summary_output(
            "detect_impact",
            (result.len() / 4).min(u32::MAX as usize) as u32,
        );
        result
    }

    /// Read raw file content. Modes: full file, line range, around_line/around_match/around_symbol,
    /// or chunked paging. Use this for exact docs/config reads, whitespace-sensitive inspection,
    /// or when you need actual source text that other tools don't provide.
    /// For structured understanding use get_file_context. For a single function
    /// body use get_symbol.
    #[tool(
        name = "get_file_content",
        description = "Read exact raw file content. Modes: full file, line range, around_line/around_match/around_symbol, or chunked paging. Use this for exact docs/config reads, whitespace-sensitive inspection, or exact source excerpts after narrowing with get_file_context, search_text, or get_symbol. For structured code understanding use get_file_context first. For a single function body use get_symbol. Accepts offset/limit (Read-tool idiom) as aliases for start_line/end_line. Use max_tokens to request a smaller response budget. Unknown fields are rejected with an error naming the invalid param. Responses are capped at ~60 KB; if truncated, a footer suggests chunk_index+max_lines, around_line, or around_symbol.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn get_file_content_tool(
        &self,
        params: Parameters<GetFileContentInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.get_file_content(params).await;
        let outcome_class = classify_get_file_content_output(&output);
        self.record_tool_completion(
            "get_file_content",
            &output,
            started.elapsed(),
            outcome_class,
        );
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn get_file_content(&self, params: Parameters<GetFileContentInput>) -> String {
        let mut input = params.0;
        input.path = normalize_exact_path(&input.path);
        let explicit_max_tokens = input.max_tokens;

        if let Err(e) = normalize_file_content_aliases(&mut input) {
            return e;
        }

        if let Some(result) = self.proxy_tool_call("get_file_content", &input).await {
            return format::enforce_token_budget(
                format::cap_file_content_output(result),
                explicit_max_tokens,
            );
        }
        // Estimate mode: return token cost without reading content
        if input.estimate == Some(true) {
            let indexed = {
                let guard = self.index.read();
                loading_guard!(guard);
                guard.capture_shared_file(&input.path)
            };
            if let Some(file) = indexed {
                let file_tokens = file.content.len() / 4;
                let line_count = file.content.iter().filter(|&&b| b == b'\n').count();
                return format!(
                    "Estimate for get_file_content(path=\"{}\"):\n  ~{} tokens (~{} lines)",
                    input.path, file_tokens, line_count
                );
            }
            // Not indexed: get_file_content still serves Tier-2 (and other
            // non-source) files via a raw disk read, so the estimate should
            // reflect the disk file rather than reporting "File not found".
            // Reuse the same repo-root containment guard as the main read path.
            if let Some(root) = self.capture_repo_root() {
                match edit::safe_repo_path(&root, &input.path) {
                    Ok(canon_path) if canon_path.is_file() => {
                        if let Ok(metadata) = std::fs::metadata(&canon_path) {
                            let file_tokens = metadata.len() as usize / 4;
                            return format!(
                                "Estimate for get_file_content(path=\"{}\"):\n  ~{} tokens (raw disk read; not indexed)",
                                input.path, file_tokens
                            );
                        }
                    }
                    Err(message) if message.contains("outside the repository") => {
                        return format::path_outside_repo(&input.path);
                    }
                    _ => {}
                }
            }
            return format::not_found_file(&input.path);
        }

        let force_refresh = input.force_refresh == Some(true);
        let params_hash = crate::protocol::session::hash_value(
            &serde_json::to_value(&input).unwrap_or(serde_json::Value::Null),
        );
        if let Some(meta) =
            self.session_context
                .try_file_content_cache_hit(&input.path, params_hash, force_refresh)
        {
            return self.format_read_cache_hit(&meta, "session_repeat_read");
        }

        let options = match file_content_options_from_input(&input) {
            Ok(options) => options,
            Err(message) => return message,
        };
        freshen_exact_path_for_targeted_retrieval(self, &options.path_scope);
        let mode_annotation = match (
            &options.content_context.mode_name,
            options.content_context.mode_explicit,
        ) {
            (Some(mode), true) => format!("── mode: {} (explicit) ──\n", mode),
            _ => String::new(),
        };
        let file = {
            let guard = self.index.read();
            loading_guard!(guard);
            guard.capture_shared_file_for_scope(&options.path_scope)
        };
        match file {
            Some(file) => {
                let raw_chars = file.as_ref().content.len();
                let max_tokens = Some(format::resolve_read_max_tokens(
                    explicit_max_tokens,
                    raw_chars,
                ));
                let output = format::file_content_from_indexed_file_with_context(
                    file.as_ref(),
                    options.content_context,
                );
                self.record_tool_savings_named(
                    "get_file_content",
                    format::estimate_tokens_from_chars(format::competent_manual_baseline_chars(
                        raw_chars,
                    )),
                    (output.len() / 4) as u64,
                );
                let capped =
                    format::cap_file_content_output(format!("{}{}", mode_annotation, output));
                let with_warning = format::append_nul_byte_warning(capped, &file.as_ref().content);
                let mut final_output = format::enforce_token_budget(with_warning, max_tokens);
                let tokens = (final_output.len() / 4) as u32;
                let prior_dedup = if force_refresh {
                    self.session_context.prior_fetch_for_dedup(
                        crate::protocol::session::FetchKind::FileContent,
                        &input.path,
                        "",
                        params_hash,
                    )
                } else {
                    None
                };
                self.session_context
                    .record_file_content_fetch(&input.path, params_hash, tokens);
                self.bump_frecency(&[PathBuf::from(&input.path)]);
                if let Some(prior) = prior_dedup {
                    final_output = format::append_dedup_hint_footer(
                        final_output,
                        "file",
                        prior.fetched_at.elapsed().as_secs(),
                        prior.approx_tokens,
                    );
                }
                final_output
            }
            None => {
                // Not in index — try raw disk read for non-source files
                // (Cargo.toml, package.json, workflow YAMLs, etc.)
                if let Some(root) = self.capture_repo_root() {
                    let canon_path = match edit::safe_repo_path(&root, &input.path) {
                        Ok(p) => p,
                        // Distinguish a containment violation (path escapes the
                        // repo root, e.g. `../../../etc/passwd`) from a genuine
                        // in-repo miss. `safe_repo_path` reports the former with
                        // an "outside the repository" message; surface that
                        // explicitly instead of a misleading "File not found".
                        Err(message) if message.contains("outside the repository") => {
                            return format::path_outside_repo(&input.path);
                        }
                        Err(_) => return format::not_found_file(&input.path),
                    };
                    if canon_path.is_file() {
                        match std::fs::read(&canon_path) {
                            Ok(content) => {
                                let body = format::render_file_content_bytes(
                                    &input.path,
                                    &content,
                                    options.content_context,
                                );
                                // Frecency bump — commitment tool. Raw-disk
                                // fallback branch (non-indexed source files);
                                // collection policy is resolved inside bump_frecency.
                                self.bump_frecency(&[PathBuf::from(&input.path)]);
                                // NUL-byte guard (raw-disk fallback branch):
                                // mirror the indexed branch — warn after the cap.
                                let capped = format::cap_file_content_output(format!(
                                    "{}{}",
                                    mode_annotation, body
                                ));
                                let with_warning =
                                    format::append_nul_byte_warning(capped, &content);
                                let max_tokens = Some(format::resolve_read_max_tokens(
                                    explicit_max_tokens,
                                    content.len(),
                                ));
                                return format::enforce_token_budget(with_warning, max_tokens);
                            }
                            Err(e) => {
                                return format!("{} [error: could not read file: {e}]", input.path);
                            }
                        }
                    }
                }
                // Suggest similar files from the index
                let suggestions = {
                    let guard = self.index.read();
                    suggest_similar_files(&guard, &input.path)
                };
                format::not_found_file_with_suggestions(&input.path, &suggestions)
            }
        }
    }

    /// Find all references or implementations for a symbol. Modes: (1) default/references: call sites,
    /// Validate a file's syntax and surface parser diagnostics with exact locations when available.
    /// Best for malformed TOML/JSON/YAML and other config files where you need authoritative parse errors.
    #[tool(
        description = "Validate a file's syntax and surface parser diagnostics with exact locations when available. Best for malformed TOML/JSON/YAML and other config files where you need authoritative parse errors. Uses the indexed file when available and falls back to direct parsing from disk when needed. NOT for understanding file structure (use get_file_context). NOT for searching file content (use search_text).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn validate_file_syntax(
        &self,
        params: Parameters<ValidateFileSyntaxInput>,
    ) -> String {
        let mut input = params.0;
        input.path = normalize_exact_path(&input.path);

        if let Some(result) = self.proxy_tool_call("validate_file_syntax", &input).await {
            return result;
        }

        let path_scope = search::PathScope::exact(&input.path);
        freshen_exact_path_for_targeted_retrieval(self, &path_scope);

        let indexed_file = {
            let guard = self.index.read();
            // Skip loading_guard here — the disk-read fallback below does not
            // need the index, so we should not block when the index is still loading.
            guard.capture_shared_file(&input.path)
        };
        if let Some(file) = indexed_file {
            let output = format::validate_file_syntax_result(&input.path, file.as_ref());
            self.session_context.record_summary_output(
                "validate_file_syntax",
                (output.len() / 4).min(u32::MAX as usize) as u32,
            );
            return output;
        }

        let extension = std::path::Path::new(&input.path)
            .extension()
            .and_then(|ext| ext.to_str())
            .unwrap_or("");
        let Some(language) = LanguageId::from_extension(extension) else {
            return format!(
                "Syntax validation unavailable for {}: unsupported or unknown file extension.",
                input.path
            );
        };

        let Some(root) = self.capture_repo_root() else {
            return format::not_found_file(&input.path);
        };
        let canon_path = match edit::safe_repo_path(&root, &input.path) {
            Ok(path) => path,
            Err(_) => return format::not_found_file(&input.path),
        };
        if !canon_path.is_file() {
            return format::not_found_file(&input.path);
        }

        let bytes = match std::fs::read(&canon_path) {
            Ok(bytes) => bytes,
            Err(e) => return format!("{} [error: could not read file: {e}]", input.path),
        };
        let classification = crate::domain::FileClassification::for_code_path(&input.path);
        let result = crate::parsing::process_file_with_classification(
            &input.path,
            &bytes,
            language,
            classification,
        );
        let file = IndexedFile::from_parse_result(result, bytes);
        let output = format::validate_file_syntax_result(&input.path, &file);
        self.session_context.record_summary_output(
            "validate_file_syntax",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        output
    }

    /// Find all references or implementations for a symbol. Modes: (1) default/references: call sites,
    /// imports, type usages grouped by file - set compact=true for ~60-75% smaller output. (2) mode='implementations':
    /// find trait/interface implementors bidirectionally - set direction='trait'/'type'/'auto'.
    /// Use when you need 'who calls this?' or 'who implements this?'
    /// NOT for file-level dependencies (use find_dependents).
    /// NOT for full refactoring context (use get_symbol_context with sections=[...]).
    #[tool(
        name = "find_references",
        description = "Find all references or implementations for a symbol. Modes: (1) default/references: call sites, imports, type usages grouped by file - set compact=true for ~60-75% smaller output. (2) mode='implementations': find trait/interface implementors bidirectionally - set direction='trait'/'type'/'auto'. Use when you need 'who calls this?' or 'who implements this?' Large output may CCR-compress; use symforge_retrieve with the footer hash. NOT for file-level dependencies (use find_dependents). NOT for full refactoring context (use get_symbol_context with sections=[...]).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn find_references_tool(
        &self,
        params: Parameters<FindReferencesInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        let started = Instant::now();
        let output = self.find_references(params).await;
        let outcome_class = classify_find_references_output(&output);
        self.record_tool_completion("find_references", &output, started.elapsed(), outcome_class);
        statused_tool_result(output, outcome_class)
    }

    pub(crate) async fn find_references(&self, params: Parameters<FindReferencesInput>) -> String {
        if let Some(result) = self.proxy_tool_call("find_references", &params.0).await {
            return result;
        }
        // Feature 012 (Phase 3): honest refusal for a cross-project request with
        // no daemon (no working set on the local path).
        if let Some(refusal) =
            local_cross_project_refusal(params.0.project.as_deref(), params.0.projects.as_deref())
        {
            return refusal;
        }
        let input = &params.0;
        if let Some(path) = input.path.as_deref() {
            let repo_root = self.capture_repo_root();
            let degraded = {
                let guard = self.index.read();
                loading_guard!(guard);
                admission_tier_degradation_for_path(
                    &guard,
                    repo_root.as_deref(),
                    "find_references",
                    path,
                    &input.name,
                )
            };
            if let Some(result) = degraded {
                return result;
            }
        }
        let mode = input.mode.as_deref().unwrap_or("references");

        if mode == "implementations" {
            let view = {
                let guard = self.index.read();
                loading_guard!(guard);
                guard.capture_implementations_view(&input.name, input.direction.as_deref())
            };
            let cap = input.limit.unwrap_or(200).min(500);
            let limits = format::OutputLimits::new(cap, cap);
            let envelope = if !view.entries.is_empty() {
                let guard = self.index.read();
                Some(search_format::format_search_envelope(
                    find_references_match_type_label(input, mode),
                    "current index",
                    implementations_parse_state_for_paths(&guard, &view),
                    &implementations_completeness_label(&view, &limits),
                    &find_references_scope_summary(input, mode),
                    &implementations_evidence(&view),
                ))
            } else {
                None
            };
            let result = format::implementations_result_view(&view, &input.name, &limits);
            if view.entries.is_empty() {
                let guard = self.index.read();
                let is_concrete = guard.all_files().any(|(_, file)| {
                    file.symbols.iter().any(|s| {
                        s.name == input.name
                            && matches!(
                                s.kind,
                                crate::domain::SymbolKind::Class
                                    | crate::domain::SymbolKind::Struct
                                    | crate::domain::SymbolKind::Enum
                            )
                    })
                });
                if is_concrete {
                    drop(guard);
                    return format!(
                        "No implementations found for \"{}\" — it is a class/struct, not an \
                         interface/trait.\nUse find_references with mode=\"references\" to find \
                         callers and usages instead.",
                        input.name
                    );
                }
                // Check if the symbol exists at all in the indexed project
                let exists_in_project = guard
                    .all_files()
                    .any(|(_, file)| file.symbols.iter().any(|s| s.name == input.name));
                drop(guard);
                if !exists_in_project {
                    return format!(
                        "No implementations found for \"{}\" — this symbol is not defined \
                         in the indexed project (likely from an external dependency).\n\
                         Use search_text to find usages of this symbol in your code instead.",
                        input.name
                    );
                }
            }
            return match envelope {
                Some(envelope) => format!("{envelope}\n\n{result}"),
                None => result,
            };
        }

        let limits =
            format::OutputLimits::new(input.limit.unwrap_or(20), input.max_per_file.unwrap_or(10));
        let collect_qualified_usages = should_collect_qualified_usages(input);
        let (result, indexed_ranges, qualified_usages) = {
            let guard = self.index.read();
            loading_guard!(guard);
            if let Some(path) = input.path.as_deref() {
                (
                    guard.capture_find_references_view_for_symbol(
                        path,
                        &input.name,
                        input.symbol_kind.as_deref(),
                        input.symbol_line,
                        input.kind.as_deref(),
                        limits.total_hits,
                    ),
                    HashSet::new(),
                    Vec::new(),
                )
            } else {
                let kind_filter = find_references_kind_filter(input.kind.as_deref());
                let refs = guard.find_references_for_name(&input.name, kind_filter, false);
                let indexed_ranges = refs
                    .iter()
                    .map(|(file_path, reference)| ((*file_path).to_string(), reference.byte_range))
                    .collect();
                let qualified_usages = if collect_qualified_usages {
                    let files = guard.files.iter().filter_map(|(path, file)| {
                        (file.language == LanguageId::Rust).then_some(
                            qualified_usages::QualifiedFileContent {
                                file_path: path.as_str(),
                                content: file.content.as_slice(),
                            },
                        )
                    });
                    qualified_usages::collect_qualified_usages(&input.name, files)
                } else {
                    Vec::new()
                };
                (
                    Ok(guard.capture_find_references_view(
                        &input.name,
                        input.kind.as_deref(),
                        limits.total_hits,
                    )),
                    indexed_ranges,
                    qualified_usages,
                )
            }
        };
        match result {
            Ok(mut view) => {
                if collect_qualified_usages {
                    merge_qualified_usages_into_view(&mut view, qualified_usages, indexed_ranges);
                }
                let envelope = if !view.files.is_empty() {
                    let guard = self.index.read();
                    Some(search_format::format_search_envelope(
                        find_references_match_type_label(input, mode),
                        "current index",
                        search_parse_state_for_paths(
                            &guard,
                            view.files.iter().map(|file| file.file_path.as_str()),
                        ),
                        &find_references_completeness_label(&view, &limits, input.kind.as_deref()),
                        &find_references_scope_summary(input, mode),
                        &find_references_evidence(&view),
                    ))
                } else {
                    None
                };
                let mut output = if input.compact.unwrap_or(false) {
                    format::find_references_compact_view(&view, &input.name, &limits)
                } else {
                    format::find_references_result_view(&view, &input.name, &limits)
                };

                // Honest disclosure (trust contract): a bare repo-wide name match
                // resolves references by NAME only and silently merges references
                // to DIFFERENT same-named definitions (e.g. a trait method and an
                // unrelated inherent method both named `update_status`). When more
                // than one definition shares the name, say so and tell the caller
                // how to disambiguate, rather than presenting a conflated list as
                // if it were precise. Skipped when `path` is set (the def-scoped
                // resolution already pins the definition) or no refs were found.
                if input.path.is_none() && !view.files.is_empty() {
                    // ponytail: linear all-files scan for same-named defs; only
                    // fires on the no-path branch that already returned hits, so
                    // it is bounded. A reverse symbol-name index would make it
                    // O(1) if this ever shows on a hot path.
                    let def_paths = {
                        let guard = self.index.read();
                        symbol_candidate_paths(&guard, &input.name)
                    };
                    if def_paths.len() > 1 {
                        let preview: Vec<&str> =
                            def_paths.iter().take(5).map(String::as_str).collect();
                        let suffix = if def_paths.len() > preview.len() {
                            format!(", … (+{} more)", def_paths.len() - preview.len())
                        } else {
                            String::new()
                        };
                        output = format!(
                            "Note: {} definitions named \"{}\" exist across the repo ({}{}). \
                             These references are matched by name and MAY MIX usages of different \
                             same-named definitions. Pass `path` (and `symbol_line` if needed) to \
                             scope references to one definition.\n\n{}",
                            def_paths.len(),
                            input.name,
                            preview.join(", "),
                            suffix,
                            output
                        );
                    }
                }

                // Supplemental: if index-based refs are empty, try text search to catch
                // qualified-path calls (e.g., module::func()) that the xref extractor misses.
                // This aligns find_references results with what search_text(follow_refs=true) finds.
                if view.files.is_empty() {
                    let text_options = search::TextSearchOptions::for_current_code_search();
                    let text_result = {
                        let guard = self.index.read();
                        search::search_text_with_options(
                            &guard,
                            Some(&input.name),
                            None,
                            false,
                            &text_options,
                        )
                    };
                    if let Ok(tr) = text_result
                        && !tr.files.is_empty()
                    {
                        output.push_str(&format!(
                            "\n\nNote: no indexed references found, but search_text found {} file(s) \
                             containing \"{}\". The index may miss qualified-path calls (e.g., \
                             module::{}()). Use search_text(query=\"{}\") for full coverage.",
                            tr.files.len(), input.name, input.name, input.name
                        ));
                    }
                }

                self.record_tool_savings_named(
                    "find_references",
                    format::estimate_tokens_from_chars(format::estimate_listing_baseline_chars(
                        output.len(),
                    )),
                    (output.len() / 4) as u64,
                );
                self.session_context.record_summary_output(
                    "find_references",
                    (output.len() / 4).min(u32::MAX as usize) as u32,
                );
                self.session_context.record_listed_symbol("", &input.name);
                let result = match envelope {
                    Some(envelope) => format!("{envelope}\n\n{output}"),
                    None => output,
                };
                self.apply_ccr_budget("find_references", result, params.0.max_tokens)
            }
            Err(error) => error,
        }
    }

    /// File-level dependency graph: which files import the given file. Set compact=true for ~60-75%
    /// smaller output. Supports Mermaid/Graphviz output. Use for "what breaks if I change this file?"
    /// NOT for symbol-level references (use find_references).
    /// NOT for git co-change patterns (use analyze_file_impact with include_co_changes=true).
    #[tool(
        description = "File-level dependency graph: which files import the given file. Set compact=true for ~60-75% smaller output. Supports Mermaid/Graphviz output. Use for 'what breaks if I change this file?' NOT for symbol-level references (use find_references). NOT for git co-change patterns (use analyze_file_impact with include_co_changes=true).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn find_dependents(&self, params: Parameters<FindDependentsInput>) -> String {
        // Symbol-shaped misuse guard: `find_dependents` answers a FILE-level
        // question ("what imports this file?"). A caller passing a `name`
        // alongside `path` wants symbol-level callers and would otherwise get a
        // file-level import graph that reads like symbol callers. Redirect
        // explicitly to `find_references` instead of silently returning the
        // wrong shape. Pure input validation — runs before proxy/index access so
        // it is identical in local and daemon-proxied modes.
        if let Some(name) = params
            .0
            .name
            .as_deref()
            .map(str::trim)
            .filter(|n| !n.is_empty())
        {
            return format!(
                "find_dependents is file-level only (it lists files that import \"{path}\"). \
                 You supplied name=\"{name}\", which is a symbol-level query. \
                 Use find_references(name=\"{name}\") for who calls/uses that symbol, \
                 or call find_dependents with only path=\"{path}\" for the file dependency graph.",
                path = params.0.path,
                name = name,
            );
        }
        if let Some(result) = self.proxy_tool_call("find_dependents", &params.0).await {
            return result;
        }
        let input = &params.0;
        let view = {
            let guard = self.index.read();
            loading_guard!(guard);
            guard.capture_find_dependents_view(&input.path)
        };
        // Default per-file reference detail is capped at 5 lines (not 10) so the
        // non-compact view stays bounded on hub files with dozens of dependents;
        // callers can raise it with max_per_file or switch to compact=true.
        let limits =
            format::OutputLimits::new(input.limit.unwrap_or(20), input.max_per_file.unwrap_or(5));
        let fmt = input.format.as_deref().unwrap_or("text");
        let output = match fmt {
            "mermaid" => format::find_dependents_mermaid(&view, &input.path, &limits),
            "dot" => format::find_dependents_dot(&view, &input.path, &limits),
            _ if input.compact.unwrap_or(false) => {
                format::find_dependents_compact_view(&view, &input.path, &limits)
            }
            _ => format::find_dependents_result_view(&view, &input.path, &limits),
        };
        self.session_context.record_summary_output(
            "find_dependents",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        format::enforce_token_budget(output, params.0.max_tokens)
    }

    /// Extract query terms that aren't part of the matched concept key,
    /// filtering out stopwords and short words.
    fn compute_remainder_terms(query: &str, concept_key: &str) -> Vec<String> {
        const STOPWORDS: &[&str] = &[
            "a", "an", "the", "in", "on", "of", "for", "to", "and", "or", "is", "it", "my", "at",
            "by", "do", "no", "so", "up", "if", "with", "from", "this", "that",
        ];
        let key_words: Vec<&str> = concept_key.split_whitespace().collect();
        query
            .split_whitespace()
            .filter(|w| {
                let lower = w.to_ascii_lowercase();
                !key_words.iter().any(|kw| kw.eq_ignore_ascii_case(w))
                    && !STOPWORDS.contains(&lower.as_str())
                    && lower.len() >= 3
            })
            .map(|w| w.to_ascii_lowercase())
            .collect()
    }

    fn explore_symbol_segments(name: &str) -> Vec<String> {
        let mut segments = Vec::new();
        let mut current = String::new();
        for ch in name.chars() {
            let is_separator =
                !ch.is_alphanumeric() || matches!(ch, '_' | ':' | '-' | '/' | '\\' | '.');
            if is_separator {
                if !current.is_empty() {
                    segments.push(current.to_ascii_lowercase());
                    current.clear();
                }
                continue;
            }

            let split_before = ch.is_uppercase()
                && !current.is_empty()
                && current
                    .chars()
                    .last()
                    .is_some_and(|prev| prev.is_lowercase() || prev.is_ascii_digit());
            if split_before {
                segments.push(current.to_ascii_lowercase());
                current.clear();
            }
            current.push(ch);
        }
        if !current.is_empty() {
            segments.push(current.to_ascii_lowercase());
        }

        segments
    }

    fn explore_fallback_symbol_match(name: &str, term: &str) -> bool {
        if name.eq_ignore_ascii_case(term) {
            return true;
        }

        let segments = Self::explore_symbol_segments(name);
        segments.iter().any(|segment| segment == term)
    }

    fn explore_terms_related(lhs: &str, rhs: &str) -> bool {
        if lhs.eq_ignore_ascii_case(rhs) {
            return true;
        }

        let lhs = lhs.to_ascii_lowercase();
        let rhs = rhs.to_ascii_lowercase();
        let shared_prefix = lhs
            .chars()
            .zip(rhs.chars())
            .take_while(|(a, b)| a == b)
            .count();
        shared_prefix >= 5
    }

    fn record_explore_file_signal(
        file_signals: &mut HashMap<String, ExploreFileSignal>,
        path: &str,
        term: &str,
        weight: u64,
    ) {
        let signal = file_signals.entry(path.to_string()).or_default();
        signal.raw_score += weight;
        signal.matched_terms.insert(term.to_string());
    }

    fn derive_explore_cluster(
        index: &crate::live_index::LiveIndex,
        query_terms: &[String],
        file_signals: &HashMap<String, ExploreFileSignal>,
        limit: usize,
    ) -> Option<DerivedExploreCluster> {
        const GENERIC_SYMBOLS: &[&str] = &[
            "build", "create", "error", "get", "handle", "init", "main", "new", "parse", "process",
            "result", "run", "set", "test", "update",
        ];

        if query_terms.len() < 2 {
            return None;
        }

        let mut ranked_files: Vec<(String, u64, usize)> = file_signals
            .iter()
            .filter_map(|(path, signal)| {
                let file = index.get_file(path)?;
                let coverage = signal.matched_terms.len();
                if coverage < 2 {
                    return None;
                }
                let path_penalty = explore_path_penalty(path, Some(&file.classification));
                let score = (signal.raw_score + ((coverage as u64) * (coverage as u64) * 10))
                    * path_penalty;
                Some((path.clone(), score, coverage))
            })
            .collect();
        ranked_files.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0)));
        ranked_files.truncate(limit.clamp(1, 3));
        if ranked_files.is_empty() {
            return None;
        }

        let mut candidate_scores: HashMap<String, u64> = HashMap::new();
        for (path, file_score, coverage) in &ranked_files {
            let Some(file) = index.get_file(path) else {
                continue;
            };

            for symbol in &file.symbols {
                let lower = symbol.name.to_ascii_lowercase();
                if lower.len() < 4 || GENERIC_SYMBOLS.contains(&lower.as_str()) {
                    continue;
                }

                let segments = Self::explore_symbol_segments(&symbol.name);
                let overlap = query_terms
                    .iter()
                    .filter(|term| {
                        segments
                            .iter()
                            .any(|segment| Self::explore_terms_related(segment, term))
                    })
                    .count();
                if overlap == 0 {
                    continue;
                }

                let kind_bonus = match symbol.kind.to_string().as_str() {
                    "struct" | "class" | "trait" | "interface" | "enum" => 5,
                    "fn" | "method" => 4,
                    "impl" | "mod" | "module" => 3,
                    _ => 1,
                } as u64;
                let reverse_hits = index
                    .reverse_index
                    .get(&symbol.name)
                    .map(|hits| hits.len())
                    .unwrap_or(0);
                let rarity_bonus = match reverse_hits {
                    0 => 8,
                    1..=2 => 6,
                    3..=5 => 4,
                    6..=10 => 2,
                    _ => 1,
                } as u64;
                let length_bonus = (symbol.name.len().min(24) / 6) as u64;
                let score = *file_score
                    + ((*coverage as u64) * 5)
                    + ((overlap as u64) * 12)
                    + kind_bonus
                    + rarity_bonus
                    + length_bonus;

                let entry = candidate_scores.entry(symbol.name.clone()).or_insert(0);
                if score > *entry {
                    *entry = score;
                }
            }
        }

        let mut ranked_symbols: Vec<(String, u64)> = candidate_scores.into_iter().collect();
        ranked_symbols.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0)));
        let promoted_symbols: Vec<String> = ranked_symbols
            .into_iter()
            .take(limit.clamp(1, 4))
            .map(|(name, _)| name)
            .collect();
        if promoted_symbols.is_empty() {
            return None;
        }

        Some(DerivedExploreCluster {
            seed_terms: query_terms.to_vec(),
            promoted_symbols,
            seed_files: ranked_files.into_iter().map(|(path, _, _)| path).collect(),
        })
    }

    fn ask_query_tokens(query: &str) -> Vec<String> {
        let mut tokens = Vec::new();
        for raw in query.split_whitespace() {
            let token = raw
                .trim_matches(|c: char| !c.is_alphanumeric() && c != '_' && c != ':')
                .to_string();
            if token.is_empty() {
                continue;
            }
            if token.len() < 2 {
                continue;
            }
            if tokens
                .iter()
                .any(|existing: &String| existing.eq_ignore_ascii_case(&token))
            {
                continue;
            }
            tokens.push(token);
        }
        tokens
    }

    fn ask_symbol_candidate_tokens(query: &str) -> Vec<String> {
        Self::ask_query_tokens(query)
            .into_iter()
            .filter(|token| {
                let is_symbol_like = token.contains('_')
                    || token.contains("::")
                    || token.chars().skip(1).any(|c| c.is_uppercase());
                is_symbol_like && token.len() >= 4
            })
            .collect()
    }

    fn extract_exact_symbol_understanding_candidate(
        index: &crate::live_index::LiveIndex,
        query: &str,
    ) -> Option<String> {
        const GENERIC_SYMBOLS: &[&str] = &[
            "build", "create", "get", "handle", "init", "main", "new", "parse", "process", "run",
            "set", "test", "update",
        ];

        /// Score a single (path, symbol) match for prominence. Higher = more canonical.
        fn score_match(path: &str, line_start: u32, line_end: u32) -> i32 {
            let mut score = 0i32;
            if path.starts_with("src/") || path.contains("/src/") {
                score += 10;
            }
            let lower = path.to_ascii_lowercase();
            if !lower.contains("test")
                && !lower.contains("vendor")
                && !lower.contains("example")
                && !lower.contains("bench")
            {
                score += 5;
            }
            let span = line_end.saturating_sub(line_start);
            score += ((span / 10) as i32).min(10);
            score
        }

        /// Search `index` for an exact (case-insensitive) match for `token`.
        /// Returns `Some((canonical_name, best_score))` when 1-5 matches are found.
        fn find_token(index: &crate::live_index::LiveIndex, token: &str) -> Option<(String, i32)> {
            let mut matches: Vec<(String, i32)> = Vec::new(); // (canonical_name, score)
            for (path, file) in index.all_files() {
                for symbol in &file.symbols {
                    if symbol.name.eq_ignore_ascii_case(token) {
                        let s =
                            score_match(path.as_str(), symbol.line_range.0, symbol.line_range.1);
                        matches.push((symbol.name.clone(), s));
                    }
                }
            }
            if matches.is_empty() || matches.len() > 5 {
                return None;
            }
            // Pick the match with the highest score; stable (first wins on tie).
            let best = matches
                .into_iter()
                .max_by_key(|(_, score)| *score)
                .expect("non-empty; guarded by is_empty check above");
            Some(best)
        }

        // Collect (canonical_name, score) for each qualifying token.
        let mut candidates: Vec<(String, i32)> = Vec::new();
        let tokens = Self::ask_symbol_candidate_tokens(query);
        for token in &tokens {
            if GENERIC_SYMBOLS.contains(&token.to_ascii_lowercase().as_str()) {
                continue;
            }
            if let Some(hit) = find_token(index, token) {
                candidates.push(hit);
            }
        }

        // Compound token joining: try "token_a_token_b" for adjacent pairs when
        // no single-token candidate was found yet.
        if candidates.is_empty() && tokens.len() >= 2 {
            for window in tokens.windows(2) {
                let joined = format!("{}_{}", window[0], window[1]);
                if GENERIC_SYMBOLS.contains(&joined.to_ascii_lowercase().as_str()) {
                    continue;
                }
                if let Some(hit) = find_token(index, &joined) {
                    candidates.push(hit);
                }
            }
        }

        if candidates.is_empty() {
            return None;
        }

        // Deduplicate by canonical name, keeping the entry with the highest score.
        candidates.sort_by(|a, b| a.0.cmp(&b.0).then(b.1.cmp(&a.1)));
        candidates.dedup_by(|later, first| {
            // `dedup_by` drops `later` when true is returned.  The sort above orders ascending
            // by name, then descending by score within each name group, so `first` always holds
            // the highest score for a given name — exactly the entry we want to keep.
            later.0.eq_ignore_ascii_case(&first.0)
        });

        // Pick the single candidate with the highest prominence score.
        candidates
            .into_iter()
            .max_by_key(|(_, score)| *score)
            .map(|(name, _)| name)
    }

    fn extract_exact_implementation_understanding_candidate(
        index: &crate::live_index::LiveIndex,
        query: &str,
    ) -> Option<String> {
        const IMPLEMENTATION_CUES: &[&str] = &[
            "type",
            "types",
            "implementation",
            "implementations",
            "implementor",
            "implementors",
            "implementer",
            "implementers",
            "implements",
        ];
        const GENERIC_QUERY_WORDS: &[&str] = &[
            "a",
            "all",
            "an",
            "and",
            "are",
            "describe",
            "does",
            "explain",
            "help",
            "how",
            "main",
            "me",
            "of",
            "the",
            "through",
            "tell",
            "type",
            "types",
            "understand",
            "walk",
            "what",
            "work",
        ];
        let tokens = Self::ask_query_tokens(query);
        if !tokens.iter().any(|token| {
            IMPLEMENTATION_CUES
                .iter()
                .any(|cue| token.eq_ignore_ascii_case(cue))
        }) {
            return None;
        }

        let mut candidates = Vec::new();
        for token in tokens {
            let lower = token.to_ascii_lowercase();
            if GENERIC_QUERY_WORDS.contains(&lower.as_str()) {
                continue;
            }

            if let Some(candidate) = Self::exact_trait_like_symbol_candidate(index, &token) {
                candidates.push(candidate);
                continue;
            }

            if lower.ends_with('s') && lower.len() > 4 {
                let singular = &token[..token.len() - 1];
                if let Some(candidate) = Self::exact_trait_like_symbol_candidate(index, singular) {
                    candidates.push(candidate);
                }
            }
        }

        candidates.sort();
        candidates.dedup();
        if candidates.len() == 1 {
            candidates.into_iter().next()
        } else {
            None
        }
    }

    fn exact_trait_like_symbol_candidate(
        index: &crate::live_index::LiveIndex,
        token: &str,
    ) -> Option<String> {
        let mut exact_match_count = 0usize;
        let mut canonical_name: Option<String> = None;
        for (_path, file) in index.all_files() {
            for symbol in &file.symbols {
                if !symbol.name.eq_ignore_ascii_case(token) {
                    continue;
                }
                if !matches!(
                    symbol.kind,
                    crate::domain::index::SymbolKind::Trait
                        | crate::domain::index::SymbolKind::Interface
                        | crate::domain::index::SymbolKind::Type
                ) {
                    continue;
                }
                exact_match_count += 1;
                if canonical_name.is_none() {
                    canonical_name = Some(symbol.name.clone());
                }
            }
        }

        if exact_match_count == 1 {
            canonical_name
        } else {
            None
        }
    }

    /// Start here when you don't know where to look. Accepts a natural-language concept
    /// and returns related symbols, patterns, and files. Set depth=2 for signatures and
    /// callers of top symbols (~1500 tokens). Set depth=3 for implementations and type
    /// dependency chains (~3000 tokens). NOT for finding a specific symbol by name
    /// (use search_symbols). NOT for text content search (use search_text).
    #[tool(
        description = "Use this when you have a concept or topic but not a specific file or symbol name. Accepts a natural-language concept and returns related symbols, patterns, and files. Set depth=2 for signatures and callers of top symbols (~1500 tokens). Set depth=3 for implementations and type dependency chains (~3000 tokens). Large output may CCR-compress; use symforge_retrieve with the footer hash. NOT for finding a specific symbol by name (use search_symbols). NOT for text content search (use search_text).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn explore(&self, params: Parameters<ExploreInput>) -> String {
        if let Some(result) = self.proxy_tool_call("explore", &params.0).await {
            return result;
        }
        if params.0.estimate == Some(true) {
            let depth = params.0.depth.unwrap_or(1);
            let est = match depth {
                1 => 500,
                2 => 1500,
                _ => 3000,
            };
            return format!("Estimate for explore: ~{} tokens (depth={})", est, depth);
        }
        let lang_filter = match parse_language_filter(params.0.language.as_deref()) {
            Ok(f) => f,
            Err(e) => return e,
        };
        let limit = params.0.limit.unwrap_or(10) as usize;
        let include_noise = params.0.include_noise.unwrap_or(false);
        let include_vendor = params.0.include_vendor.unwrap_or(false);
        let include_personal_tooling = params.0.include_personal_tooling.unwrap_or(false);
        // B1 additive: vendor surfaces when include_noise OR include_vendor is true;
        // personal-tooling surfaces when include_noise OR include_personal_tooling.
        let suppress_vendor = !(include_noise || include_vendor);
        let suppress_personal = !(include_noise || include_personal_tooling);
        let suppress_other_noise = !include_noise;
        let any_suppression = suppress_vendor || suppress_personal || suppress_other_noise;
        let guard = self.index.read();
        loading_guard!(guard);

        let concept = super::explore::match_concept(&params.0.query);

        // A single-word concept that matched ONLY via the stemmed fallback is a
        // weak signal: the query never named the concept verbatim. When the query
        // also carries specific terms (computed below) the header should let those
        // terms lead and demote such a concept to a parenthetical hint, rather than
        // collapsing the topic to a label the user did not type. Exact matches and
        // multi-word concept keys keep leading the header.
        let demote_stem_only_concept = matches!(
            concept,
            Some((key, _, super::explore::ConceptMatchKind::Stemmed))
                if key.split_whitespace().count() == 1
        );

        let mut enriched_imports: Vec<String> = Vec::new();
        let (label, symbol_queries, text_queries, remainder_terms) = if let Some((key, c, _)) =
            concept
        {
            let remainder = Self::compute_remainder_terms(&params.0.query, key);
            let mut sym_q: Vec<String> = c.symbol_queries.iter().map(|s| s.to_string()).collect();
            // Convention-aware enrichment: add project-specific imports related to the concept.
            let project_imports =
                crate::protocol::conventions::extract_top_import_roots(&guard, 100);
            let enrichment = super::explore::enrich_concept_with_imports(c, &project_imports);
            enriched_imports = enrichment;
            sym_q.extend(enriched_imports.iter().cloned());
            (
                c.label.to_string(),
                sym_q,
                c.text_queries
                    .iter()
                    .map(|s| s.to_string())
                    .collect::<Vec<_>>(),
                remainder,
            )
        } else {
            let terms = super::explore::fallback_terms(&params.0.query);
            if terms.is_empty() {
                return "Explore requires a non-empty query.".to_string();
            }
            (
                format!("'{}'", params.0.query),
                terms.clone(),
                terms,
                vec![],
            )
        };

        // Phase 1: Symbol search — over-fetch and track both match counts and
        // query-term coverage per symbol so multi-term hits outrank one-term noise.
        let mut match_scores: HashMap<(String, String, String), ExploreMatchScore> = HashMap::new();
        let mut file_signals: HashMap<String, ExploreFileSignal> = HashMap::new();

        // Phase 0: Module-path boosting — symbols from files whose path segment
        // matches a query term get a weight boost. +2 for exact segment match,
        // +1 for substring segment match. Per-directory cap of `limit` symbols.
        // For concept+remainder queries, boost on remainder terms only so path-scoping
        // is driven by the narrowing terms (e.g., "watcher" in "error handling in the watcher").
        let boost_terms = if remainder_terms.is_empty() {
            symbol_queries.clone()
        } else {
            remainder_terms.clone()
        };
        for term in &boost_terms {
            let term_lower = term.to_ascii_lowercase();
            for (file_path, file) in guard.all_files() {
                if explore_should_skip_path_boost(
                    file_path,
                    &file.classification,
                    include_noise,
                    include_vendor,
                    include_personal_tooling,
                ) {
                    continue;
                }
                let segments: Vec<&str> = file_path.split(&['/', '\\'][..]).collect();
                let best_match = segments
                    .iter()
                    .filter_map(|seg| {
                        let seg_lower = seg.to_ascii_lowercase();
                        let seg_stem = seg_lower
                            .strip_suffix(".rs")
                            .or_else(|| seg_lower.strip_suffix(".py"))
                            .or_else(|| seg_lower.strip_suffix(".ts"))
                            .or_else(|| seg_lower.strip_suffix(".js"))
                            .or_else(|| seg_lower.strip_suffix(".go"))
                            .unwrap_or(&seg_lower);
                        if seg_stem == term_lower {
                            Some(2usize)
                        } else if seg_stem.contains(&*term_lower) {
                            Some(1usize)
                        } else {
                            None
                        }
                    })
                    .max();
                if let Some(weight) = best_match {
                    Self::record_explore_file_signal(
                        &mut file_signals,
                        file_path,
                        &term_lower,
                        weight as u64,
                    );
                    for (injected, sym) in file.symbols.iter().enumerate() {
                        if injected >= limit {
                            break;
                        }
                        let entry = (sym.name.clone(), sym.kind.to_string(), file_path.clone());
                        let score = match_scores.entry(entry).or_default();
                        if score.raw_count == 0 {
                            // Cap path-boost: only seed symbols that have no prior
                            // matches. This prevents path-matching files from
                            // dominating over content-matching files.
                            score.raw_count = weight.min(1);
                        }
                        score.matched_terms.insert(term_lower.clone());
                    }
                }
            }
        }

        // Merge remainder terms into symbol/text queries for Phases 1-2 so that compound
        // queries like "error handling in the watcher" search concept queries AND "watcher".
        let mut all_symbol_queries = symbol_queries.clone();
        all_symbol_queries.extend(remainder_terms.iter().cloned());
        let mut all_text_queries = text_queries.clone();
        all_text_queries.extend(remainder_terms.iter().cloned());

        // Lowercased remainder terms drive "specific term" detection below: a
        // remainder noun that matches an indexed symbol name (e.g. "admission"
        // -> AdmissionTier) must never be outranked by the concept bucket's
        // generic symbol_queries (e.g. "index"), and it should keep the topic
        // visible in the header instead of collapsing it to the concept label.
        let remainder_term_keys: HashSet<String> = remainder_terms
            .iter()
            .map(|t| t.to_ascii_lowercase())
            .collect();
        // Remainder terms that actually resolve to an indexed symbol name via
        // search_symbols' substring semantics. Populated during the symbol
        // search loop so we don't pay for a second index pass.
        let mut specific_terms: HashSet<String> = HashSet::new();

        let fallback_mode = concept.is_none();
        for sq in &all_symbol_queries {
            let term_key = sq.to_ascii_lowercase();
            let result = search::search_symbols(&guard, sq, None, limit * 3);
            let is_remainder_term = remainder_term_keys.contains(&term_key);
            let mut seen_paths = HashSet::new();
            for hit in &result.hits {
                if fallback_mode && !Self::explore_fallback_symbol_match(&hit.name, &term_key) {
                    continue;
                }
                // A remainder noun that lands on a real symbol name is a
                // load-bearing query term, not generic concept noise.
                if !fallback_mode && is_remainder_term {
                    specific_terms.insert(term_key.clone());
                }
                let entry = (hit.name.clone(), hit.kind.clone(), hit.path.clone());
                let score = match_scores.entry(entry).or_default();
                score.raw_count += 1;
                score.matched_terms.insert(term_key.clone());
                if seen_paths.insert(hit.path.clone()) {
                    Self::record_explore_file_signal(&mut file_signals, &hit.path, &term_key, 2);
                }
            }
        }

        // Filter Phase 1 results by language and path_prefix
        if lang_filter.is_some() || params.0.path_prefix.is_some() {
            match_scores.retain(|(_, _, path), _| {
                if let Some(ref prefix) = params.0.path_prefix
                    && !path.starts_with(prefix.as_str())
                {
                    return false;
                }
                if let Some(ref lang) = lang_filter {
                    let ext = path.rsplit('.').next().unwrap_or("");
                    if crate::domain::index::LanguageId::from_extension(ext).as_ref() != Some(lang)
                    {
                        return false;
                    }
                }
                true
            });
            file_signals.retain(|path, _| {
                if let Some(ref prefix) = params.0.path_prefix
                    && !path.starts_with(prefix.as_str())
                {
                    return false;
                }
                if let Some(ref lang) = lang_filter {
                    let ext = path.rsplit('.').next().unwrap_or("");
                    if crate::domain::index::LanguageId::from_extension(ext).as_ref() != Some(lang)
                    {
                        return false;
                    }
                }
                true
            });
        }

        if any_suppression {
            file_signals.retain(|path, _| {
                let Some(file) = guard.get_file(path) else {
                    return false;
                };
                if suppress_other_noise
                    && explore_is_test_like_path(path, Some(&file.classification))
                {
                    return false;
                }
                if suppress_personal && crate::live_index::query::is_personal_tooling_path(path) {
                    return false;
                }
                let class = search::NoisePolicy::classify_path(path, None);
                match class {
                    search::NoiseClass::Vendor => !suppress_vendor,
                    search::NoiseClass::Generated | search::NoiseClass::Ignored => {
                        !suppress_other_noise
                    }
                    search::NoiseClass::None => true,
                }
            });
        }

        // Phase 2: Text search — collect text hits and inject enclosing symbols into match_counts
        let mut text_hits: Vec<(String, String, usize)> = Vec::new(); // (path, line, line_number)
        for tq in &all_text_queries {
            let mut options = search::TextSearchOptions {
                total_limit: limit.min(50),
                max_per_file: limit, // need enough matches per file for enclosing symbol extraction
                ..search::TextSearchOptions::for_current_code_search()
            };
            if let Some(ref prefix) = params.0.path_prefix {
                options.path_scope = search::PathScope::Prefix(prefix.clone());
            }
            if let Some(ref lang) = lang_filter {
                options.language_filter = Some(lang.clone());
            }
            let result = search::search_text_with_options(&guard, Some(tq), None, false, &options);
            if let Ok(r) = result {
                let term_key = tq.to_ascii_lowercase();
                for file in &r.files {
                    // SF-STRESS-013: require a word-boundary match so a concept
                    // idiom like `try {` does not score off `Country {`. Filter
                    // before recording the file signal so coincidental files do
                    // not register at all.
                    let boundary_matches: Vec<&search::TextLineMatch> = file
                        .matches
                        .iter()
                        .filter(|m| concept_text_query_matches_on_boundary(&m.line, tq))
                        .collect();
                    if boundary_matches.is_empty() {
                        continue;
                    }
                    Self::record_explore_file_signal(&mut file_signals, &file.path, &term_key, 3);
                    for m in boundary_matches {
                        if text_hits.len() < limit && !format::is_noise_line(&m.line) {
                            text_hits.push((file.path.clone(), m.line.clone(), m.line_number));
                        }
                        // Inject enclosing symbol into match_counts.
                        // Weight 2 so content matches outweigh path-only boosts.
                        if let Some(ref enc) = m.enclosing_symbol {
                            let entry = (enc.name.clone(), enc.kind.clone(), file.path.clone());
                            let score = match_scores.entry(entry).or_default();
                            score.raw_count += 2;
                            score.matched_terms.insert(term_key.clone());
                        }
                    }
                }
            }
        }

        // Filter text hits by path_prefix (language already handled via TextSearchOptions)
        if let Some(ref prefix) = params.0.path_prefix {
            text_hits.retain(|(path, _, _)| path.starts_with(prefix.as_str()));
        }

        let derived_cluster = if fallback_mode {
            Self::derive_explore_cluster(&guard, &symbol_queries, &file_signals, limit)
        } else {
            None
        };

        if let Some(cluster) = &derived_cluster {
            for derived_query in &cluster.promoted_symbols {
                let term_key = derived_query.to_ascii_lowercase();
                if !all_symbol_queries
                    .iter()
                    .any(|existing| existing.eq_ignore_ascii_case(derived_query))
                {
                    let result = search::search_symbols(&guard, derived_query, None, limit * 2);
                    let mut seen_paths = HashSet::new();
                    for hit in &result.hits {
                        let entry = (hit.name.clone(), hit.kind.clone(), hit.path.clone());
                        let score = match_scores.entry(entry).or_default();
                        score.raw_count += 1;
                        score.matched_terms.insert(term_key.clone());
                        if seen_paths.insert(hit.path.clone()) {
                            Self::record_explore_file_signal(
                                &mut file_signals,
                                &hit.path,
                                &term_key,
                                2,
                            );
                        }
                    }
                }

                let mut options = search::TextSearchOptions {
                    total_limit: limit.min(50),
                    max_per_file: limit,
                    ..search::TextSearchOptions::for_current_code_search()
                };
                if let Some(ref prefix) = params.0.path_prefix {
                    options.path_scope = search::PathScope::Prefix(prefix.clone());
                }
                if let Some(ref lang) = lang_filter {
                    options.language_filter = Some(lang.clone());
                }

                if let Ok(result) = search::search_text_with_options(
                    &guard,
                    Some(derived_query),
                    None,
                    false,
                    &options,
                ) {
                    for file in &result.files {
                        if !file.matches.is_empty() {
                            Self::record_explore_file_signal(
                                &mut file_signals,
                                &file.path,
                                &term_key,
                                2,
                            );
                        }
                        for m in &file.matches {
                            if text_hits.len() < limit && !format::is_noise_line(&m.line) {
                                text_hits.push((file.path.clone(), m.line.clone(), m.line_number));
                            }
                            if let Some(ref enc) = m.enclosing_symbol {
                                let entry = (enc.name.clone(), enc.kind.clone(), file.path.clone());
                                let score = match_scores.entry(entry).or_default();
                                score.raw_count += 1;
                                score.matched_terms.insert(term_key.clone());
                            }
                        }
                    }
                }
            }
        }

        // Phase 3: Filter noise, weight by kind and path, sort, truncate to limit.
        // Exclude explore.rs itself (CONCEPT_MAP contains concept keywords in its body).
        match_scores.retain(|(_, _, path), _| !path.ends_with("protocol/explore.rs"));

        // Score each symbol: match_count * kind_weight, penalized for doc/generated files.
        let scored: Vec<((String, String, String), u64)> = match_scores
            .into_iter()
            .map(|((name, kind, path), score_data)| {
                // Kind weight: definition-like symbols rank higher than incidental matches.
                let kind_weight: u64 = match kind.as_str() {
                    "fn" | "method" => 4,
                    "struct" | "class" | "trait" | "interface" | "enum" => 4,
                    "impl" | "mod" | "module" => 3,
                    "const" | "type" => 2,
                    "variable" | "let" => 1,
                    "key" | "section" => 1,
                    _ => 2, // "other" (selectors, etc.)
                };
                let classification = guard.get_file(&path).map(|file| &file.classification);
                let path_penalty = explore_path_penalty(&path, classification);
                // Specific remainder terms (query nouns that resolved to a real
                // indexed symbol name, e.g. "admission" -> AdmissionTier) are
                // load-bearing, not generic concept noise. Each one counts as
                // two extra terms toward coverage: enough that a single specific
                // noun outranks a generic two-term concept-bucket hit (the
                // failure this fix targets), but a symbol with genuine
                // three-plus-term co-occurrence still wins. This only affects
                // concept mode; fallback mode never populates the set.
                let specific_match_count = score_data
                    .matched_terms
                    .iter()
                    .filter(|term| specific_terms.contains(*term))
                    .count() as u64;
                let effective_terms =
                    score_data.matched_terms.len() as u64 + 2 * specific_match_count;
                let coverage_bonus: u64 = match effective_terms {
                    0 | 1 => 1,
                    n => n * n,
                };
                let alignment_multiplier = if fallback_mode {
                    explore_fallback_alignment_multiplier(
                        symbol_queries.len(),
                        score_data.matched_terms.len(),
                    )
                } else {
                    8
                };
                let score = (score_data.raw_count as u64)
                    * kind_weight
                    * path_penalty
                    * coverage_bonus
                    * alignment_multiplier;
                ((name, kind, path), score)
            })
            .collect();

        // Noise filtering: hide vendor / generated / gitignored / personal-tooling
        // by default. include_noise is the umbrella; include_vendor and
        // include_personal_tooling are additive finer-grained overrides per B1.
        let mut noise_hidden: usize = 0;
        let should_hide_path = |path: &str| -> bool {
            let Some(file) = guard.get_file(path) else {
                return true;
            };
            if suppress_other_noise && explore_is_test_like_path(path, Some(&file.classification)) {
                return true;
            }
            if suppress_personal && crate::live_index::query::is_personal_tooling_path(path) {
                return true;
            }
            let class = search::NoisePolicy::classify_path(path, None);
            match class {
                search::NoiseClass::Vendor => suppress_vendor,
                search::NoiseClass::Generated | search::NoiseClass::Ignored => suppress_other_noise,
                search::NoiseClass::None => false,
            }
        };

        let mut ranked = scored;
        ranked.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.0.cmp(&b.0.0)));
        // Filter out weak matches (score < 8 means single text-only hit in a doc file).
        ranked.retain(|(_, score)| *score >= 8);
        // SF-STRESS-013: drop hidden vendor/generated/test symbols BEFORE the
        // limit truncation so they no longer consume the result budget. Running
        // the noise filter after truncate starved real results (e.g. 1 visible
        // symbol while 19 hidden vendor symbols had already eaten the limit).
        if any_suppression {
            ranked.retain(|(key, _)| {
                let hide = should_hide_path(&key.2);
                if hide {
                    noise_hidden += 1;
                }
                !hide
            });
        }
        ranked.truncate(limit);
        let max_score = ranked.first().map(|(_, s)| *s as f32).unwrap_or(1.0);
        let symbol_scores: Vec<f32> = ranked
            .iter()
            .map(|(_, s)| {
                if max_score > 0.0 {
                    (*s as f32 / max_score).min(1.0)
                } else {
                    0.0
                }
            })
            .collect();
        let symbol_hits: Vec<(String, String, String)> =
            ranked.into_iter().map(|(k, _)| k).collect();

        // Text hits still pass through the same noise filter so hidden files
        // never leak into the rendered pattern list.
        let text_hits = if any_suppression {
            text_hits
                .into_iter()
                .filter(|(path, _, _)| {
                    let hide = should_hide_path(path);
                    if hide {
                        noise_hidden += 1;
                    }
                    !hide
                })
                .collect::<Vec<_>>()
        } else {
            text_hits
        };

        // Count files by symbol/text presence
        let mut file_counts: std::collections::HashMap<String, usize> =
            std::collections::HashMap::new();
        for (_, _, path) in &symbol_hits {
            *file_counts.entry(path.clone()).or_default() += 1;
        }
        for (path, _, _) in &text_hits {
            *file_counts.entry(path.clone()).or_default() += 1;
        }
        let mut related_files: Vec<(String, usize)> = file_counts.into_iter().collect();
        related_files.sort_by_key(|(_, count)| std::cmp::Reverse(*count));
        related_files.truncate(limit);

        // Depth 2+: enrich top symbol hits with signatures and dependents
        let depth = params.0.depth.unwrap_or(1).clamp(1, 3);
        let mut enriched_symbols: Vec<format::ExploreEnrichedSymbol> = Vec::new();
        // (name, kind, path, signature, dependent_files)

        if depth >= 2 {
            let enrich_limit = 5.min(symbol_hits.len());
            for (name, kind, path) in &symbol_hits[..enrich_limit] {
                let signature = guard.get_file(path).and_then(|file| {
                    let sym = file.symbols.iter().find(|s| {
                        s.name == *name && s.kind.to_string().eq_ignore_ascii_case(kind)
                    })?;
                    let body = std::str::from_utf8(
                        &file.content[sym.byte_range.0 as usize..sym.byte_range.1 as usize],
                    )
                    .ok()?;
                    Some(format::apply_verbosity(body, "signature"))
                });

                let dependents = {
                    let ref_view = guard.capture_find_references_view(name, None, 3);
                    ref_view
                        .files
                        .iter()
                        .take(3)
                        .map(|f| f.file_path.clone())
                        .collect()
                };

                enriched_symbols.push((
                    name.clone(),
                    kind.clone(),
                    path.clone(),
                    signature,
                    dependents,
                ));
            }
        }

        // Depth 3: gather implementations AND type dependencies for top symbols
        let mut symbol_impls: Vec<(String, Vec<String>)> = Vec::new();
        let mut symbol_deps: Vec<(String, Vec<String>)> = Vec::new();
        if depth >= 3 {
            let impl_limit = 3.min(enriched_symbols.len());
            for (name, _kind, path, _, _) in &enriched_symbols[..impl_limit] {
                // Implementations (trait → implementors)
                let impl_view = guard.capture_implementations_view(name, None);
                let impl_names: Vec<String> = impl_view
                    .entries
                    .iter()
                    .take(5)
                    .map(|e| {
                        format!(
                            "{} impl {} ({}:{})",
                            e.implementor, e.trait_name, e.file_path, e.line
                        )
                    })
                    .collect();
                if !impl_names.is_empty() {
                    symbol_impls.push((name.clone(), impl_names));
                }

                // Type dependencies (what types does this symbol reference?)
                let bundle = guard.capture_context_bundle_view(path, name, None, None);
                if let crate::live_index::query::ContextBundleView::Found(found) = bundle {
                    let dep_names: Vec<String> = found
                        .dependencies
                        .iter()
                        .take(8)
                        .map(|d| format!("{} {} ({})", d.kind_label, d.name, d.file_path))
                        .collect();
                    if !dep_names.is_empty() {
                        symbol_deps.push((name.clone(), dep_names));
                    }
                }
            }
        }

        // When a concept matched but the query also named specific terms that
        // resolve to indexed symbols, keep those nouns visible in the header so
        // the topic isn't silently collapsed to the generic concept label.
        // Order by query position (remainder_terms preserves it) for stability.
        let display_label = if !specific_terms.is_empty() {
            let ordered: Vec<&str> = remainder_terms
                .iter()
                .filter(|t| specific_terms.contains(t.as_str()))
                .map(|t| t.as_str())
                .collect();
            if demote_stem_only_concept {
                // The concept matched only via a single-word stem misfire (e.g.
                // "indexed" -> "Indexing") while the query named real terms. Lead
                // with those specific terms and demote the concept to an honest
                // parenthetical hint, instead of letting a label the user never
                // typed front the header.
                format!("{} (+ {label} signals)", ordered.join(", "))
            } else {
                format!("{label} + {}", ordered.join(", "))
            }
        } else {
            label.clone()
        };

        let mut output = format::explore_result_view(format::ExploreResultViewInput {
            label: &display_label,
            symbol_hits: &symbol_hits,
            text_hits: &text_hits,
            related_files: &related_files,
            enriched_symbols: &enriched_symbols,
            symbol_impls: &symbol_impls,
            symbol_deps: &symbol_deps,
            derived_seed_terms: derived_cluster
                .as_ref()
                .map(|cluster| cluster.seed_terms.as_slice())
                .unwrap_or(&[]),
            derived_symbols: derived_cluster
                .as_ref()
                .map(|cluster| cluster.promoted_symbols.as_slice())
                .unwrap_or(&[]),
            enriched_imports: &enriched_imports,
            symbol_scores: &symbol_scores,
            derived_seed_files: derived_cluster
                .as_ref()
                .map(|cluster| cluster.seed_files.as_slice())
                .unwrap_or(&[]),
            depth,
        });

        if noise_hidden > 0 {
            output.push_str(&format!(
                "\n\nNote: {noise_hidden} result(s) from vendor/generated files hidden. Use include_noise=true to include."
            ));
        }

        if !output.is_empty() {
            // SF-STRESS-013: the explore scorer computes match count, kind
            // weight, term-coverage and path proximity — it does NOT compute
            // caller density. Drop the inaccurate claim so the footer is honest.
            output
                .push_str("\n\nranked by: concept match + symbol-token alignment + path proximity");
        }

        self.record_tool_savings_named(
            "explore",
            format::estimate_tokens_from_chars(format::estimate_listing_baseline_chars(
                output.len(),
            )),
            (output.len() / 4) as u64,
        );
        self.session_context
            .record_summary_output("explore", (output.len() / 4).min(u32::MAX as usize) as u32);
        self.apply_ccr_budget("explore", output, params.0.max_tokens)
    }

    #[tool(
        description = "Detect project coding conventions from the indexed codebase. Returns error handling style, naming patterns, test organization, common imports, and file structure. Use when you need to write code that fits the project's existing patterns.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn conventions(&self) -> String {
        if let Some(result) = self.proxy_tool_call_without_params("conventions").await {
            return result;
        }
        let conv = {
            let guard = self.index.read();
            loading_guard!(guard);
            crate::protocol::conventions::detect_conventions(&guard)
        };
        let mut output = crate::protocol::conventions::format_conventions(&conv);
        output.push_str("\n\n── Worktree awareness ──\n");
        output.push_str(
            "When editing from inside a git worktree, pass `working_directory` \
             (absolute path of the worktree root) to every edit tool \
             (edit_within_symbol, replace_symbol_body, insert_symbol, \
             delete_symbol, batch_edit, batch_insert, batch_rename) so writes \
             land in your worktree instead of the indexed copy.\n\
             A supplied `working_directory` is explicit call-time routing \
             consent; unset/normal policy allows it, while false/off/disabled \
             `SYMFORGE_WORKTREE_AWARE` values block requested routing before \
             write. Omitting the parameter preserves today's indexed-path \
             behaviour. See README §Worktree awareness.",
        );
        output.push_str("\n\n── Frecency ranking ──\n");
        output.push_str(
            "Per-workspace file-ranking signal that decays on a 7-day half-life \
             and fuses with existing path-match and co-change signals. Call \
             `search_files` with `rank_by=\"frecency\"` to surface files you \
             recently touched. With `SYMFORGE_FRECENCY` unset, commitment tools \
             collect session-scoped history; `SYMFORGE_FRECENCY=1` uses the \
             persistent `.symforge/frecency.db`; false/off/disabled values block \
             frecency and requested ranking reports disabled-by-policy evidence.\n\
             Bump-on-commitment policy: SymForge bumps a path's frecency score \
             on every edit tool and on the read tools that imply commitment to \
             a known file (`get_file_context`, `get_file_content`, `get_symbol`, \
             `get_symbol_context`). Discovery tools (`search_files`, \
             `search_text`, `search_symbols`) deliberately never bump — \
             searching for a file is not the same as working on it, and \
             self-bumping searches corrupt rankings via a positive feedback \
             loop. Batch tools dedup bumps per invocation. Set \
             `search_files(debug_ranking=true)` for compact call-time ranking \
             diagnostics, or `SYMFORGE_DEBUG_RANKING=1` to default them on \
             and show the last-10 bumps list in `health`. See README \
             §Frecency ranking and ADR 0011 for the full policy.",
        );
        self.session_context.record_summary_output(
            "conventions",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        output
    }

    #[tool(
        description = "Plan an edit: analyzes a target symbol or file, counts references, and suggests the right sequence of SymForge edit tools. Accepts a bare symbol name, a file path, or an exact selector like `src/lib.rs::helper`. Use before making changes to understand impact.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn edit_plan(&self, params: Parameters<EditPlanInput>) -> String {
        if let Some(result) = self.proxy_tool_call("edit_plan", &params.0).await {
            return result;
        }
        let guard = self.index.read();
        loading_guard!(guard);
        let temporal = self.index.git_temporal();
        let output = crate::protocol::edit_plan::plan_edit(&guard, &temporal, &params.0.target);
        self.session_context.record_summary_output(
            "edit_plan",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        output
    }

    #[tool(
        description = "Suggest what to investigate next based on what you've already loaded. Analyzes session context to find referenced-but-not-loaded symbols. Use during deep investigations to find gaps.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn investigation_suggest(
        &self,
        params: Parameters<InvestigationInput>,
    ) -> String {
        if let Some(result) = self
            .proxy_tool_call("investigation_suggest", &params.0)
            .await
        {
            return result;
        }
        let guard = self.index.read();
        loading_guard!(guard);
        let output = crate::protocol::investigation::suggest_next_steps(
            &guard,
            &self.session_context,
            params.0.focus.as_deref(),
        );
        self.session_context.record_summary_output(
            "investigation_suggest",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        output
    }

    #[tool(
        name = "symforge",
        description = "STEL read/explore facade — natural-language code intelligence with trust envelope on the compact surface. Phase 0 batteries may pass `_probe_legacy_*` harness fields.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn symforge_facade_tool(
        &self,
        params: Parameters<crate::stel::SymforgeCallInput>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        if params.0.is_probe_relay() {
            let legacy_tool = match params.0.probe_legacy_tool.as_deref() {
                Some(tool) => tool,
                None => {
                    return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                        .into_call_tool_result(
                            "Phase 0 facade relay requires `_probe_legacy_tool` (A-019 battery harness only)",
                        ));
                }
            };
            let legacy_args = match params.0.probe_legacy_args.clone() {
                Some(args) => args,
                None => {
                    return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                        .into_call_tool_result(
                            "Phase 0 facade relay requires `_probe_legacy_args` (A-019 battery harness only)",
                        ));
                }
            };
            let output = self.dispatch_tool_for_tests(legacy_tool, legacy_args).await;
            let outcome_class = if is_error_output(&output) || output.starts_with("Invalid") {
                OutcomeClass::InvalidRequest
            } else if output.starts_with("Index not loaded.") {
                OutcomeClass::InternalFailure
            } else {
                OutcomeClass::Found
            };
            return statused_tool_result(output, outcome_class);
        }

        // Surface-honesty (012 D6 / contracts §3c): with `query` now
        // `#[serde(default)]`, an omitted/blank `query` no longer fails rmcp
        // deserialization with an opaque error — validate it explicitly here and
        // return a clean, actionable InvalidRequest instead.
        if params.0.request.query.trim().is_empty() {
            return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                .into_call_tool_result("query is required: pass a natural-language phrase"));
        }

        // Gate KEPT (unlike `status`, Wave 1 Fix 4): the `symforge` facade is a
        // genuine compact-surface invariant, not a self-inflicted refusal. It is
        // deliberately NOT advertised on the full surface (surface_probe.rs filters
        // it out of `tools/list`), and the A-019 golden-replay harness special-
        // cases THIS exact string as the "compact surface was not selected" signal
        // (stel/golden_replay.rs). On full, the caller has the 32 legacy tools the
        // facade fuses — the message names that path.
        if super::surface_probe::surface_profile_from_env()
            != super::surface_probe::SurfaceProfile::Compact
        {
            return Ok(ResultStatus::new(OutcomeClass::InvalidRequest).into_call_tool_result(
                "symforge STEL handler requires SYMFORGE_SURFACE=compact; use legacy tools on the full surface",
            ));
        }

        self.symforge_stel_handler(&params.0.request).await
    }

    /// Production compact-surface `symforge` path: L1 plan → L2 decision → L3 serve or P-FF bypass.
    ///
    /// `pub(crate)` so the durable-ledger proxy test (feature 013 US1 T021) can
    /// drive the economics path directly, below the `SYMFORGE_SURFACE` facade
    /// gate, without a process-global env mutation. Not a public API change.
    pub(crate) async fn symforge_stel_handler(
        &self,
        request: &crate::stel::StelRequest,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        use crate::protocol::smart_query;
        use crate::stel::controller::{build_estimate, evaluate_plan_tuned};
        use crate::stel::executor::{
            ServedStepResult, apply_compact_serve_caps, apply_degrade_to_plan,
            chain_failure_decision, format_bypass_body, format_cache_hit_body,
            format_multi_step_serve_body, format_partial_multi_step_serve_body,
            format_single_step_serve_body, is_degrade, route_tool_label, serve_chain_outcome_class,
            serve_step_failed, serve_step_outcome, should_skip_legacy_dispatch, tools_executed,
        };
        use crate::stel::handler::{self, metrics_for_decision_tuned};
        use crate::stel::planner::{build_plan, plan_summary_line};

        let q = smart_query::strip_leading_articles(request.query.trim());
        if q.is_empty() {
            return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                .into_call_tool_result("query requires a non-empty question."));
        }

        // Facade contract: a prose `symbol` would be passed verbatim as a tool
        // `name` and yield a misleading "Symbol not found: <sentence>". Reject it
        // here with a corrective message so the agent self-corrects.
        if let Some(message) = crate::stel::planner::symbol_contract_violation(request) {
            return Ok(
                ResultStatus::new(OutcomeClass::InvalidRequest).into_call_tool_result(&message)
            );
        }

        // Surface-honesty (012 Phase 3 / Principle VII): `StelRequest` carries
        // `project`/`projects` for schema parity with the direct tools, but the L1
        // planner does NOT route them into its read steps. Accepting them silently
        // would single-project-resolve a `projects:["*"]` caller and hand back
        // partial results that LOOK cross-project — a silent drop. Refuse honestly
        // instead: name the supported vehicle. A blank `project` / empty `projects`
        // is treated as "not set" (it would target the active project anyway), so
        // the refusal fires only on a meaningful cross-project request.
        let has_project = request
            .project
            .as_deref()
            .is_some_and(|p| !p.trim().is_empty());
        let has_projects = request
            .projects
            .as_deref()
            .is_some_and(|ids| ids.iter().any(|id| !id.trim().is_empty()));
        if has_project || has_projects {
            return Ok(
                ResultStatus::new(OutcomeClass::InvalidRequest).into_call_tool_result(
                    "cross-project targeting is not routed through the `symforge` facade; \
                 call search_symbols / search_text / find_references directly with \
                 project/projects.",
                ),
            );
        }

        // Surface-honesty (012 D6 / contracts §3c): `path:` is a WITHIN-project
        // filter, not a project selector. A `path:` that resolves outside the
        // bound project would silently match nothing (or, for an absolute path,
        // mislead the caller into thinking they retargeted). Reject it up front
        // with a clear message naming the bound root, mirroring the
        // `symbol_contract_violation` corrective pattern. Skipped when no root is
        // bound (nothing to verify against) or when `path` is blank.
        if let Some(root) = self.capture_repo_root()
            && let Some(path) = request.path.as_deref().filter(|p| !p.trim().is_empty())
            && !path_is_within_bound_project(path, &root)
        {
            let root_display = root.display().to_string().replace('\\', "/");
            return Ok(
                ResultStatus::new(OutcomeClass::InvalidRequest).into_call_tool_result(format!(
                    "path is outside the bound project {root_display}: \
                             `path:` is a within-project filter, not a project selector \
                             (use `index_folder {{ path }}` to retarget the workspace)."
                )),
            );
        }

        let mut plan = build_plan(request);
        // US5 (010 FR-014, D2): ground the plan's economics in the real target
        // byte sizes from the index before the L2 gate runs, so `predicted_net`
        // varies with the actual work and the adaptive bypass/degrade branches
        // become reachable (a tiny target's manual baseline falls below
        // SymForge's fixed schema+invoke overhead → economics bypass).
        self.ground_plan_economics(&mut plan);
        // T032 / FR-006: load the validated tuning in force for the current
        // estimator (None when no durable store / no accepted tuning / a stale
        // version), and thread it through BOTH the L2 decision and the envelope
        // economics so adaptive serve/degrade/bypass branches use the calibrated
        // floors. With no tuning this is byte-identical to the static path.
        let tuned = self.active_tuning_for_economics();
        let decision =
            evaluate_plan_tuned(request, &plan, Some(&self.session_context), tuned.as_ref());
        let step = plan
            .steps
            .first()
            .expect("L1 planner always emits at least one step");
        let plan_summary = plan_summary_line(&plan);
        let session_tokens_served = self.session_context.snapshot().total_tokens as i64;

        if request.preview == Some(true) {
            let estimate = build_estimate(request, &plan, &decision);
            let body = handler::format_preview_estimate(&estimate);
            let metrics = metrics_for_decision_tuned(
                plan_summary,
                &decision,
                &plan,
                0,
                session_tokens_served,
                tuned.as_ref(),
            );
            let envelope = handler::envelope_for_decision(&metrics);
            // 012 D6-a: the preview body is `envelope + "\n\n" + StelEstimate JSON`
            // that consumers parse to the end of the string, so a trailing
            // free-text bound-root line would corrupt the JSON tail. Preview is a
            // pre-flight estimate, not a served result; bound-root visibility is
            // attached to the actual served/bypass responses below instead.
            let output = handler::prepend_envelope(&envelope, &body);
            return statused_tool_result(output, OutcomeClass::Found);
        }

        if should_skip_legacy_dispatch(&decision) {
            let mut body = if decision.decision == crate::stel::AdmissionDecision::CacheHit {
                format_cache_hit_body(&decision)
            } else {
                format_bypass_body(&decision)
            };
            // Wave 1 Fix 5: disclose unconsumed caller params on the bypass path
            // too, so an economics-bypassed impact request is equally honest.
            for note in crate::stel::planner::served_param_disclosures(request, &plan) {
                body.push_str("\n\n");
                body.push_str(&note);
            }
            let output = self.finalize_symforge_with_ledger(
                "symforge",
                request,
                &plan,
                &decision,
                plan_summary,
                session_tokens_served,
                &body,
                false,
                &step.tool,
                None,
                tuned.as_ref(),
            );
            // 012 D6-a: surface the bound project on every `symforge` response.
            let output = self.with_bound_root_visibility(output);
            self.session_context
                .record_summary_output("symforge", handler::estimate_tokens(&output));
            return statused_tool_result(output, OutcomeClass::Found);
        }

        let exec_plan = if is_degrade(&decision) {
            apply_degrade_to_plan(&plan, &decision)
        } else if decision.decision == crate::stel::AdmissionDecision::Serve {
            apply_compact_serve_caps(&plan, &decision)
        } else {
            plan.clone()
        };

        // US4 find fusion is a UNION of independent surfaces (path + name), not
        // a dependent chain: an empty surface (NotFound/EmptyResult) is a valid
        // partial result, not a fatal failure. For fusion plans we therefore
        // only abort on a genuine error (InternalFailure/InvalidRequest); a
        // dependent chain keeps its existing fail-fast on any non-success.
        let is_fusion_union = crate::stel::is_find_fusion_plan(&exec_plan);
        let mut step_results = Vec::new();
        let mut outcome_class = OutcomeClass::Found;
        let mut chain_failed = false;
        for step in &exec_plan.steps {
            // The plan-only planner emits the path step with
            // `rank_by="path+cochange"` and no anchor (it has no index). Resolve
            // and inject the co-change anchor here, where the index lives. A
            // weak/absent anchor degrades to pure path ranking with no error.
            let step_args = self.inject_find_fusion_cochange_anchor(&step.tool, &step.args);
            let tool_body = self.dispatch_tool_for_tests(&step.tool, step_args).await;
            step_results.push(ServedStepResult {
                tool: step.tool.clone(),
                body: tool_body.clone(),
            });
            if serve_step_failed(&step.tool, &tool_body) {
                let step_outcome = serve_step_outcome(&step.tool, &tool_body);
                let fatal = !is_fusion_union
                    || matches!(
                        step_outcome,
                        OutcomeClass::InternalFailure | OutcomeClass::InvalidRequest
                    );
                if fatal {
                    outcome_class = serve_chain_outcome_class(step_outcome);
                    chain_failed = true;
                    break;
                }
            }
        }

        // P3-7: a find-fusion UNION where every surface came back empty/not-found
        // is not a success — downgrade the outcome to EmptyResult so agents see an
        // honest "no results" status instead of a misleading Found envelope. Only
        // applies when no step hard-failed (fail-fast already set the class above).
        if is_fusion_union && !chain_failed && !step_results.is_empty() {
            let all_empty = step_results.iter().all(|r| {
                matches!(
                    serve_step_outcome(&r.tool, &r.body),
                    OutcomeClass::EmptyResult | OutcomeClass::NotFound
                )
            });
            if all_empty {
                outcome_class = OutcomeClass::EmptyResult;
            }
        }

        let mut effective_decision = decision.clone();
        if chain_failed {
            let failed_index = step_results.len().saturating_sub(1);
            let failed_tool = step_results[failed_index].tool.as_str();
            let failed_outcome = serve_step_outcome(failed_tool, &step_results[failed_index].body);
            effective_decision =
                chain_failure_decision(&plan, &decision, failed_index, failed_tool, failed_outcome);
        }

        let chain_failure_note = chain_failed.then(|| effective_decision.decision_reason.clone());
        let mut body = if exec_plan.steps.len() == 1 {
            format_single_step_serve_body(
                &plan,
                &effective_decision,
                &exec_plan.steps[0],
                &step_results[0].body,
            )
        } else if chain_failed {
            format_partial_multi_step_serve_body(
                &plan,
                &effective_decision,
                &step_results,
                chain_failure_note.as_deref(),
            )
        } else {
            format_multi_step_serve_body(&plan, &effective_decision, &step_results)
        };

        // US5/FR-012: the impact intent plans a single `find_dependents` step
        // (dependents only). Chain co-change partners into the SAME envelope by
        // reusing the `analyze_file_impact` co-change flow (`git_temporal()` +
        // `format::co_changes_result_view`) — no second index, no fork. Only the
        // single-step success path is augmented; a failed/empty dependents step
        // keeps its own diagnostics.
        if plan.intent == crate::stel::IntentBucket::Impact
            && !chain_failed
            && exec_plan.steps.len() == 1
        {
            self.append_impact_intent_cochanges(&mut body, &exec_plan.steps[0].args);
        }

        // Wave 1 Fix 5: disclose any caller param the route did NOT consume
        // (e.g. a `path` on the git-derived impact route) — lossless-or-loud,
        // via the existing ParamDisposition accounting, never a silent drop.
        for note in crate::stel::planner::served_param_disclosures(request, &plan) {
            body.push_str("\n\n");
            body.push_str(&note);
        }

        let tools = tools_executed(&step_results);
        let route_label = route_tool_label(&tools);
        let tools_called = if tools.len() > 1 { Some(tools) } else { None };
        let output = self.finalize_symforge_with_ledger(
            "symforge",
            request,
            &plan,
            &effective_decision,
            plan_summary,
            session_tokens_served,
            &body,
            !step_results.is_empty(),
            &route_label,
            tools_called,
            tuned.as_ref(),
        );
        // 012 D6-a: surface the bound project on every `symforge` response.
        let output = self.with_bound_root_visibility(output);
        self.session_context
            .record_summary_output("symforge", handler::estimate_tokens(&output));
        statused_tool_result(output, outcome_class)
    }

    /// Append git co-change partners to the impact-intent envelope.
    ///
    /// The impact intent (`symforge intent=impact`) plans a single
    /// `find_dependents` step, which reports the file dependency graph but no
    /// co-change data. This chains co-change partners into the SAME response
    /// envelope using the same sources `analyze_file_impact` uses — the
    /// lock-free `git_temporal()` snapshot on the shared handle and
    /// `format::co_changes_result_view` — so dependents and co-changes arrive
    /// together without a second index or a forked formatter.
    ///
    /// Gating mirrors `analyze_file_impact`: when temporal is not `Ready` or the
    /// path has no git history we surface a short, non-fatal note rather than a
    /// placeholder block. `args` is the executed `find_dependents` step args,
    /// whose `path` field is the impact target.
    fn append_impact_intent_cochanges(&self, body: &mut String, args: &serde_json::Value) {
        const IMPACT_INTENT_COCHANGE_LIMIT: usize = 5;

        let Some(path) = args.get("path").and_then(|p| p.as_str()) else {
            return;
        };

        let temporal = self.index.git_temporal();
        match temporal.state {
            crate::live_index::git_temporal::GitTemporalState::Ready => {
                let normalized = path.replace('\\', "/");
                match temporal.files.get(&normalized) {
                    Some(history) => {
                        body.push_str("\n\n");
                        body.push_str(&format::co_changes_result_view(
                            &normalized,
                            history,
                            IMPACT_INTENT_COCHANGE_LIMIT,
                        ));
                    }
                    None => {
                        body.push_str("\n\nNo git co-change data found for this file.");
                    }
                }
            }
            crate::live_index::git_temporal::GitTemporalState::Pending
            | crate::live_index::git_temporal::GitTemporalState::Computing => {
                body.push_str("\n\nGit temporal data is still loading. Co-changes unavailable.");
            }
            crate::live_index::git_temporal::GitTemporalState::Unavailable(ref reason) => {
                body.push_str(&format!("\n\nGit temporal data unavailable: {reason}"));
            }
        }
    }

    #[tool(
        name = "symforge_edit",
        description = "STEL structural edit facade — replace a whole symbol's source by name. `body` is the FULL item source (signature + body, not just the inner block); pass it flush-left — the tool re-columns it to the symbol's indentation, so an already-indented body is not doubled. Leading doc-comments/attributes outside the symbol range are preserved unless `body` itself begins with a doc-comment. Preview by default; apply:true commits; if_match guards against a concurrent edit.",
        annotations(
            read_only_hint = false,
            destructive_hint = true,
            idempotent_hint = false,
            open_world_hint = false
        )
    )]
    pub(crate) async fn symforge_edit_facade_tool(
        &self,
        params: Parameters<crate::stel::StelEditRequest>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        // Gate KEPT (unlike `status`, Wave 1 Fix 4): `symforge_edit` routes through
        // the STEL economics/ledger apply path, the compact-surface invariant the
        // A-019 golden replay pins. On full the caller has the legacy edit tools
        // (replace_symbol_body / edit_within_symbol / …) this facade fuses — the
        // message names that path. Pinned by tests/stel_symforge_edit.rs.
        if super::surface_probe::surface_profile_from_env()
            != super::surface_probe::SurfaceProfile::Compact
        {
            return Ok(ResultStatus::new(OutcomeClass::InvalidRequest).into_call_tool_result(
                "symforge_edit STEL handler requires SYMFORGE_SURFACE=compact; use legacy edit tools on the full surface",
            ));
        }

        self.symforge_edit_stel_handler(&params.0).await
    }

    /// Production compact-surface `symforge_edit` path: L1 edit plan → L2 economics → preview or guarded apply.
    async fn symforge_edit_stel_handler(
        &self,
        request: &crate::stel::StelEditRequest,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        use crate::stel::controller::evaluate_edit_plan;
        use crate::stel::edit_apply::{
            PreApplyOutcome, apply_requested, format_already_applied_body, format_apply_metadata,
            run_pre_apply_gates,
        };
        use crate::stel::edit_planner::{build_edit_plan, edit_plan_summary_line};
        use crate::stel::handler;
        use crate::stel::planner::confidence_label;

        if let Err(error) = crate::stel::edit_planner::validate_edit_request(request) {
            return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                .into_call_tool_result(error.message));
        }

        let apply = apply_requested(request);
        let mut resolved_symbol = None;

        // In daemon-proxy stdio, this front-end intentionally holds
        // LiveIndex::empty(); the proxied edit tool runs these gates against the
        // daemon's populated index.
        if apply && self.daemon_client.is_none() {
            let abs_path =
                match super::edit_tools::prepare_exact_path_for_edit(self, request.path.trim()) {
                    Ok((path, _)) => path,
                    Err(message) => {
                        return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                            .into_call_tool_result(message));
                    }
                };
            match run_pre_apply_gates(&self.index, request, &abs_path) {
                Ok(PreApplyOutcome::Ready(symbol)) => resolved_symbol = Some(symbol),
                Ok(PreApplyOutcome::AlreadyApplied(symbol)) => {
                    let plan = build_edit_plan(request).expect("validated edit request");
                    let decision = evaluate_edit_plan(&plan);
                    let plan_summary = edit_plan_summary_line(&plan);
                    let session_tokens_served = self.session_context.snapshot().total_tokens as i64;
                    let tool_body = format_already_applied_body(&symbol);
                    let routing_meta = format!(
                        "Mode: guarded apply (already applied)\n\
                         Route confidence: {}\n\
                         Chosen tool: replace_symbol_body\n\
                         Economics: {} ({})",
                        confidence_label(plan.confidence),
                        decision.decision.as_str(),
                        decision.decision_reason,
                    );
                    let body = format!("{routing_meta}\n\n{tool_body}");
                    let output = self.finalize_symforge_with_ledger(
                        "symforge_edit",
                        &crate::stel::StelRequest::default(),
                        &plan,
                        &decision,
                        plan_summary,
                        session_tokens_served,
                        &body,
                        false,
                        "replace_symbol_body",
                        None,
                        // Edits are byte-grounded (grounded_edit_tokens), not
                        // floor-tuned; the auto-tune corrects only the plan-floor
                        // path, so no tuning applies here.
                        None,
                    );
                    self.session_context
                        .record_summary_output("symforge_edit", handler::estimate_tokens(&output));
                    return statused_tool_result(output, OutcomeClass::Found);
                }
                Err(error) => {
                    return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                        .into_call_tool_result(error.message));
                }
            }
        }

        let plan = match build_edit_plan(request) {
            Ok(plan) => plan,
            Err(error) => {
                return Ok(ResultStatus::new(OutcomeClass::InvalidRequest)
                    .into_call_tool_result(error.message));
            }
        };
        let decision = evaluate_edit_plan(&plan);
        let step = plan
            .steps
            .first()
            .expect("edit planner always emits at least one step");
        let plan_summary = edit_plan_summary_line(&plan);
        let session_tokens_served = self.session_context.snapshot().total_tokens as i64;

        let tool_body = self
            .dispatch_tool_for_tests(&step.tool, step.args.clone())
            .await;
        let invocation = serde_json::to_string(&step.args).unwrap_or_else(|_| "{}".to_string());
        let mode_line = if apply {
            "Mode: guarded apply (committed when validation succeeds)"
        } else {
            "Mode: preview-only (dry_run); default when apply is omitted or false"
        };
        let routing_meta = format!(
            "{mode_line}\n\
             Route confidence: {}\n\
             Chosen tool: {}\n\
             Invocation: {}\n\
             Rationale: {}\n\
             Economics: {} ({})",
            confidence_label(plan.confidence),
            step.tool,
            invocation,
            plan.confidence_rationale,
            decision.decision.as_str(),
            decision.decision_reason,
        );
        let mut body = format!("{routing_meta}\n\n{tool_body}");
        if apply && let Some(symbol) = resolved_symbol.as_ref() {
            let write_mode = super::edit_format::symforge_edit_apply_write_mode(&tool_body);
            body = format!(
                "{routing_meta}\n\n{}\n\n{tool_body}",
                format_apply_metadata(symbol, write_mode)
            );
        }

        let legacy_executed = apply && super::edit_format::edit_output_bytes_committed(&tool_body);
        let output = self.finalize_symforge_with_ledger(
            "symforge_edit",
            &crate::stel::StelRequest::default(),
            &plan,
            &decision,
            plan_summary,
            session_tokens_served,
            &body,
            legacy_executed,
            &step.tool,
            None,
            // Edits are byte-grounded, not floor-tuned (see above).
            None,
        );
        self.session_context
            .record_summary_output("symforge_edit", handler::estimate_tokens(&output));

        let outcome_class = Self::classify_symforge_edit_outcome(&tool_body, apply, &body);
        statused_tool_result(output, outcome_class)
    }

    fn classify_symforge_edit_outcome(
        tool_body: &str,
        apply: bool,
        full_body: &str,
    ) -> OutcomeClass {
        use super::edit_format::symforge_edit_internal_failure;
        if is_error_output(tool_body) || tool_body.starts_with("Invalid") {
            OutcomeClass::InvalidRequest
        } else if symforge_edit_internal_failure(tool_body, apply, full_body) {
            OutcomeClass::InternalFailure
        } else {
            OutcomeClass::Found
        }
    }

    #[tool(
        name = "status",
        description = "STEL trust envelope and index health summary.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn status_stel_tool(
        &self,
        params: Parameters<crate::stel::StelStatusRequest>,
    ) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
        // Wave-1 defect fix (2026-07-02): NO surface gate here. `status` is a
        // read-only health/trust readout that the docs tell every client to call
        // at session start, so refusing it on `SYMFORGE_SURFACE=full` was a
        // self-inflicted failure with no invariant behind it (unlike `symforge`/
        // `symforge_edit`, whose gates guard the STEL economics/golden-replay
        // path — kept, see those handlers). The body self-describes the active
        // surface via `render_stel_status_body`, so a full-surface `status` is
        // honest about where it ran.

        // TR-01 (FR-006/007): in the default daemon-proxy topology this front-end
        // server's `self.index` is EMPTY — the populated index lives in the warm
        // daemon that serves real queries. So `status` MUST report the daemon's
        // index, exactly like `health`/`health_compact` do, or it lies about a
        // working system. Proxy to the daemon first; only fall through to the
        // local `self.index` when there is no daemon (embed/local) or the daemon
        // is unreachable (degraded fallback, where `ensure_local_index` has
        // populated `self.index`).
        //
        // Thread THIS adapter's served surface into the proxied request so the
        // daemon reports the surface actually served on this connection — not the
        // daemon process's own env, which may differ (dogfood defect: a full-env
        // adapter proxied through a compact-env daemon rendered `surface:
        // compact`). The adapter is the authority, so OVERWRITE any client value;
        // the daemon prefers this field and falls back to its own env for older
        // adapters (backward compat via `#[serde(default)]` on
        // `connection_surface`). The same request drives the daemon-less fallback
        // below, where env IS the connection surface, so output is unchanged.
        let mut request = params.0.clone();
        request.connection_surface = Some(
            super::surface_probe::surface_profile_label(
                super::surface_probe::surface_profile_from_env(),
            )
            .to_string(),
        );
        if let Some(result) = self.proxy_tool_call("status", &request).await {
            // D2-ROOT: the daemon worker owns the populated INDEX but has an EMPTY
            // session ledger + NO durable store, so its proxied body reads
            // `ledger_events: 0`, `last_ledger_*: none`, `durable_ledger:
            // unavailable`, `calibration: deferred` — but THIS proxy owns the
            // ledger + store and events accumulate here. Overlay ALL of the
            // proxy's OWN ledger/store-derived lines (not just durable_ledger)
            // onto the worker body so the operator's status window shows reality,
            // not the worker's blind zero. The INDEX lines stay the worker's
            // (TR-01). No-op for the parts absent in `detail:compact`, and
            // honestly stays `0`/`none`/`unavailable`/`deferred` if this proxy's
            // own ledger/store is empty.
            let result = overlay_proxy_status_lines(result, &self.proxy_owned_status_lines());
            // Mirror `health`: warn loudly if the daemon we proxied to runs an
            // older binary than this front-end.
            let body = append_daemon_staleness_warning(result, env!("CARGO_PKG_VERSION"));
            return statused_tool_result(body, OutcomeClass::Found);
        }

        let body = self.render_stel_status_body(&request);
        statused_tool_result(body, OutcomeClass::Found)
    }

    /// Render the `status` body from THIS server's own index, ledger, and
    /// durable store — no proxy, no surface-env gate.
    ///
    /// This is the single rendering path shared by three callers:
    ///   - the front-end local/degraded fallback (when no daemon is reachable),
    ///   - the embed/local build (the server IS the index), and
    ///   - the daemon-side `status` dispatch arm
    ///     ([`Self::status_for_daemon_session`]), where `self.index` is the
    ///     POPULATED served index.
    ///
    /// Because the daemon process owns the warm index, calling this on the
    /// daemon side yields the same readiness/counts the queries actually use —
    /// the TR-01 fix (FR-006). The surface-env gate stays on the front-end
    /// `status_stel_tool` entry point only; the daemon renders whatever the
    /// proxied request asks for.
    pub(crate) fn render_stel_status_body(
        &self,
        request: &crate::stel::StelStatusRequest,
    ) -> String {
        // T037 / FR-011 operator reset: clear accumulated calibration BEFORE
        // rendering, so the surface returns to `Deferred`. MCP-native — a param on
        // the existing `status` tool, never injected context; never rebuilds the
        // index (only the calibration tables are cleared).
        let reset_note = if request.reset_calibration == Some(true) {
            match self.reset_calibration() {
                Some(cleared) => Some(format!(
                    "calibration_reset: cleared {cleared} sample(s) + active tuning (state -> deferred)"
                )),
                None => Some(
                    "calibration_reset: no durable store; in-memory calibration is already deferred"
                        .to_string(),
                ),
            }
        } else {
            None
        };

        // Report the surface actually served on THIS connection. In the daemon-
        // proxy topology that is the ADAPTER's profile, threaded in via
        // `request.connection_surface`; this daemon process's own env may differ
        // (a full-env adapter serves legacy tools through a compact-env daemon).
        // Prefer the connection profile when present and recognized; fall back to
        // this process's env for direct/daemon-less serving and for older
        // adapters that predate the field (backward compat via `#[serde(default)]`).
        let env_label = super::surface_probe::surface_profile_label(
            super::surface_probe::surface_profile_from_env(),
        );
        let (surface_label, daemon_env_surface) = match request
            .connection_surface
            .as_deref()
            .and_then(super::surface_probe::surface_label_from_str)
        {
            // Honest divergence disclosure: the connection serves `conn` while
            // this daemon's env resolves `env_label`. Report the connection truth
            // and name the daemon's own env on one line (see
            // `format_compact_status`), so a cross-process mismatch is never a
            // silent lie.
            Some(conn) if conn != env_label => (conn, Some(env_label)),
            Some(conn) => (conn, None),
            None => (env_label, None),
        };

        let guard = self.index.read();
        let ledger = self.stel_ledger.lock();
        // 012 D6-a bound-root visibility: surface WHICH workspace answered. This
        // is the root bound on THIS server — on the daemon side it is the warm
        // project's root (TR-01), on the front-end fallback it is the proxy's
        // bound root. Normalized to forward slashes to match `runtime_status_for`.
        let project_root = self
            .capture_repo_root()
            .map(|root| root.to_string_lossy().replace('\\', "/"));
        // 013: `mut` — line below reassigns `ctx` with the durable calibration
        // verdict override (T033/FR-009).
        let mut ctx = crate::stel::StelStatusContext::from_server(
            surface_label,
            &self.project_name,
            project_root,
            guard.is_ready(),
            guard.file_count(),
            guard.symbol_count(),
            &ledger,
            self.session_context.snapshot().total_tokens,
        )
        // US3/T029: surface the durable ledger subsystem state so
        // restart-survival is observable from `status` (Unavailable on
        // stdio/embed; Disabled{reason} for a wired-but-failing store — N-3).
        .with_durable_ledger(self.durable_ledger_summary_for_status());

        // T033 / FR-009: override the in-memory verdict with the DURABLE one so
        // `status detail:full` reflects the persisted cross-session calibration
        // state + active tuning. `None` means no durable store is wired; a wired
        // store whose sample read fails returns `Deferred` so status never keeps
        // an in-memory `Tuned` verdict without a readable durable artifact. After
        // a reset above, the durable read sees zero samples -> `Deferred`.
        if let Some(verdict) = self.durable_calibration_verdict() {
            ctx = ctx.with_calibration_verdict(verdict);
        }

        // Attach the daemon-env divergence (proxy topology only); `None` on
        // same-env and direct serving so the disclosure line appears strictly on
        // divergence.
        ctx.daemon_env_surface = daemon_env_surface;

        let body = crate::stel::format_stel_status(request, &ctx);
        match reset_note {
            Some(note) => format!("{body}\n{note}"),
            None => body,
        }
    }

    /// Render the proxy-owned `status` line-set from THIS server's OWN ledger +
    /// durable store + calibration verdict — the proxy's truth for the lines a
    /// worker-rendered `status` body misrepresents on the daemon-backed default
    /// (D2-ROOT).
    ///
    /// Builds the SAME [`StelStatusContext`] that [`Self::render_stel_status_body`]
    /// builds (the proxy's `stel_ledger` session events, `durable_ledger_summary`,
    /// and durable `calibration` verdict) — only WITHOUT the index/project lines,
    /// which stay the worker's (TR-01). Used by `status_stel_tool` to overlay the
    /// proxy's `ledger_events`/`last_ledger_*`/`durable_ledger`/`calibration`
    /// onto the proxied worker body so the operator's status window reflects the
    /// proxy's real accumulation, not the storeless worker's blind zero.
    ///
    /// Honesty: an empty proxy ledger yields `ledger_events: 0` /
    /// `last_ledger_*: none`; an `Unavailable`/`Disabled` store yields the
    /// truthful durable line; a `Deferred`/`Accumulating` verdict yields that
    /// calibration section — exactly as `render_stel_status_body` would render
    /// them. No store/reset side effects here: this is a pure read.
    pub(crate) fn proxy_owned_status_lines(&self) -> crate::stel::ProxyOwnedStatusLines {
        // Index/project fields are NOT consumed by `render_proxy_owned_lines`
        // (those lines stay the worker's), so we pass the proxy's own empty-index
        // values without reading the index — keeping this a ledger/store-only read.
        let ledger = self.stel_ledger.lock();
        let mut ctx = crate::stel::StelStatusContext::from_server(
            "compact",
            &self.project_name,
            // 012 project_root: unused here — render_proxy_owned_lines omits the
            // project/index lines (they stay the worker's, TR-01).
            None,
            false,
            0,
            0,
            &ledger,
            self.session_context.snapshot().total_tokens,
        )
        .with_durable_ledger(self.durable_ledger_summary_for_status());
        // Mirror `render_stel_status_body`: override the in-memory verdict with the
        // DURABLE one (cross-session samples + active tuning). A wired store whose
        // sample read fails returns `Deferred`; only no store at all yields `None`.
        if let Some(verdict) = self.durable_calibration_verdict() {
            ctx = ctx.with_calibration_verdict(verdict);
        }
        crate::stel::render_proxy_owned_lines(&ctx)
    }

    /// Daemon-side `status` entry point (TR-01 / FR-006).
    ///
    /// Reached via the `"status"` arm in `daemon::execute_tool_call` when the
    /// front-end proxies `status` to the warm daemon. The daemon server owns the
    /// POPULATED index, so this renders truthful readiness + counts. It does NOT
    /// re-apply the `SYMFORGE_SURFACE=compact` env gate (that gate is the
    /// front-end's concern; the daemon serves the proxied request) and it does
    /// not re-proxy (the daemon server has no `daemon_client`).
    pub(crate) fn status_for_daemon_session(
        &self,
        request: &crate::stel::StelStatusRequest,
    ) -> String {
        self.render_stel_status_body(request)
    }

    /// Bound-root visibility line for the `symforge` response envelope (012 D6-a).
    ///
    /// Reuses [`Self::runtime_status_for`] (the same accessor `health` uses) so
    /// the surfaced root carries the identical backslash normalization and
    /// `project_root` derivation — a single source of truth for "which workspace
    /// answered". Returns `project_root: (unbound)` when nothing is bound so a
    /// stale or wrong binding is LOUD in every facade response, never silent.
    fn stel_bound_root_line(&self) -> String {
        let published = self.index.published_state();
        let status =
            self.runtime_status_for(&published, self.local_runtime_mode(), None, None, None);
        format!(
            "project_root: {}",
            status.project_root.as_deref().unwrap_or("(unbound)")
        )
    }

    /// Attach the bound-root visibility line to a finished `symforge` response so
    /// the answering project is always observable (012 D6-a).
    ///
    /// Appended as a trailing line rather than prepended so the trust envelope
    /// stays the FIRST block of the response — a contract relied on by consumers
    /// and by the facade tests (`output.starts_with("── stel")`). The bound-root
    /// line is still unconditionally present, so a stale/wrong binding is loud.
    fn with_bound_root_visibility(&self, output: String) -> String {
        format!("{output}\n{}", self.stel_bound_root_line())
    }

    #[allow(clippy::too_many_arguments)]
    fn finalize_symforge_with_ledger(
        &self,
        surface: &'static str,
        _request: &crate::stel::StelRequest,
        plan: &crate::stel::StelPlan,
        decision: &crate::stel::StelDecision,
        plan_summary: String,
        session_tokens_served: i64,
        body: &str,
        legacy_executed: bool,
        selected_tool: &str,
        tools_called: Option<Vec<String>>,
        tuned: Option<&crate::stel::ledger_store::TunedEstimateConstants>,
    ) -> String {
        use crate::stel::handler::{self, finalize_symforge_output, metrics_for_decision_tuned};
        use crate::stel::ledger::{
            LedgerCaptureInput, capture_ledger, format_ledger_envelope_line,
        };

        let response_tokens = handler::estimate_tokens(body);
        // T032: record the prediction the predictor ACTUALLY made for this call —
        // tuned when a validated tuning is in force, static otherwise — so the
        // ledger's predicted-vs-actual residual reflects the live estimator and
        // the next tuning pass measures progress against it (hysteresis).
        let metrics = metrics_for_decision_tuned(
            plan_summary,
            decision,
            plan,
            response_tokens,
            session_tokens_served,
            tuned,
        );
        let (event, meta) = capture_ledger(&LedgerCaptureInput {
            plan,
            decision,
            economics: &metrics.economics,
            selected_tool,
            tools_called: tools_called.as_deref(),
            legacy_executed,
            output_body: body,
            surface,
        });
        self.stel_ledger.lock().push(event.clone());
        // US3/T028: durable write-through after the in-memory push. Single
        // ledger path (no double-count); degrades to a logged no-op on a store
        // error and never fails the request (FR-011). Compile-time no-op on
        // stdio/embed builds where no durable store is wired.
        self.persist_ledger_event_durably(&event);
        let ledger_line = format_ledger_envelope_line(&event, &meta);
        finalize_symforge_output(metrics, ledger_line, body)
    }

    #[tool(
        description = "Retrieve full tool output previously stored by CCR compression. Pass the hash from a search or discovery footer.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn symforge_retrieve(
        &self,
        params: Parameters<SymforgeRetrieveInput>,
    ) -> String {
        let hash = params.0.hash.trim().to_lowercase();
        if hash.len() != 12 || !hash.chars().all(|c| c.is_ascii_hexdigit()) {
            return "CCR retrieve: invalid hash (expected 12 hex chars)".to_string();
        }
        match self.ccr_store.lock().retrieve(&hash) {
            Some(body) => body,
            None => format!("CCR retrieve: unknown or expired hash '{hash}'"),
        }
    }

    #[tool(
        description = "Show what symbols and files have been fetched this session. Returns a context inventory with token counts. Use to track your context budget and avoid re-fetching content you already have.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn context_inventory(&self) -> String {
        if let Some(result) = self
            .proxy_tool_call_without_params("context_inventory")
            .await
        {
            return result;
        }
        let snap = self.session_context.snapshot();
        let ccr = self.compression_economics();
        crate::protocol::session::format_context_inventory(&snap, ccr)
    }

    #[tool(
        description = "Natural language entry point — ask any question about the codebase and SymForge routes to the right tool internally. Use when unsure which specific tool to call. Examples: 'who calls X', 'where is X defined', 'how does X work', 'what changed', 'find file X'. Returns the result plus which tool was used, so you can call it directly next time.",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn ask(&self, params: Parameters<SmartQueryInput>) -> String {
        use crate::protocol::smart_query;

        let original_q = params.0.query.trim();
        let q = smart_query::strip_leading_articles(original_q);
        if q.is_empty() {
            return "query requires a non-empty question.".to_string();
        }

        let (mut intent, mut matched_prefix) = smart_query::classify_intent_with_match(q);
        if matches!(
            intent,
            smart_query::QueryIntent::Understand { .. } | smart_query::QueryIntent::Explore { .. }
        ) {
            let guard = self.index.read();
            if let Some(name) =
                Self::extract_exact_implementation_understanding_candidate(&guard, q)
            {
                intent = smart_query::QueryIntent::UnderstandImplementations { name };
                matched_prefix = false;
            } else if let Some(symbol) =
                Self::extract_exact_symbol_understanding_candidate(&guard, q)
            {
                intent = smart_query::QueryIntent::UnderstandSymbol { symbol };
                matched_prefix = false;
            }
        }
        let assessment = smart_query::assess_route(&intent, matched_prefix);
        let route_desc = smart_query::route_description(&intent);

        let result = match &intent {
            smart_query::QueryIntent::FindCallers { symbol, path } => {
                let input = FindReferencesInput {
                    name: symbol.clone(),
                    kind: None,
                    path: path.clone(),
                    symbol_kind: None,
                    symbol_line: None,
                    limit: None,
                    max_per_file: None,
                    compact: Some(true),
                    mode: None,
                    direction: None,
                    estimate: None,
                    max_tokens: None,
                    project: None,
                    projects: None,
                };
                self.find_references(Parameters(input)).await
            }
            smart_query::QueryIntent::FindSymbol { name, kind } => {
                let input = SearchSymbolsInput {
                    query: Some(name.clone()),
                    kind: kind.clone(),
                    path_prefix: None,
                    language: None,
                    limit: None,
                    include_generated: None,
                    include_tests: None,
                    include_vendor: None,
                    include_personal_tooling: None,
                    estimate: None,
                    max_tokens: None,
                    project: None,
                    projects: None,
                };
                self.search_symbols(Parameters(input)).await
            }
            smart_query::QueryIntent::FindFile { hint } => {
                let input = SearchFilesInput {
                    query: hint.clone(),
                    limit: None,
                    current_file: None,
                    changed_with: None,
                    resolve: None,
                    estimate: None,
                    max_tokens: None,
                    debug_ranking: None,
                    rank_by: None,
                    anchor_path: None,
                    include_vendor: None,
                    include_personal_tooling: None,
                    path_prefix: None,
                };
                self.search_files(Parameters(input)).await
            }
            smart_query::QueryIntent::FindChanges => {
                let input = WhatChangedInput {
                    since: None,
                    git_ref: None,
                    uncommitted: Some(true),
                    path_prefix: None,
                    language: None,
                    code_only: Some(true),
                    include_symbol_diff: Some(true),
                    estimate: None,
                    max_tokens: None,
                };
                self.what_changed(Parameters(input)).await
            }
            smart_query::QueryIntent::Understand { concept } => {
                let input = ExploreInput {
                    query: concept.clone(),
                    limit: None,
                    depth: Some(2),
                    include_noise: None,
                    include_vendor: None,
                    include_personal_tooling: None,
                    language: None,
                    path_prefix: None,
                    estimate: None,
                    max_tokens: None,
                };
                self.explore(Parameters(input)).await
            }
            smart_query::QueryIntent::UnderstandSymbol { symbol } => {
                let input = GetSymbolContextInput {
                    name: symbol.clone(),
                    file: None,
                    path: None,
                    symbol_kind: None,
                    symbol_line: None,
                    verbosity: Some("compact".to_string()),
                    bundle: None,
                    sections: None,
                    max_tokens: None,
                    estimate: None,
                };
                self.get_symbol_context(Parameters(input)).await
            }
            smart_query::QueryIntent::UnderstandImplementations { name } => {
                let input = FindReferencesInput {
                    name: name.clone(),
                    kind: None,
                    path: None,
                    symbol_kind: None,
                    symbol_line: None,
                    limit: None,
                    max_per_file: None,
                    compact: None,
                    mode: Some("implementations".to_string()),
                    direction: None,
                    estimate: None,
                    max_tokens: None,
                    project: None,
                    projects: None,
                };
                self.find_references(Parameters(input)).await
            }
            smart_query::QueryIntent::SearchCode { pattern } => {
                let input = SearchTextInput {
                    query: Some(pattern.clone()),
                    terms: None,
                    regex: None,
                    path_prefix: None,
                    language: None,
                    limit: None,
                    max_per_file: None,
                    glob: None,
                    exclude_glob: None,
                    context: None,
                    case_sensitive: None,
                    whole_word: None,
                    group_by: None,
                    follow_refs: None,
                    follow_refs_limit: None,
                    ranked: None,
                    include_generated: None,
                    include_tests: None,
                    include_vendor: None,
                    include_personal_tooling: None,
                    estimate: None,
                    max_tokens: None,
                    structural: None,
                    project: None,
                    projects: None,
                };
                self.search_text(Parameters(input)).await
            }
            smart_query::QueryIntent::FindDependents { target } => {
                let input = FindDependentsInput {
                    path: target.clone(),
                    name: None,
                    limit: None,
                    max_per_file: None,
                    format: None,
                    compact: Some(true),
                    estimate: None,
                    max_tokens: None,
                };
                self.find_dependents(Parameters(input)).await
            }
            smart_query::QueryIntent::FindImplementations { name } => {
                let input = FindReferencesInput {
                    name: name.clone(),
                    kind: None,
                    path: None,
                    symbol_kind: None,
                    symbol_line: None,
                    limit: None,
                    max_per_file: None,
                    compact: None,
                    mode: Some("implementations".to_string()),
                    direction: None,
                    estimate: None,
                    max_tokens: None,
                    project: None,
                    projects: None,
                };
                self.find_references(Parameters(input)).await
            }
            smart_query::QueryIntent::ToolHelp { topic } => {
                smart_query::render_tool_catalog_for_topic(topic.as_deref())
            }
            smart_query::QueryIntent::Explore { query } => {
                let input = ExploreInput {
                    query: query.clone(),
                    limit: None,
                    depth: Some(2),
                    include_noise: None,
                    include_vendor: None,
                    include_personal_tooling: None,
                    language: None,
                    path_prefix: None,
                    estimate: None,
                    max_tokens: None,
                };
                self.explore(Parameters(input)).await
            }
        };

        let mut envelope = format!(
            "Route confidence: {}\nChosen tool: {}\nInvocation: {}\nRationale: {}",
            smart_query::route_confidence_label(assessment.confidence),
            smart_query::route_tool_name(&intent),
            smart_query::route_invocation(&intent),
            assessment.rationale,
        );
        if original_q != q {
            envelope.push_str(&format!("\nOriginal query: {original_q}"));
        }
        if let Some(next_step) = assessment.suggested_next_step {
            envelope.push_str(&format!("\nSuggested next step: {next_step}"));
        }

        let output = format!("{envelope}\n{route_desc}\n\n{result}");
        self.session_context
            .record_summary_output("ask", (output.len() / 4).min(u32::MAX as usize) as u32);
        format::enforce_token_budget(output, params.0.max_tokens)
    }

    /// Symbol-level diff between two git refs. Shows +added, -removed, ~modified symbols per changed
    /// file. Filter with path_prefix and/or language. Set code_only=true to exclude non-source files.
    /// Use for code review to see which functions/classes changed.
    /// NOT for file-level change lists (use what_changed).
    #[tool(
        description = "Symbol-level diff between two git refs. Shows +added, -removed, ~modified symbols per changed file. Filter with path_prefix and/or language. Set code_only=true to exclude non-source files. Use for code review to see which functions/classes changed. NOT for file-level change lists (use what_changed).",
        annotations(read_only_hint = true, open_world_hint = false)
    )]
    pub(crate) async fn diff_symbols(&self, params: Parameters<DiffSymbolsInput>) -> String {
        if let Some(result) = self.proxy_tool_call("diff_symbols", &params.0).await {
            return result;
        }
        if params.0.estimate == Some(true) {
            let compact = params.0.compact.unwrap_or(false);
            let summary = params.0.summary_only.unwrap_or(false);
            let est = if summary {
                50
            } else if compact {
                200
            } else {
                500
            };
            return format!(
                "Estimate for diff_symbols: ~{} tokens (compact={}, summary_only={})",
                est, compact, summary
            );
        }
        let base = params.0.base.as_deref().unwrap_or("main");
        let target = params.0.target.as_deref().unwrap_or("HEAD");

        let repo_root = self.capture_repo_root();

        let Some(repo_root) = repo_root else {
            return "No repository root found.".to_string();
        };

        // Check index is not loading/empty
        {
            let guard = self.index.read();
            loading_guard!(guard);
        }

        // Get changed files
        let repo = match crate::git::GitRepo::open(&repo_root) {
            Ok(r) => r,
            Err(e) => return format!("Failed to open repository: {e}"),
        };
        let changed_files_owned = match repo.changed_paths_between_refs(base, target) {
            Ok(paths) => paths,
            Err(e) => return format!("Failed to run git diff: {e}"),
        };

        // Apply path_prefix + language filter
        let lang_filter = match parse_language_filter(params.0.language.as_deref()) {
            Ok(f) => f,
            Err(e) => return e,
        };
        let code_only = params.0.code_only.unwrap_or(false);
        let changed_files: Vec<&str> = changed_files_owned
            .iter()
            .map(|s| s.as_str())
            .filter(|p| {
                if let Some(ref prefix) = params.0.path_prefix
                    && !p.starts_with(prefix.as_str())
                {
                    return false;
                }
                if let Some(ref lang) = lang_filter {
                    let ext = p.rsplit('.').next().unwrap_or("");
                    if crate::domain::index::LanguageId::from_extension(ext).as_ref() != Some(lang)
                    {
                        return false;
                    }
                }
                if code_only && lang_filter.is_none() {
                    let ext = p.rsplit('.').next().unwrap_or("");
                    match crate::domain::index::LanguageId::from_extension(ext) {
                        None => return false,
                        Some(lang) => {
                            if crate::parsing::config_extractors::is_config_language(&lang) {
                                return false;
                            }
                        }
                    }
                }
                true
            })
            .collect();

        if changed_files.is_empty() {
            return format!("No file changes found between {base} and {target}.");
        }

        let output = render_diff_symbols_output(
            base,
            target,
            changed_files_owned.len(),
            &changed_files,
            &repo,
            params.0.compact.unwrap_or(false),
            params.0.summary_only.unwrap_or(false),
            params.0.path_prefix.as_deref(),
            params.0.language.as_deref(),
            code_only,
        );
        self.record_tool_savings_named(
            "diff_symbols",
            format::estimate_tokens_from_chars(format::estimate_listing_baseline_chars(
                output.len(),
            )),
            (output.len() / 4) as u64,
        );
        self.session_context.record_summary_output(
            "diff_symbols",
            (output.len() / 4).min(u32::MAX as usize) as u32,
        );
        format::enforce_token_budget(output, params.0.max_tokens)
    }
}

