    #[test]
    fn extract_runtime_version_pulls_token_from_runtime_line() {
        let proxied = proxied_health_with_version("7.17.2");
        assert_eq!(super::extract_runtime_version(&proxied), Some("7.17.2"));
        assert_eq!(super::extract_runtime_version("no version here"), None);
    }

    #[test]
    fn extract_runtime_version_pulls_token_from_status_body() {
        // TR-01: the `status` body uses `symforge_version: X`, not `version=X`.
        // The extractor must read that form so the staleness guard is not a
        // structural no-op on the status proxy path.
        let status_body =
            "── stel status ──\nsurface: compact\nsymforge_version: 7.17.2\nindex_ready: true\n──";
        assert_eq!(super::extract_runtime_version(status_body), Some("7.17.2"));
    }

    #[test]
    fn daemon_staleness_warning_fires_on_status_body_for_older_daemon() {
        // TR-01: an older daemon answering a proxied `status` call must trigger
        // the same loud skew warning `health` gets (the comment in
        // `status_stel_tool` is now true, not aspirational).
        let status_body =
            "── stel status ──\nsurface: compact\nsymforge_version: 7.17.2\nindex_ready: true\n──"
                .to_string();
        let out = super::append_daemon_staleness_warning(status_body, "7.18.1");
        assert!(
            out.contains("Daemon serving stale code"),
            "older daemon serving `status` must trigger the staleness warning; got: {out}"
        );
    }

    #[tokio::test]
    async fn status_serves_on_full_surface_without_corpus() {
        // Wave 1 Fix 4 (corpus-free proof): with SYMFORGE_SURFACE=full active,
        // `status` must NOT refuse (its old surface gate is gone) and must
        // self-describe the active surface. Runs over a temp in-memory index —
        // no phase0 corpus, so it executes in a fresh clone (unlike the
        // corpus-gated tests/stel_status.rs coverage that skips when absent).
        // The lib suite runs --test-threads=1; EnvVarGuard restores on drop.
        let _surface = EnvVarGuard::set("SYMFORGE_SURFACE", "full");

        let (key, file) = make_file("src/lib.rs", b"fn core() {}", vec![]);
        let server = make_server(make_live_index_ready(vec![(key, file)]));

        let result = server
            .status_stel_tool(Parameters(crate::stel::StelStatusRequest::default()))
            .await
            .expect("status dispatch");
        let serialized = serde_json::to_value(&result).expect("serialize CallToolResult");
        let output = tool_result_text(&serialized);

        assert!(
            !output.contains("requires SYMFORGE_SURFACE=compact"),
            "status must not refuse on the full surface:\n{output}"
        );
        assert!(
            output.contains("surface: full"),
            "status must self-describe the active (full) surface:\n{output}"
        );
    }

    #[tokio::test]
    async fn status_reports_connection_surface_and_discloses_daemon_env_divergence() {
        // Dogfood defect (2026-07-02): a full-surface stdio ADAPTER proxies
        // `status` to a compact-env DAEMON. The daemon must report the surface
        // actually served on the connection (`full`, threaded in via
        // `connection_surface`) — NOT its own env (`compact`) — and disclose the
        // divergence on one line. Exercises the daemon-side handler directly;
        // in-process the adapter and daemon share env, so divergence is only
        // reachable by hand-threading the connection profile.
        let _surface = EnvVarGuard::set("SYMFORGE_SURFACE", "compact");

        let (key, file) = make_file("src/lib.rs", b"fn core() {}", vec![]);
        let server = make_server(make_live_index_ready(vec![(key, file)]));

        let request = crate::stel::StelStatusRequest {
            connection_surface: Some("full".to_string()),
            ..Default::default()
        };
        let body = server.render_stel_status_body(&request);

        assert!(
            body.contains("surface: full"),
            "status must report the surface served on the connection (full):\n{body}"
        );
        assert!(
            body.contains("daemon_env_surface: compact (serving connection: full)"),
            "status must disclose the daemon/connection surface divergence:\n{body}"
        );
    }

    #[tokio::test]
    async fn status_without_connection_surface_falls_back_to_env() {
        // Backward compat: an OLD adapter sends no `connection_surface`. The
        // daemon falls back to its own env (`compact`) and adds NO divergence
        // line — byte-identical to pre-fix behavior.
        let _surface = EnvVarGuard::set("SYMFORGE_SURFACE", "compact");

        let (key, file) = make_file("src/lib.rs", b"fn core() {}", vec![]);
        let server = make_server(make_live_index_ready(vec![(key, file)]));

        let body = server.render_stel_status_body(&crate::stel::StelStatusRequest::default());

        assert!(
            body.contains("surface: compact"),
            "absent connection surface must fall back to env (compact):\n{body}"
        );
        assert!(
            !body.contains("daemon_env_surface:"),
            "no divergence line without a connection surface:\n{body}"
        );
    }

    #[tokio::test]
    async fn status_same_env_and_connection_surface_has_no_divergence_line() {
        // Same-env path: connection `full` + daemon env `full`. Report `full`
        // with NO divergence line (divergence discloses strictly on mismatch).
        let _surface = EnvVarGuard::set("SYMFORGE_SURFACE", "full");

        let (key, file) = make_file("src/lib.rs", b"fn core() {}", vec![]);
        let server = make_server(make_live_index_ready(vec![(key, file)]));

        let request = crate::stel::StelStatusRequest {
            connection_surface: Some("full".to_string()),
            ..Default::default()
        };
        let body = server.render_stel_status_body(&request);

        assert!(
            body.contains("surface: full"),
            "matching connection+env must report full:\n{body}"
        );
        assert!(
            !body.contains("daemon_env_surface:"),
            "no divergence line when connection matches env:\n{body}"
        );
    }

    fn make_symbol_with_bytes(
        name: &str,
        kind: SymbolKind,
        line_start: u32,
        line_end: u32,
        byte_range: (u32, u32),
    ) -> SymbolRecord {
        SymbolRecord {
            name: name.to_string(),
            kind,
            depth: 0,
            sort_order: 0,
            byte_range,
            item_byte_range: Some(byte_range),
            line_range: (line_start, line_end),
            doc_byte_range: None,
        }
    }

    fn medium_test_source_with_prefix(core: &str, line_prefix: &str) -> Vec<u8> {
        use crate::protocol::format::{SMALL_FILE_CHAR_THRESHOLD, SMALL_FILE_LINE_THRESHOLD};

        let mut out = core.to_string();
        if !out.ends_with('\n') {
            out.push('\n');
        }
        let mut line_count = out.lines().count();
        while line_count <= SMALL_FILE_LINE_THRESHOLD {
            out.push_str(line_prefix);
            out.push_str("test fixture padding\n");
            line_count += 1;
        }
        while out.len() <= SMALL_FILE_CHAR_THRESHOLD {
            out.push_str(line_prefix);
            out.push_str("pad\n");
        }
        out.into_bytes()
    }

    fn medium_test_source(core: &str) -> Vec<u8> {
        medium_test_source_with_prefix(core, "// ")
    }

    fn make_file(path: &str, content: &[u8], symbols: Vec<SymbolRecord>) -> (String, IndexedFile) {
        (
            path.to_string(),
            IndexedFile {
                relative_path: path.to_string(),
                language: LanguageId::Rust,
                classification: crate::domain::FileClassification::for_code_path(path),
                content: content.to_vec(),
                symbols,
                parse_status: ParseStatus::Parsed,
                parse_diagnostic: None,
                byte_len: content.len() as u64,
                content_hash: "test".to_string(),
                references: vec![],
                alias_map: std::collections::HashMap::new(),
                mtime_secs: 0,
            },
        )
    }

    fn make_file_with_refs(
        path: &str,
        content: &[u8],
        symbols: Vec<SymbolRecord>,
        references: Vec<ReferenceRecord>,
    ) -> (String, IndexedFile) {
        let (key, mut file) = make_file(path, content, symbols);
        file.references = references;
        (key, file)
    }

    fn make_ref(
        name: &str,
        qualified_name: Option<&str>,
        kind: ReferenceKind,
        line: u32,
        enclosing_symbol_index: Option<u32>,
    ) -> ReferenceRecord {
        ReferenceRecord {
            name: name.to_string(),
            qualified_name: qualified_name.map(str::to_string),
            kind,
            byte_range: (line * 10, line * 10 + 6),
            line_range: (line, line),
            enclosing_symbol_index,
        }
    }

    fn make_symbol_with_depth(
        name: &str,
        kind: SymbolKind,
        depth: u32,
        line_start: u32,
        line_end: u32,
        byte_range: (u32, u32),
    ) -> SymbolRecord {
        SymbolRecord {
            name: name.to_string(),
            kind,
            depth,
            sort_order: 0,
            byte_range,
            item_byte_range: Some(byte_range),
            line_range: (line_start, line_end),
            doc_byte_range: None,
        }
    }

    fn large_outline_fixture(
        path: &str,
        function_count: u32,
        line_count: u32,
    ) -> (String, IndexedFile) {
        let mut content = String::new();
        let mut symbols = Vec::new();

        let module_start = content.len() as u32;
        content.push_str("mod large {\n");
        for i in 0..function_count {
            let start = content.len() as u32;
            content.push_str(&format!("    fn function_{i:03}() {{}}\n"));
            let end = content.len() as u32;
            symbols.push(make_symbol_with_depth(
                &format!("function_{i:03}"),
                SymbolKind::Function,
                1,
                i + 1,
                i + 1,
                (start, end),
            ));
        }
        content.push_str("}\n");

        while content.lines().count() < line_count as usize {
            content.push_str("// padding\n");
        }

        let module_end = content.len() as u32;
        symbols.insert(
            0,
            make_symbol_with_depth(
                "large",
                SymbolKind::Module,
                0,
                0,
                line_count.saturating_sub(1),
                (module_start, module_end),
            ),
        );

        make_file(path, content.as_bytes(), symbols)
    }

    fn nested_test_module_fixture(path: &str, test_count: u32) -> (String, IndexedFile) {
        let mut content = String::from("#[cfg(test)]\nmod tests {\n");
        let mut symbols = vec![make_symbol_with_depth(
            "tests",
            SymbolKind::Module,
            0,
            1,
            test_count + 2,
            (0, 0),
        )];

        for i in 0..test_count {
            let start = content.len() as u32;
            content.push_str(&format!("    fn test_{i:03}() {{}}\n"));
            let end = content.len() as u32;
            symbols.push(make_symbol_with_depth(
                &format!("test_{i:03}"),
                SymbolKind::Function,
                1,
                i + 2,
                i + 2,
                (start, end),
            ));
        }
        content.push_str("}\n");

        make_file(path, content.as_bytes(), symbols)
    }

    fn make_live_index_ready(files: Vec<(String, IndexedFile)>) -> LiveIndex {
        use crate::live_index::trigram::TrigramIndex;
        let files_map = files
            .into_iter()
            .map(|(path, file)| (path, std::sync::Arc::new(file)))
            .collect::<HashMap<_, _>>();
        let trigram_index = TrigramIndex::build_from_files(&files_map);
        let mut index = LiveIndex {
            files: files_map,
            loaded_at: Instant::now(),
            loaded_at_system: std::time::SystemTime::now(),
            load_duration: Duration::from_millis(10),
            cb_state: CircuitBreakerState::new(0.20),
            is_empty: false,
            load_source: crate::live_index::store::IndexLoadSource::FreshLoad,
            snapshot_verify_state: crate::live_index::store::SnapshotVerifyState::NotNeeded,
            reverse_index: HashMap::new(),
            files_by_basename: HashMap::new(),
            files_by_dir_component: HashMap::new(),
            trigram_index,
            gitignore: None,
            skipped_files: Vec::new(),
            coupling_store: None,
            local_empty_reason: std::sync::Arc::new(parking_lot::RwLock::new(None)),
            indexed_root: None,
        };
        index.rebuild_reverse_index();
        index.rebuild_path_indices();
        index
    }

    /// Build a ready index that knows `path` only as a Tier-2 metadata-only skip
    /// record (e.g. a dependency lockfile) — the path is NOT in `files`,
    /// mirroring the post-admission state where lockfiles are demoted instead of
    /// parsed. One real Tier-1 source file is also seeded so the index reports
    /// `Ready` (an index with zero Tier-1 files reports `Empty`, matching a real
    /// repo where source coexists with the lockfile). Used to exercise the honest
    /// "not indexed" degradation responses in
    /// get_file_context / get_symbol / get_file_content.
    fn make_live_index_with_tier2_skip(
        path: &str,
        size: u64,
        reason: crate::domain::index::SkipReason,
    ) -> LiveIndex {
        use crate::domain::index::{AdmissionDecision, AdmissionTier, SkippedFile};
        let (anchor_key, anchor_file) = make_file(
            "src/anchor.rs",
            b"fn anchor() {}\n",
            vec![make_symbol("anchor", SymbolKind::Function, 0, 0)],
        );
        let mut index = make_live_index_ready(vec![(anchor_key, anchor_file)]);
        let extension = std::path::Path::new(path)
            .extension()
            .and_then(|e| e.to_str())
            .map(str::to_string);
        index.skipped_files = vec![SkippedFile {
            path: path.to_string(),
            size,
            extension,
            decision: AdmissionDecision::skip(AdmissionTier::MetadataOnly, reason),
        }];
        index
    }

    fn make_live_index_ready_with_coupling_store(
        files: Vec<(String, IndexedFile)>,
        store: crate::live_index::coupling::CouplingStore,
    ) -> LiveIndex {
        let mut index = make_live_index_ready(files);
        index.coupling_store = Some(Arc::new(store));
        index
    }

    /// Build an index seeded with one src, one vendor, and one personal-tooling
    /// file -- each containing the literal `noisy_token`. Used by Task 2.2 tests
    /// to exercise the default-suppress / opt-in surfacing semantics in
    /// `search_text` and `explore`.
    fn make_live_index_ready_with_vendor_file() -> LiveIndex {
        let content = b"// noisy_token marker for path-filter tests\n";
        let sym = SymbolRecord {
            name: "anchor".to_string(),
            kind: SymbolKind::Function,
            depth: 0,
            sort_order: 0,
            byte_range: (0, content.len() as u32),
            line_range: (0, 0),
            doc_byte_range: None,
            item_byte_range: None,
        };
        let (src_key, src_file) = make_file("src/normal.rs", content, vec![sym.clone()]);
        let (vendor_key, vendor_file) = make_file("vendor/foo/bar.rs", content, vec![sym.clone()]);
        let (personal_key, personal_file) =
            make_file(".claude/gsd-local-patches/foo.rs", content, vec![sym]);
        make_live_index_ready(vec![
            (src_key, src_file),
            (vendor_key, vendor_file),
            (personal_key, personal_file),
        ])
    }

