    #[tokio::test]
    async fn test_get_repo_map_full_proxies_to_daemon_session() {
        let daemon_home = TempDir::new().expect("daemon home");
        let _env_guard = EnvVarGuard::set_path("SYMFORGE_HOME", daemon_home.path());
        // The daemon is fail-closed; pin a token so the direct open call and the
        // proxy client (which resolves the token via env) can authenticate.
        let auth_token = "repo-map-proxy-test-token";
        let _auth_guard = EnvVarGuard::set("SYMFORGE_DAEMON_AUTH_TOKEN", auth_token);
        let project = TempDir::new().expect("project dir");
        fs::create_dir_all(project.path().join("src")).expect("src dir");
        fs::write(project.path().join("src").join("main.rs"), "fn main() {}\n")
            .expect("write source");

        let handle = crate::daemon::spawn_daemon("127.0.0.1")
            .await
            .expect("spawn daemon");
        let base_url = format!("http://127.0.0.1:{}", handle.port);
        let opened = reqwest::Client::new()
            .post(format!("{base_url}/v1/sessions/open"))
            .bearer_auth(auth_token)
            .json(&crate::daemon::OpenProjectRequest {
                project_root: project.path().display().to_string(),
                client_name: "codex".to_string(),
                pid: Some(1234),
            })
            .send()
            .await
            .expect("open request")
            .error_for_status()
            .expect("open status")
            .json::<crate::daemon::OpenProjectResponse>()
            .await
            .expect("open body");

        let daemon_client = crate::daemon::DaemonSessionClient::new_for_test(
            base_url,
            opened.project_id,
            opened.session_id,
            opened.project_name,
        );
        let server = SymForgeServer::new_daemon_proxy(daemon_client);

        let result = server
            .get_repo_map(Parameters(super::GetRepoMapInput {
                detail: Some("full".to_string()),
                path: None,
                depth: None,
                max_files: None,
                estimate: None,
                max_tokens: None,
            }))
            .await;
        assert!(
            result.contains("main.rs"),
            "remote repo outline should come from daemon project instance, got: {result}"
        );

        let _ = handle.shutdown_tx.send(());
    }

    /// Review finding 2 (post-v7.19.0): when a daemon is CONFIGURED but
    /// unreachable, `checkpoint_now` falls back to checkpointing the locally
    /// reloaded index — and its receipt must say so, because the snapshot it
    /// writes can lag the daemon's authoritative live index. A client pointed
    /// at a dead port (with no stored project root, so `reconnect` cannot
    /// rediscover a real daemon) forces exactly that fallback path.
    #[tokio::test]
    async fn test_checkpoint_now_degraded_fallback_receipt_names_local_index() {
        let daemon_client = crate::daemon::DaemonSessionClient::new_for_test(
            // Port 1 is never serving; connection fails fast.
            "http://127.0.0.1:1".to_string(),
            "project-id".to_string(),
            "session-id".to_string(),
            "project-name".to_string(),
        );
        let server = SymForgeServer::new_daemon_proxy(daemon_client);
        let dir = tempfile::tempdir().expect("create temp repo root");
        server.set_repo_root(Some(dir.path().to_path_buf()));

        let output = server
            .checkpoint_now(Parameters(super::CheckpointNowInput {
                verify_after_write: Some(true),
                export_artifact: None,
            }))
            .await;

        assert!(
            output.contains("Checkpoint complete"),
            "local fallback should still checkpoint successfully, got: {output}"
        );
        assert!(
            output.contains("daemon unreachable"),
            "degraded-fallback receipt must disclose the daemon was unreachable, got: {output}"
        );
        assert!(
            output.contains("locally reloaded index"),
            "degraded-fallback receipt must name WHAT was checkpointed, got: {output}"
        );
    }

