    #[tokio::test]
    async fn test_get_symbol_context_reference_list_uses_actual_enclosing_kind() {
        // Regression: reference entries used to render every enclosing symbol as
        // "in fn <name>" regardless of kind, yielding nonsense like
        // "in fn impl BucketManager". The enclosing kind must be honored, and an
        // impl/struct whose stored name already carries the kind prefix must not
        // double it.
        let impl_sym = make_symbol("impl BucketManager", SymbolKind::Impl, 1, 5);
        let caller_file = make_file_with_refs(
            "src/bucket.rs",
            b"impl BucketManager {\n    fn f(&self) { target(); }\n}\n",
            vec![impl_sym],
            vec![ReferenceRecord {
                name: "target".to_string(),
                qualified_name: None,
                kind: ReferenceKind::Call,
                byte_range: (38, 44),
                line_range: (1, 1),
                enclosing_symbol_index: Some(0),
            }],
        );
        let server = make_server(make_live_index_ready(vec![caller_file]));

        let result = server
            .get_symbol_context(Parameters(super::GetSymbolContextInput {
                name: "target".to_string(),
                file: None,
                path: None,
                symbol_kind: None,
                symbol_line: None,
                verbosity: None,
                bundle: None,
                sections: None,
                max_tokens: None,
                estimate: None,
            }))
            .await;

        assert!(
            result.contains("in impl BucketManager"),
            "reference list should render the actual enclosing kind; got: {result}"
        );
        assert!(
            !result.contains("in fn impl BucketManager"),
            "reference list must not hardcode 'fn' nor double the kind; got: {result}"
        );
    }

    #[tokio::test]
    async fn test_get_symbol_context_surfaces_impl_guidance_for_zero_caller_struct() {
        let content = b"pub struct ProjectOrchestratorActor;\n\nimpl ProjectOrchestratorActor {\n    pub fn new() -> Self {\n        Self\n    }\n}\n\nimpl Actor for ProjectOrchestratorActor {\n    fn handle(&self) {}\n}\n";
        let symbols = vec![
            SymbolRecord {
                name: "ProjectOrchestratorActor".to_string(),
                kind: SymbolKind::Struct,
                depth: 0,
                sort_order: 0,
                byte_range: (0, 35),
                line_range: (0, 0),
                doc_byte_range: None,
                item_byte_range: None,
            },
            SymbolRecord {
                name: "impl ProjectOrchestratorActor".to_string(),
                kind: SymbolKind::Impl,
                depth: 0,
                sort_order: 1,
                byte_range: (37, 117),
                line_range: (2, 6),
                doc_byte_range: None,
                item_byte_range: None,
            },
            SymbolRecord {
                name: "impl Actor for ProjectOrchestratorActor".to_string(),
                kind: SymbolKind::Impl,
                depth: 0,
                sort_order: 2,
                byte_range: (119, content.len() as u32),
                line_range: (8, 10),
                doc_byte_range: None,
                item_byte_range: None,
            },
        ];
        let server = make_server(make_live_index_ready(vec![make_file(
            "src/actors.rs",
            content,
            symbols,
        )]));

        let result = server
            .get_symbol_context(Parameters(super::GetSymbolContextInput {
                name: "ProjectOrchestratorActor".to_string(),
                file: None,
                path: Some("src/actors.rs".to_string()),
                symbol_kind: Some("struct".to_string()),
                symbol_line: None,
                verbosity: None,
                bundle: None,
                sections: None,
                max_tokens: None,
                estimate: None,
            }))
            .await;

        assert!(
            result.contains("0 direct callers"),
            "default symbol context should surface impl guidance for zero-caller structs: {result}"
        );
        assert!(
            result.contains("impl ProjectOrchestratorActor (src/actors.rs:3)"),
            "inherent impl suggestion should be surfaced: {result}"
        );
        assert!(
            result.contains("impl Actor for ProjectOrchestratorActor (src/actors.rs:9)"),
            "trait impl suggestion should be surfaced: {result}"
        );
    }

