    #[tokio::test]
    async fn test_index_folder_can_reindex_same_root_twice_locally() {
        let repo = TempDir::new().expect("temp repo");
        fs::create_dir_all(repo.path().join("src")).expect("create src dir");
        fs::write(repo.path().join("src/lib.rs"), "pub fn first() {}\n")
            .expect("write initial file");

        let server = make_server(make_live_index_empty());
        let first = server
            .index_folder(Parameters(super::IndexFolderInput {
                path: repo.path().display().to_string(),
                idempotency_key: None,
                add: None,
            }))
            .await;
        assert!(
            first.contains("Indexed 1 files"),
            "first local index_folder should succeed, got: {first}"
        );

        fs::write(repo.path().join("src/lib.rs"), "pub fn second() {}\n").expect("update file");
        let second = server
            .index_folder(Parameters(super::IndexFolderInput {
                path: repo.path().display().to_string(),
                idempotency_key: None,
                add: None,
            }))
            .await;
        assert!(
            second.contains("Indexed 1 files"),
            "second local index_folder should also succeed, got: {second}"
        );

        let outline = server
            .get_file_context(Parameters(super::GetFileContextInput {
                path: "src/lib.rs".to_string(),
                max_tokens: None,
                force_refresh: None,
                sections: Some(vec!["outline".to_string()]),
                estimate: None,
            }))
            .await;
        assert!(
            outline.contains("second"),
            "second local index_folder should refresh the same-root index, got: {outline}"
        );

        let health = server.health_compact().await;
        let root_text = repo
            .path()
            .canonicalize()
            .expect("temp repo should canonicalize")
            .to_string_lossy()
            .replace('\\', "/");
        assert!(
            health.contains(&format!("project_root={root_text}")),
            "health should surface the project root after index_folder, got: {health}"
        );
        assert!(
            health.contains("load_source=fresh_load")
                && health.contains("reset_state=none")
                && health.contains("index_state=fresh_process"),
            "plain index_folder should report a fresh index without reset identity, got: {health}"
        );
        assert!(
            !health.contains("index_state=index_folder_reset"),
            "plain index_folder must not claim reset state, got: {health}"
        );
        assert!(
            health.contains("index_id=index-"),
            "health should keep index identity assertable after reindex, got: {health}"
        );
    }

    #[tokio::test]
    async fn test_index_folder_reset_deletes_snapshot_scope_and_reports_fresh_status() {
        let _reset_env = EnvVarGuard::set(super::INDEX_FOLDER_RESET_ENV, "1");
        let repo = TempDir::new().expect("temp repo");
        let src_dir = repo.path().join("src");
        let symforge_dir = repo.path().join(".symforge");
        fs::create_dir_all(&src_dir).expect("create src dir");
        fs::create_dir_all(&symforge_dir).expect("create .symforge dir");
        fs::write(src_dir.join("lib.rs"), "pub fn reset_fresh() {}\n").expect("write source");
        fs::write(symforge_dir.join("index.bin"), b"stale snapshot").expect("write snapshot");
        fs::write(symforge_dir.join("index.bin.tmp"), b"stale tmp").expect("write tmp");
        fs::write(symforge_dir.join("frecency.db"), b"unrelated").expect("write sentinel");

        let server = make_server(make_live_index_empty());
        let output = server
            .index_folder(Parameters(super::IndexFolderInput {
                path: repo.path().display().to_string(),
                idempotency_key: None,
                add: None,
            }))
            .await;

        assert!(
            output.starts_with("Indexed 1 files"),
            "reset index_folder should still report indexing success first, got: {output}"
        );
        assert!(
            output.contains("Reset: scope=.symforge/index.bin,.symforge/index.bin.tmp | removed=2"),
            "reset output should prove bounded snapshot deletion, got: {output}"
        );
        assert!(
            output.contains("Runtime:") && output.contains("load_source=fresh_load"),
            "reset output should include fresh runtime status, got: {output}"
        );
        assert!(
            output.contains("index_state=index_folder_reset") && output.contains("index_id=index-"),
            "reset output should include assertable fresh identity, got: {output}"
        );
        assert!(
            output.contains("reset_state=current_project:p"),
            "reset output should prove reset identity is tied to the current project generation, got: {output}"
        );
        assert!(!symforge_dir.join("index.bin").exists());
        assert!(!symforge_dir.join("index.bin.tmp").exists());
        assert!(
            symforge_dir.join("frecency.db").exists(),
            "reset must preserve unrelated .symforge state"
        );
        assert!(
            src_dir.join("lib.rs").exists(),
            "reset must never delete source files"
        );

        let health = server
            .health(Parameters(super::HealthInput::default()))
            .await;
        assert!(
            health.contains("load_source=fresh_load")
                && health.contains("reset_state=current_project:p")
                && health.contains("index_state=index_folder_reset")
                && health.contains("index_id=index-"),
            "health after reset should prove fresh identity/source, got: {health}"
        );
    }

