    #[tokio::test]
    async fn test_tool_call_completion_instrumentation_records_representative_tools() {
        use crate::analytics::{
            AnalyticsConfig, AnalyticsRecorder, AnalyticsScope, AnalyticsStore,
            SqliteAnalyticsStore,
        };
        use crate::protocol::edit::ReplaceSymbolBodyInput;

        let (_dir, server) = setup_loaded_edit_test(&[(
            "src/lib.rs",
            "fn present() {\n    println!(\"old\");\n}\n",
        )]);
        let db_path = crate::paths::symforge_db_path(_dir.path(), crate::paths::ANALYTICS_DB_NAME);
        let store = AnalyticsStore::open(AnalyticsConfig::enabled(&db_path)).unwrap();
        server.set_analytics_recorder_for_tests(AnalyticsRecorder::start(
            store,
            AnalyticsScope::Session,
            16,
        ));

        let read = serialized_tool_result(
            server
                .get_file_content_tool(Parameters(get_file_content_input("src/lib.rs")))
                .await,
        );
        assert_tool_result_status(&read, OutcomeClass::Found);

        let search = serialized_tool_result(
            server
                .search_symbols_tool(Parameters(search_symbols_input(Some("present"))))
                .await,
        );
        assert_tool_result_status(&search, OutcomeClass::Found);

        let dry_run_edit = serialized_tool_result(
            server
                .replace_symbol_body_tool(Parameters(ReplaceSymbolBodyInput {
                    path: "src/lib.rs".to_string(),
                    name: "present".to_string(),
                    kind: None,
                    symbol_line: None,
                    new_body: "fn present() {\n    println!(\"new\");\n}".to_string(),
                    dry_run: Some(true),
                    idempotency_key: None,
                    if_match: None,
                    working_directory: None,
                }))
                .await,
        );
        assert_tool_result_edit_status(&dry_run_edit, "dry_run_success", OutcomeClass::Found);

        assert_eq!(server.analytics_queue_status_for_tests().enqueued, 3);
        drop(server);

        let records = SqliteAnalyticsStore::open(&db_path)
            .unwrap()
            .recent_records(10)
            .unwrap();
        let tool_names = records
            .iter()
            .map(|record| record.tool_name.as_str())
            .collect::<Vec<_>>();

        assert!(tool_names.contains(&"get_file_content"));
        assert!(tool_names.contains(&"search_symbols"));
        assert!(tool_names.contains(&"replace_symbol_body"));
        assert!(records.iter().all(|record| record.surface == "tool"
            && record.configured_scope == "session"
            && record.response_bytes > 0
            && record.estimated_tokens.is_some()
            && record.outcome_class == "found"));
    }

    struct BlockingAnalyticsWriter {
        started: std::sync::mpsc::Sender<()>,
        release: std::sync::mpsc::Receiver<()>,
        blocked_once: bool,
    }

    impl crate::analytics::AnalyticsWriter for BlockingAnalyticsWriter {
        fn write(
            &mut self,
            _observation: &crate::analytics::AnalyticsObservation,
        ) -> anyhow::Result<crate::analytics::AnalyticsWriteOutcome> {
            if !self.blocked_once {
                self.blocked_once = true;
                self.started.send(()).unwrap();
                self.release.recv().unwrap();
            }
            Ok(crate::analytics::AnalyticsWriteOutcome::Recorded { id: 1 })
        }
    }

    #[tokio::test]
    async fn test_tool_handler_enqueues_without_waiting_for_background_writer() {
        use crate::analytics::{AnalyticsRecorder, AnalyticsScope};

        let (started_tx, started_rx) = std::sync::mpsc::channel();
        let (release_tx, release_rx) = std::sync::mpsc::channel();
        let content = b"fn present() {}\n";
        let (key, file) = make_file(
            "src/lib.rs",
            content,
            vec![make_symbol("present", SymbolKind::Function, 0, 0)],
        );
        let server = make_server(make_live_index_ready(vec![(key, file)]));
        server.set_analytics_recorder_for_tests(AnalyticsRecorder::start_with_writer_for_tests(
            AnalyticsScope::Session,
            1,
            BlockingAnalyticsWriter {
                started: started_tx,
                release: release_rx,
                blocked_once: false,
            },
        ));

        let result = tokio::time::timeout(
            Duration::from_millis(200),
            server.get_file_content_tool(Parameters(get_file_content_input("src/lib.rs"))),
        )
        .await
        .expect("tool handler must not wait for the analytics writer");
        let result = serialized_tool_result(result);
        assert_tool_result_status(&result, OutcomeClass::Found);
        started_rx
            .recv_timeout(Duration::from_secs(1))
            .expect("background writer should receive the enqueued observation");

        let status = server.analytics_queue_status_for_tests();
        assert_eq!(status.enqueued, 1);
        assert_eq!(status.recorded, 0);

        release_tx.send(()).unwrap();
        drop(server);
    }

    #[tokio::test]
    async fn test_batch_edit_and_insert_statuses_include_per_operation_status() {
        use crate::protocol::edit::{
            BatchEditInput, BatchInsertInput, EditOperation, InsertPosition, InsertTarget,
            SingleEdit,
        };

        let dir = tempfile::tempdir().unwrap();
        std::fs::create_dir(dir.path().join(".git")).unwrap();
        let src_dir = dir.path().join("src");
        std::fs::create_dir_all(&src_dir).unwrap();
        let a_content = b"fn alpha() { old(); }\n";
        let b_content = b"fn beta() { old(); }\n";
        std::fs::write(src_dir.join("a.rs"), a_content).unwrap();
        std::fs::write(src_dir.join("b.rs"), b_content).unwrap();

        let mut files = vec![];
        for (path, content) in [
            ("src/a.rs", a_content as &[u8]),
            ("src/b.rs", b_content as &[u8]),
        ] {
            let result = crate::parsing::process_file(path, content, LanguageId::Rust);
            let indexed = IndexedFile::from_parse_result(result, content.to_vec());
            files.push((path.to_string(), indexed));
        }
        let server =
            make_server_with_root(make_live_index_ready(files), Some(dir.path().to_path_buf()));

        let dry_run_batch_edit = serialized_tool_result(
            server
                .batch_edit_tool(Parameters(BatchEditInput {
                    edits: vec![
                        SingleEdit {
                            path: "src/a.rs".to_string(),
                            name: "alpha".to_string(),
                            kind: None,
                            symbol_line: None,
                            operation: EditOperation::Replace {
                                new_body: "fn alpha() { new(); }".to_string(),
                            },
                            working_directory: None,
                        },
                        SingleEdit {
                            path: "src/b.rs".to_string(),
                            name: "beta".to_string(),
                            kind: None,
                            symbol_line: None,
                            operation: EditOperation::Delete,
                            working_directory: None,
                        },
                    ],
                    dry_run: Some(true),
                    idempotency_key: None,
                    working_directory: None,
                }))
                .await,
        );
        assert_tool_result_edit_status(&dry_run_batch_edit, "dry_run_success", OutcomeClass::Found);
        let operation_statuses = dry_run_batch_edit["_meta"][RESULT_STATUS_META_KEY]["operations"]
            .as_array()
            .expect("batch edit status should include per-operation statuses");
        assert_eq!(operation_statuses.len(), 2);
        assert!(
            operation_statuses
                .iter()
                .all(|entry| entry["status"] == serde_json::json!("dry_run_success"))
        );
        assert!(tool_result_text(&dry_run_batch_edit).contains("[DRY RUN]"));
        assert!(
            std::fs::read_to_string(src_dir.join("a.rs"))
                .unwrap()
                .contains("old")
        );

        let successful_batch_insert = serialized_tool_result(
            server
                .batch_insert_tool(Parameters(BatchInsertInput {
                    content: "fn logging() {}".to_string(),
                    position: InsertPosition::After,
                    targets: vec![
                        InsertTarget {
                            path: "src/a.rs".to_string(),
                            name: "alpha".to_string(),
                            kind: None,
                            symbol_line: None,
                            working_directory: None,
                        },
                        InsertTarget {
                            path: "src/b.rs".to_string(),
                            name: "beta".to_string(),
                            kind: None,
                            symbol_line: None,
                            working_directory: None,
                        },
                    ],
                    dry_run: Some(false),
                    idempotency_key: None,
                    working_directory: None,
                }))
                .await,
        );
        assert_tool_result_edit_status(&successful_batch_insert, "success", OutcomeClass::Found);
        let operation_statuses =
            successful_batch_insert["_meta"][RESULT_STATUS_META_KEY]["operations"]
                .as_array()
                .expect("batch insert status should include per-operation statuses");
        assert_eq!(operation_statuses.len(), 2);
        assert!(
            operation_statuses
                .iter()
                .all(|entry| entry["status"] == serde_json::json!("success"))
        );

        let failed_batch_edit = serialized_tool_result(
            server
                .batch_edit_tool(Parameters(BatchEditInput {
                    edits: vec![
                        SingleEdit {
                            path: "src/a.rs".to_string(),
                            name: "alpha".to_string(),
                            kind: None,
                            symbol_line: None,
                            operation: EditOperation::Delete,
                            working_directory: None,
                        },
                        SingleEdit {
                            path: "src/b.rs".to_string(),
                            name: "missing".to_string(),
                            kind: None,
                            symbol_line: None,
                            operation: EditOperation::Delete,
                            working_directory: None,
                        },
                    ],
                    dry_run: Some(false),
                    idempotency_key: None,
                    working_directory: None,
                }))
                .await,
        );
        assert_tool_result_edit_status(&failed_batch_edit, "not_found", OutcomeClass::NotFound);
        assert!(tool_result_text(&failed_batch_edit).contains("ROLLED BACK"));
        let operation_statuses = failed_batch_edit["_meta"][RESULT_STATUS_META_KEY]["operations"]
            .as_array()
            .expect("failed batch edit status should identify the failing operation");
        assert_eq!(operation_statuses.len(), 1);
        assert_eq!(
            operation_statuses[0]["operation_index"],
            serde_json::json!(2)
        );
        assert_eq!(
            operation_statuses[0]["status"],
            serde_json::json!("not_found")
        );
    }

    #[tokio::test]
    async fn test_edit_idempotency_replays_same_key_same_request_without_second_write() {
        let source = b"fn present() {\n    old();\n}\n";
        let (_dir, server, file_path) = setup_edit_test(source);
        let request = serde_json::json!({
            "path": "src/lib.rs",
            "name": "present",
            "new_body": "fn present() {\n    new();\n}",
            "dry_run": false,
            "idempotency_key": "edit-replay-same-request",
        });

        let first = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(
                request.clone(),
            )))
            .await;
        assert!(first.contains("replaced"));
        let written_once = std::fs::read_to_string(&file_path).unwrap();
        assert!(written_once.contains("new();"));

        let second = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(request)))
            .await;

        assert_eq!(second, first);
        assert_eq!(std::fs::read_to_string(&file_path).unwrap(), written_once);
    }

    #[tokio::test]
    async fn test_edit_idempotency_rejects_same_key_different_request_before_file_changes() {
        let source = b"fn present() {\n    old();\n}\n";
        let (_dir, server, file_path) = setup_edit_test(source);
        let first_request = serde_json::json!({
            "path": "src/lib.rs",
            "name": "present",
            "new_body": "fn present() {\n    first();\n}",
            "dry_run": false,
            "idempotency_key": "edit-conflict-same-key",
        });
        let second_request = serde_json::json!({
            "path": "src/lib.rs",
            "name": "present",
            "new_body": "fn present() {\n    second();\n}",
            "dry_run": false,
            "idempotency_key": "edit-conflict-same-key",
        });

        let first = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(
                first_request,
            )))
            .await;
        assert!(first.contains("replaced"));

        let conflict = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(
                second_request,
            )))
            .await;
        let content = std::fs::read_to_string(&file_path).unwrap();

        assert!(conflict.contains("Idempotency conflict"));
        assert!(content.contains("first();"));
        assert!(!content.contains("second();"));
    }

    #[tokio::test]
    async fn test_edit_idempotency_dry_run_does_not_poison_committed_replay_state() {
        let source = b"fn present() {\n    old();\n}\n";
        let (_dir, server, file_path) = setup_edit_test(source);
        let dry_run_request = serde_json::json!({
            "path": "src/lib.rs",
            "name": "present",
            "new_body": "fn present() {\n    planned();\n}",
            "dry_run": true,
            "idempotency_key": "edit-dry-run-ignored",
        });
        let commit_request = serde_json::json!({
            "path": "src/lib.rs",
            "name": "present",
            "new_body": "fn present() {\n    committed();\n}",
            "dry_run": false,
            "idempotency_key": "edit-dry-run-ignored",
        });

        let dry_run = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(
                dry_run_request,
            )))
            .await;
        assert!(dry_run.contains("[DRY RUN]"));
        assert!(
            std::fs::read_to_string(&file_path)
                .unwrap()
                .contains("old();")
        );

        let committed = server
            .replace_symbol_body(Parameters(replace_symbol_body_input_from_json(
                commit_request,
            )))
            .await;
        assert!(committed.contains("replaced"));
        assert!(
            std::fs::read_to_string(&file_path)
                .unwrap()
                .contains("committed();")
        );
    }

